var e=JSON.parse(`[{"id":11648,"term":"supplier","meaning":"공급업체; 납품업자","partOfSpeech":"n.","example":"We need to find a new supplier for our packaging materials.","exampleTranslation":"포장재 새 공급업체를 찾아야 해.","category":"빈도 학습","level":16},{"id":11649,"term":"prize","meaning":"상; 상금","partOfSpeech":"n.","example":"She won first prize at the cooking competition.","exampleTranslation":"그녀는 요리 대회에서 1등 상을 받았어.","category":"빈도 학습","level":16},{"id":11650,"term":"typically","meaning":"보통; 일반적으로","partOfSpeech":"adv.","example":"I typically wake up around seven in the morning.","exampleTranslation":"나는 보통 오전 7시쯤 일어나.","category":"빈도 학습","level":16},{"id":11651,"term":"peer","meaning":"동료; 또래","partOfSpeech":"n.","example":"He always felt comfortable talking to his peer group.","exampleTranslation":"그는 항상 또래들과 이야기할 때 편안함을 느꼈어.","category":"빈도 학습","level":16},{"id":11652,"term":"pension","meaning":"연금","partOfSpeech":"n.","example":"My grandfather lives on his pension now that he is retired.","exampleTranslation":"할아버지는 은퇴하셔서 지금 연금으로 생활하고 계셔.","category":"빈도 학습","level":16},{"id":11653,"term":"wing","meaning":"날개; 건물의 한 동","partOfSpeech":"n.","example":"The bird spread its wing and flew off the branch.","exampleTranslation":"새가 날개를 펼치고 나뭇가지에서 날아올랐어.","category":"빈도 학습","level":16},{"id":11654,"term":"acquisition","meaning":"인수; 획득","partOfSpeech":"n.","example":"The acquisition of the smaller company took several months.","exampleTranslation":"그 소규모 회사 인수에 몇 달이 걸렸어.","category":"빈도 학습","level":16},{"id":11655,"term":"laughter","meaning":"웃음; 웃음소리","partOfSpeech":"n.","example":"The whole room filled with laughter after his joke.","exampleTranslation":"그의 농담이 끝나자 방 안이 웃음소리로 가득 찼어.","category":"빈도 학습","level":16},{"id":11656,"term":"deeply","meaning":"깊이; 몹시","partOfSpeech":"adv.","example":"She was deeply moved by the farewell speech.","exampleTranslation":"그녀는 작별 인사에 몹시 감동했어.","category":"빈도 학습","level":16},{"id":11657,"term":"recognition","meaning":"인정; 인식","partOfSpeech":"n.","example":"He finally got recognition for all his hard work.","exampleTranslation":"그는 마침내 자신의 노고를 인정받았어.","category":"빈도 학습","level":16},{"id":11658,"term":"assistance","meaning":"도움; 지원","partOfSpeech":"n.","example":"Please ask a staff member if you need any assistance.","exampleTranslation":"도움이 필요하시면 직원에게 문의해 주세요.","category":"빈도 학습","level":16},{"id":11659,"term":"roof","meaning":"지붕","partOfSpeech":"n.","example":"There was a leak in the roof after the heavy rain.","exampleTranslation":"폭우가 내린 뒤 지붕에서 물이 샜어.","category":"빈도 학습","level":16},{"id":11660,"term":"retirement","meaning":"은퇴; 퇴직","partOfSpeech":"n.","example":"He threw a big party to celebrate his retirement.","exampleTranslation":"그는 은퇴를 기념해 큰 파티를 열었어.","category":"빈도 학습","level":16},{"id":11661,"term":"respectively","meaning":"각각; 각기","partOfSpeech":"adv.","example":"Tom and Lisa won gold and silver respectively.","exampleTranslation":"톰과 리사는 각각 금메달과 은메달을 땄어.","category":"빈도 학습","level":16},{"id":11662,"term":"variation","meaning":"변화; 차이","partOfSpeech":"n.","example":"There is some variation in prices from store to store.","exampleTranslation":"가게마다 가격에 다소 차이가 있어.","category":"빈도 학습","level":16},{"id":11663,"term":"ultimately","meaning":"결국; 궁극적으로","partOfSpeech":"adv.","example":"They argued for a while but ultimately agreed.","exampleTranslation":"한동안 다퉜지만 결국 합의를 봤어.","category":"빈도 학습","level":16},{"id":11664,"term":"proof","meaning":"증거; 증명","partOfSpeech":"n.","example":"Do you have any proof that you were there that night?","exampleTranslation":"그날 밤 거기 있었다는 증거가 있어?","category":"빈도 학습","level":16},{"id":11665,"term":"soil","meaning":"흙; 토양","partOfSpeech":"n.","example":"The soil in this garden is perfect for growing vegetables.","exampleTranslation":"이 정원 흙은 채소 기르기에 딱 맞아.","category":"빈도 학습","level":16},{"id":11666,"term":"smart","meaning":"영리한; 세련된","partOfSpeech":"adj.","example":"That was a really smart decision in a tough situation.","exampleTranslation":"어려운 상황에서 정말 영리한 결정이었어.","category":"빈도 학습","level":16},{"id":11667,"term":"layer","meaning":"층; 겹","partOfSpeech":"n.","example":"Put on an extra layer if you feel cold.","exampleTranslation":"추우면 옷을 한 겹 더 입어.","category":"빈도 학습","level":16},{"id":11668,"term":"upset","meaning":"속상한; 화난","partOfSpeech":"adj.","example":"She was upset when her flight got cancelled.","exampleTranslation":"항공편이 취소되자 그녀는 몹시 속상해했어.","category":"빈도 학습","level":16},{"id":11669,"term":"tooth","meaning":"이; 치아","partOfSpeech":"n.","example":"He broke a tooth biting into that hard candy.","exampleTranslation":"그는 딱딱한 사탕을 씹다가 이가 부러졌어.","category":"빈도 학습","level":16},{"id":11670,"term":"representation","meaning":"대표; 표현","partOfSpeech":"n.","example":"The poster was a colorful representation of the city's culture.","exampleTranslation":"그 포스터는 도시 문화를 다채롭게 표현한 작품이었어.","category":"빈도 학습","level":16},{"id":11671,"term":"preparation","meaning":"준비; 대비","partOfSpeech":"n.","example":"Good preparation is the key to a successful presentation.","exampleTranslation":"충분한 준비가 성공적인 발표의 핵심이야.","category":"빈도 학습","level":16},{"id":11672,"term":"dispute","meaning":"분쟁; 다투다","partOfSpeech":"n./v.","example":"The two neighbors had a dispute over the fence line.","exampleTranslation":"두 이웃은 담장 경계선 때문에 분쟁을 벌였어.","category":"빈도 학습","level":16},{"id":11673,"term":"emphasis","meaning":"강조; 중점","partOfSpeech":"n.","example":"The coach put a lot of emphasis on teamwork.","exampleTranslation":"코치는 팀워크를 매우 강조했어.","category":"빈도 학습","level":16},{"id":11674,"term":"edition","meaning":"판; 호","partOfSpeech":"n.","example":"I just bought the latest edition of that travel guide.","exampleTranslation":"방금 그 여행 가이드의 최신판을 샀어.","category":"빈도 학습","level":16},{"id":11675,"term":"silver","meaning":"은; 은색","partOfSpeech":"n.","example":"She wore a delicate silver necklace to the dinner.","exampleTranslation":"그녀는 저녁 식사에 섬세한 은 목걸이를 하고 갔어.","category":"빈도 학습","level":16},{"id":11676,"term":"entertainment","meaning":"오락; 즐길 거리","partOfSpeech":"n.","example":"The festival offered all kinds of entertainment for families.","exampleTranslation":"그 축제는 가족들을 위한 온갖 즐길 거리를 제공했어.","category":"빈도 학습","level":16},{"id":11677,"term":"honest","meaning":"솔직한; 정직한","partOfSpeech":"adj.","example":"Just be honest with me about how you feel.","exampleTranslation":"네 감정을 나한테 솔직하게 말해줘.","category":"빈도 학습","level":16},{"id":11678,"term":"undertake","meaning":"맡다; 착수하다","partOfSpeech":"v.","example":"She agreed to undertake the project despite the tight deadline.","exampleTranslation":"촉박한 마감에도 불구하고 그녀는 그 프로젝트를 맡기로 했어.","category":"빈도 학습","level":16},{"id":11679,"term":"retail","meaning":"소매; 소매의","partOfSpeech":"n.","example":"She worked in retail for three years before switching careers.","exampleTranslation":"그녀는 다른 일을 시작하기 전 3년간 소매업에서 일했어.","category":"빈도 학습","level":16},{"id":11680,"term":"wire","meaning":"전선; 철사","partOfSpeech":"n.","example":"The electrician connected the wire to the socket.","exampleTranslation":"전기 기사가 전선을 소켓에 연결했다.","category":"빈도 학습","level":16},{"id":11681,"term":"unlikely","meaning":"가능성이 낮은; ~할 것 같지 않은","partOfSpeech":"adj.","example":"It's unlikely that the store will be open on Sunday.","exampleTranslation":"그 가게가 일요일에 문을 열 것 같지 않다.","category":"빈도 학습","level":16},{"id":11682,"term":"gay","meaning":"동성애자의; 게이","partOfSpeech":"adj.","example":"The city held its annual gay pride parade last weekend.","exampleTranslation":"그 도시는 지난 주말에 연례 게이 프라이드 퍼레이드를 열었다.","category":"빈도 학습","level":16},{"id":11683,"term":"publication","meaning":"출판(물); 발행","partOfSpeech":"n.","example":"Her first publication sold thousands of copies.","exampleTranslation":"그녀의 첫 번째 출판물은 수천 부가 팔렸다.","category":"빈도 학습","level":16},{"id":11684,"term":"slight","meaning":"약간의; 미미한","partOfSpeech":"adj.","example":"There's a slight chance of rain this afternoon.","exampleTranslation":"오늘 오후에 비가 올 가능성이 약간 있다.","category":"빈도 학습","level":16},{"id":11685,"term":"unknown","meaning":"알려지지 않은; 미상의","partOfSpeech":"adj.","example":"The cause of the accident is still unknown.","exampleTranslation":"사고 원인은 아직 밝혀지지 않았다.","category":"빈도 학습","level":16},{"id":11686,"term":"zone","meaning":"구역; 지대","partOfSpeech":"n.","example":"This zone is reserved for emergency vehicles only.","exampleTranslation":"이 구역은 긴급 차량 전용이다.","category":"빈도 학습","level":16},{"id":11687,"term":"restrict","meaning":"제한하다; 규제하다","partOfSpeech":"v.","example":"The doctor told him to restrict his sugar intake.","exampleTranslation":"의사는 그에게 당분 섭취를 줄이라고 했다.","category":"빈도 학습","level":16},{"id":11688,"term":"trace","meaning":"흔적; 추적하다","partOfSpeech":"n./v.","example":"Police managed to trace the package to its sender.","exampleTranslation":"경찰이 소포를 발송자까지 추적하는 데 성공했다.","category":"빈도 학습","level":16},{"id":11689,"term":"inch","meaning":"인치(2.54cm); 조금씩 나아가다","partOfSpeech":"n.","example":"Move the slider one inch to the right.","exampleTranslation":"슬라이더를 오른쪽으로 1인치 움직이세요.","category":"빈도 학습","level":16},{"id":11690,"term":"equivalent","meaning":"동등한; 상당하는 것","partOfSpeech":"adj.","example":"One cup of coffee is roughly equivalent to two cans of soda in caffeine.","exampleTranslation":"커피 한 잔은 카페인 양으로 따지면 탄산음료 두 캔과 비슷하다.","category":"빈도 학습","level":16},{"id":11691,"term":"solid","meaning":"단단한; 견고한; 확실한","partOfSpeech":"adj.","example":"She gave a solid performance in the interview.","exampleTranslation":"그녀는 면접에서 탄탄한 실력을 보여줬다.","category":"빈도 학습","level":16},{"id":11692,"term":"enterprise","meaning":"기업; 사업","partOfSpeech":"n.","example":"They launched a small enterprise selling homemade candles.","exampleTranslation":"그들은 수제 양초를 판매하는 소규모 사업을 시작했다.","category":"빈도 학습","level":16},{"id":11693,"term":"elderly","meaning":"노인의; 나이 드신","partOfSpeech":"adj.","example":"The program provides meals for elderly residents.","exampleTranslation":"그 프로그램은 노인 주민들에게 식사를 제공한다.","category":"빈도 학습","level":16},{"id":11694,"term":"owe","meaning":"빚지다; ~에게 신세를 지다","partOfSpeech":"v.","example":"I still owe you twenty dollars from last week.","exampleTranslation":"나 지난주에 네게 20달러 아직 못 갚았잖아.","category":"빈도 학습","level":16},{"id":11695,"term":"governor","meaning":"주지사; 총재","partOfSpeech":"n.","example":"The governor announced a new plan to improve public schools.","exampleTranslation":"주지사가 공립학교 개선을 위한 새 계획을 발표했다.","category":"빈도 학습","level":16},{"id":11696,"term":"uniform","meaning":"제복; 균일한","partOfSpeech":"n./adj.","example":"All staff must wear a uniform during working hours.","exampleTranslation":"모든 직원은 근무 시간에 제복을 착용해야 한다.","category":"빈도 학습","level":16},{"id":11697,"term":"port","meaning":"항구; 항","partOfSpeech":"n.","example":"The cruise ship arrived at the port early in the morning.","exampleTranslation":"유람선이 이른 아침에 항구에 도착했다.","category":"빈도 학습","level":16},{"id":11698,"term":"pitch","meaning":"음조; 던지다; (판매) 홍보","partOfSpeech":"n./v.","example":"Her voice rose in pitch when she got excited.","exampleTranslation":"그녀는 흥분하면 목소리 톤이 높아진다.","category":"빈도 학습","level":16},{"id":11699,"term":"contemporary","meaning":"동시대의; 현대의","partOfSpeech":"adj.","example":"The museum features contemporary art from local artists.","exampleTranslation":"그 박물관은 지역 예술가들의 현대 미술 작품을 전시한다.","category":"빈도 학습","level":16},{"id":11700,"term":"ease","meaning":"편안함; 수월함; 완화하다","partOfSpeech":"n./v.","example":"She handled the difficult situation with ease.","exampleTranslation":"그녀는 어려운 상황을 수월하게 처리했다.","category":"빈도 학습","level":16},{"id":11701,"term":"beer","meaning":"맥주","partOfSpeech":"n.","example":"Can I get a cold beer, please?","exampleTranslation":"차가운 맥주 한 잔 주시겠어요?","category":"빈도 학습","level":16},{"id":11702,"term":"specialist","meaning":"전문가; 전문의","partOfSpeech":"n.","example":"My doctor referred me to a specialist for further tests.","exampleTranslation":"의사가 추가 검사를 위해 전문의에게 나를 보냈다.","category":"빈도 학습","level":16},{"id":11703,"term":"assure","meaning":"확신시키다; 장담하다","partOfSpeech":"v.","example":"Let me assure you that everything will be ready on time.","exampleTranslation":"모든 것이 제때 준비될 거라고 장담할게요.","category":"빈도 학습","level":16},{"id":11704,"term":"profile","meaning":"프로필; 측면; 소개","partOfSpeech":"n.","example":"Please update your profile with a recent photo.","exampleTranslation":"최근 사진으로 프로필을 업데이트해 주세요.","category":"빈도 학습","level":16},{"id":11705,"term":"mood","meaning":"기분; 분위기","partOfSpeech":"n.","example":"I'm not in the mood to go out tonight.","exampleTranslation":"오늘 밤은 밖에 나갈 기분이 아니야.","category":"빈도 학습","level":17},{"id":11706,"term":"episode","meaning":"에피소드; 회(방송); 사건","partOfSpeech":"n.","example":"Did you watch the last episode of that series?","exampleTranslation":"그 드라마 마지막 에피소드 봤어?","category":"빈도 학습","level":17},{"id":11707,"term":"crack","meaning":"균열; 금이 가다; 깨다","partOfSpeech":"n./v.","example":"There's a crack in the bathroom wall.","exampleTranslation":"화장실 벽에 균열이 생겼다.","category":"빈도 학습","level":17},{"id":11708,"term":"numerous","meaning":"수많은; 다수의","partOfSpeech":"adj.","example":"I've visited that café numerous times this month.","exampleTranslation":"이번 달에 그 카페를 수없이 찾았다.","category":"빈도 학습","level":17},{"id":11709,"term":"symptom","meaning":"증상; 징후","partOfSpeech":"n.","example":"Headache is the most common symptom of dehydration.","exampleTranslation":"두통은 탈수의 가장 흔한 증상이다.","category":"빈도 학습","level":17},{"id":11710,"term":"virtually","meaning":"사실상; 거의","partOfSpeech":"adv.","example":"The new software is virtually bug-free.","exampleTranslation":"새 소프트웨어는 사실상 버그가 없다.","category":"빈도 학습","level":17},{"id":11711,"term":"era","meaning":"시대; 시기","partOfSpeech":"n.","example":"We live in an era of rapid technological change.","exampleTranslation":"우리는 급격한 기술 변화의 시대에 살고 있다.","category":"빈도 학습","level":17},{"id":11712,"term":"coverage","meaning":"보도; 보장 범위","partOfSpeech":"n.","example":"The accident received wide coverage in the news.","exampleTranslation":"그 사고는 뉴스에서 광범위하게 보도됐다.","category":"빈도 학습","level":17},{"id":11713,"term":"tension","meaning":"긴장(감); 팽팽함","partOfSpeech":"n.","example":"You could feel the tension in the room before the announcement.","exampleTranslation":"발표 전에 방 안의 긴장감이 느껴졌다.","category":"빈도 학습","level":17},{"id":11714,"term":"cable","meaning":"케이블; 전선","partOfSpeech":"n.","example":"I need a cable to connect my laptop to the TV.","exampleTranslation":"노트북을 TV에 연결할 케이블이 필요하다.","category":"빈도 학습","level":17},{"id":11715,"term":"sensitive","meaning":"민감한; 예민한","partOfSpeech":"adj.","example":"She's very sensitive to cold weather.","exampleTranslation":"그녀는 추운 날씨에 매우 민감하다.","category":"빈도 학습","level":17},{"id":11716,"term":"nervous","meaning":"긴장된; 불안한","partOfSpeech":"adj.","example":"I always get nervous before a job interview.","exampleTranslation":"나는 취업 면접 전에 항상 긴장된다.","category":"빈도 학습","level":17},{"id":11717,"term":"input","meaning":"입력; 의견; 기여","partOfSpeech":"n.","example":"We'd appreciate your input on the new design.","exampleTranslation":"새 디자인에 대한 여러분의 의견을 듣고 싶습니다.","category":"빈도 학습","level":17},{"id":11718,"term":"isolate","meaning":"격리하다; 고립시키다","partOfSpeech":"v.","example":"The doctor advised her to isolate at home for a week.","exampleTranslation":"의사는 그녀에게 일주일 동안 집에서 격리하라고 조언했다.","category":"빈도 학습","level":17},{"id":11719,"term":"prisoner","meaning":"수감자; 죄수","partOfSpeech":"n.","example":"The prisoner was released after serving five years.","exampleTranslation":"그 수감자는 5년을 복역한 후 석방됐다.","category":"빈도 학습","level":17},{"id":11720,"term":"eliminate","meaning":"제거하다; 없애다","partOfSpeech":"v.","example":"We need to eliminate all sources of noise in the office.","exampleTranslation":"사무실의 모든 소음 원인을 없애야 해요.","category":"빈도 학습","level":17},{"id":11721,"term":"tight","meaning":"꽉 조이는; 빠듯한","partOfSpeech":"adj.","example":"These shoes are a bit tight around the toes.","exampleTranslation":"이 신발은 발가락 부분이 좀 꽉 껴요.","category":"빈도 학습","level":17},{"id":11722,"term":"wet","meaning":"젖은; 축축한","partOfSpeech":"adj.","example":"Don't go outside — the grass is still wet.","exampleTranslation":"밖에 나가지 마세요 — 잔디가 아직 젖어 있어요.","category":"빈도 학습","level":17},{"id":11723,"term":"secondary","meaning":"이차적인; 부차적인","partOfSpeech":"adj.","example":"Cost is secondary — quality is what matters most.","exampleTranslation":"비용은 부차적이에요 — 품질이 가장 중요해요.","category":"빈도 학습","level":17},{"id":11724,"term":"welfare","meaning":"복지; 안녕","partOfSpeech":"n.","example":"The company genuinely cares about the welfare of its employees.","exampleTranslation":"그 회사는 직원들의 복지를 진심으로 신경 써요.","category":"빈도 학습","level":17},{"id":11725,"term":"recruit","meaning":"모집하다; 채용하다","partOfSpeech":"v.","example":"They are trying to recruit experienced engineers this quarter.","exampleTranslation":"그들은 이번 분기에 경험 있는 엔지니어를 채용하려고 해요.","category":"빈도 학습","level":17},{"id":11726,"term":"exclude","meaning":"제외하다; 배제하다","partOfSpeech":"v.","example":"The discount does not exclude taxes and shipping fees.","exampleTranslation":"그 할인에는 세금과 배송비가 제외되지 않아요.","category":"빈도 학습","level":17},{"id":11727,"term":"string","meaning":"줄; 끈","partOfSpeech":"n.","example":"She tied the package with a piece of string.","exampleTranslation":"그녀는 끈으로 소포를 묶었어요.","category":"빈도 학습","level":17},{"id":11728,"term":"cloud","meaning":"구름; 흐리게 하다","partOfSpeech":"n./v.","example":"A dark cloud moved in and it started to rain.","exampleTranslation":"먹구름이 몰려오더니 비가 내리기 시작했어요.","category":"빈도 학습","level":17},{"id":11729,"term":"persuade","meaning":"설득하다","partOfSpeech":"v.","example":"I finally managed to persuade him to see a doctor.","exampleTranslation":"저는 마침내 그를 설득해서 병원에 가게 했어요.","category":"빈도 학습","level":17},{"id":11730,"term":"inspire","meaning":"영감을 주다; 고무하다","partOfSpeech":"v.","example":"Great teachers inspire students to love learning.","exampleTranslation":"훌륭한 선생님들은 학생들이 배움을 사랑하도록 영감을 줘요.","category":"빈도 학습","level":17},{"id":11731,"term":"grand","meaning":"웅장한; 멋진","partOfSpeech":"adj.","example":"The hotel lobby was absolutely grand with high ceilings.","exampleTranslation":"그 호텔 로비는 천장이 높아서 정말 웅장했어요.","category":"빈도 학습","level":17},{"id":11732,"term":"hence","meaning":"그러므로; 따라서","partOfSpeech":"adv.","example":"The road is closed; hence we need to take a different route.","exampleTranslation":"도로가 막혀 있어요. 그러므로 다른 길로 가야 해요.","category":"빈도 학습","level":17},{"id":11733,"term":"crew","meaning":"승무원; 팀원","partOfSpeech":"n.","example":"The crew prepared the cabin before passengers boarded.","exampleTranslation":"승무원들은 승객이 탑승하기 전에 기내를 준비했어요.","category":"빈도 학습","level":17},{"id":11734,"term":"phenomenon","meaning":"현상; 놀라운 사람·사물","partOfSpeech":"n.","example":"The northern lights are a breathtaking natural phenomenon.","exampleTranslation":"오로라는 정말 숨막히게 아름다운 자연 현상이에요.","category":"빈도 학습","level":17},{"id":11735,"term":"pupil","meaning":"학생; 눈동자","partOfSpeech":"n.","example":"Every pupil in the class passed the final exam.","exampleTranslation":"반의 모든 학생이 기말고사를 통과했어요.","category":"빈도 학습","level":17},{"id":11736,"term":"false","meaning":"거짓의; 틀린","partOfSpeech":"adj.","example":"That rumor turned out to be completely false.","exampleTranslation":"그 소문은 완전히 거짓으로 밝혀졌어요.","category":"빈도 학습","level":17},{"id":11737,"term":"assist","meaning":"돕다; 보조하다","partOfSpeech":"v.","example":"Can you assist me with carrying these boxes?","exampleTranslation":"이 상자 나르는 것 좀 도와줄 수 있어요?","category":"빈도 학습","level":17},{"id":11738,"term":"restore","meaning":"복구하다; 회복시키다","partOfSpeech":"v.","example":"They worked all night to restore power to the neighborhood.","exampleTranslation":"그들은 동네에 전기를 복구하기 위해 밤새 일했어요.","category":"빈도 학습","level":17},{"id":11739,"term":"formula","meaning":"공식; 방법","partOfSpeech":"n.","example":"There is no magic formula for learning a language fast.","exampleTranslation":"언어를 빨리 배우는 마법 같은 공식은 없어요.","category":"빈도 학습","level":17},{"id":11740,"term":"alter","meaning":"바꾸다; 변경하다","partOfSpeech":"v.","example":"We can alter the schedule if that works better for you.","exampleTranslation":"당신에게 더 편하다면 일정을 바꿀 수 있어요.","category":"빈도 학습","level":17},{"id":11741,"term":"perceive","meaning":"인식하다; 느끼다","partOfSpeech":"v.","example":"How you perceive a situation shapes how you respond to it.","exampleTranslation":"상황을 어떻게 인식하느냐가 반응 방식을 결정해요.","category":"빈도 학습","level":17},{"id":11742,"term":"routine","meaning":"일과; 습관적인","partOfSpeech":"n.","example":"My morning routine starts with a glass of water.","exampleTranslation":"제 아침 일과는 물 한 잔으로 시작해요.","category":"빈도 학습","level":17},{"id":11743,"term":"sink","meaning":"가라앉다; 싱크대","partOfSpeech":"v./n.","example":"The boat began to sink after hitting the rocks.","exampleTranslation":"배가 암초에 부딪힌 후 가라앉기 시작했어요.","category":"빈도 학습","level":17},{"id":11744,"term":"stare","meaning":"뚫어지게 보다; 응시하다","partOfSpeech":"v.","example":"It's rude to stare at people on the subway.","exampleTranslation":"지하철에서 사람들을 빤히 쳐다보는 건 무례해요.","category":"빈도 학습","level":17},{"id":11745,"term":"anymore","meaning":"더 이상 (…않다)","partOfSpeech":"adv.","example":"I don't drink coffee anymore — it keeps me up at night.","exampleTranslation":"저는 더 이상 커피를 안 마셔요 — 밤에 잠을 못 자거든요.","category":"빈도 학습","level":17},{"id":11746,"term":"hero","meaning":"영웅; 주인공","partOfSpeech":"n.","example":"The firefighter was called a hero after saving the child.","exampleTranslation":"그 소방관은 아이를 구한 후 영웅으로 불렸어요.","category":"빈도 학습","level":17},{"id":11747,"term":"supporter","meaning":"지지자; 후원자","partOfSpeech":"n.","example":"She has been a strong supporter of local charities for years.","exampleTranslation":"그녀는 수년간 지역 자선단체의 든든한 후원자였어요.","category":"빈도 학습","level":17},{"id":11748,"term":"convert","meaning":"전환하다; 바꾸다","partOfSpeech":"v.","example":"You can convert the file to PDF before sending it.","exampleTranslation":"파일을 보내기 전에 PDF로 변환할 수 있어요.","category":"빈도 학습","level":17},{"id":11749,"term":"steady","meaning":"꾸준한; 안정적인","partOfSpeech":"adj.","example":"She has made steady progress in her English studies.","exampleTranslation":"그녀는 영어 공부에서 꾸준한 발전을 이루고 있어요.","category":"빈도 학습","level":17},{"id":11750,"term":"meter","meaning":"미터; 계량기","partOfSpeech":"n.","example":"The finish line is about one meter away from you.","exampleTranslation":"결승선이 당신에게서 약 1미터 떨어져 있어요.","category":"빈도 학습","level":17},{"id":11751,"term":"truck","meaning":"트럭","partOfSpeech":"n.","example":"A large truck blocked the road for about an hour.","exampleTranslation":"대형 트럭 한 대가 약 한 시간 동안 도로를 막았어요.","category":"빈도 학습","level":17},{"id":11752,"term":"nose","meaning":"코","partOfSpeech":"n.","example":"My nose gets runny every time I go out in the cold.","exampleTranslation":"추운 날 밖에 나갈 때마다 코가 줄줄 흘러요.","category":"빈도 학습","level":17},{"id":11753,"term":"beside","meaning":"옆에; 곁에","partOfSpeech":"prep.","example":"Come sit beside me on the bench.","exampleTranslation":"벤치에 내 옆에 와서 앉아요.","category":"빈도 학습","level":17},{"id":11754,"term":"sail","meaning":"항해하다; 돛","partOfSpeech":"v./n.","example":"We plan to sail around the island this weekend.","exampleTranslation":"우리는 이번 주말에 섬 주변을 항해할 계획이에요.","category":"빈도 학습","level":17},{"id":11755,"term":"disaster","meaning":"재앙; 재난","partOfSpeech":"n.","example":"The earthquake was a total disaster for the whole region.","exampleTranslation":"그 지진은 전 지역에 완전한 재앙이었어요.","category":"빈도 학습","level":17},{"id":11756,"term":"pace","meaning":"속도; 걸음","partOfSpeech":"n.","example":"Let's slow down the pace so everyone can keep up.","exampleTranslation":"모두가 따라올 수 있도록 속도를 늦춰요.","category":"빈도 학습","level":17},{"id":11757,"term":"heavily","meaning":"심하게; 많이","partOfSpeech":"adv.","example":"It rained heavily all morning and flooded the streets.","exampleTranslation":"오전 내내 비가 심하게 내려 거리가 침수됐어요.","category":"빈도 학습","level":17},{"id":11758,"term":"devote","meaning":"헌신하다; 바치다","partOfSpeech":"v.","example":"She decided to devote her weekends to volunteering.","exampleTranslation":"그녀는 주말을 봉사 활동에 바치기로 결심했어요.","category":"빈도 학습","level":17},{"id":11759,"term":"terrorist","meaning":"테러리스트; 테러범","partOfSpeech":"n.","example":"The police arrested the suspected terrorist at the airport.","exampleTranslation":"경찰은 공항에서 테러 용의자를 체포했어요.","category":"빈도 학습","level":17},{"id":11760,"term":"justify","meaning":"정당화하다; 해명하다","partOfSpeech":"v.","example":"How do you justify spending so much on shoes?","exampleTranslation":"신발에 그렇게 많이 쓴 걸 어떻게 정당화해요?","category":"빈도 학습","level":17},{"id":11761,"term":"vital","meaning":"매우 중요한; 필수적인","partOfSpeech":"adj.","example":"Getting enough sleep is vital for your health.","exampleTranslation":"충분한 수면은 건강에 매우 중요해요.","category":"빈도 학습","level":17},{"id":11762,"term":"fascinate","meaning":"매료시키다; 매혹하다","partOfSpeech":"v.","example":"Deep-sea creatures fascinate me like nothing else.","exampleTranslation":"심해 생물은 그 무엇보다 저를 매료시켜요.","category":"빈도 학습","level":17},{"id":11763,"term":"external","meaning":"외부의; 외적인","partOfSpeech":"adj.","example":"The damage was only external and nothing was broken inside.","exampleTranslation":"손상은 외부에만 있었고 안쪽은 멀쩡했어요.","category":"빈도 학습","level":17},{"id":11764,"term":"spare","meaning":"여분의; (시간을) 내다","partOfSpeech":"adj./v.","example":"Do you have a spare charger I could borrow?","exampleTranslation":"빌릴 수 있는 여분 충전기 있어요?","category":"빈도 학습","level":17},{"id":11765,"term":"whenever","meaning":"~할 때마다; 언제든지","partOfSpeech":"conj.","example":"Whenever I feel stressed, I go for a walk.","exampleTranslation":"스트레스받을 때마다 산책을 나가요.","category":"빈도 학습","level":17},{"id":11766,"term":"depression","meaning":"우울증; 불경기","partOfSpeech":"n.","example":"He sought help after struggling with depression for months.","exampleTranslation":"그는 몇 달간 우울증으로 힘들다가 도움을 구했어요.","category":"빈도 학습","level":17},{"id":11767,"term":"guilty","meaning":"죄책감을 느끼는; 유죄의","partOfSpeech":"adj.","example":"I felt guilty about forgetting her birthday.","exampleTranslation":"그녀의 생일을 잊어버려서 죄책감이 들었어요.","category":"빈도 학습","level":17},{"id":11768,"term":"underlie","meaning":"밑에 깔려 있다; 근저에 있다","partOfSpeech":"v.","example":"Fear of failure can underlie a lot of procrastination.","exampleTranslation":"실패에 대한 두려움이 많은 미루기 습관의 근저에 있을 수 있어요.","category":"빈도 학습","level":17},{"id":11769,"term":"mom","meaning":"엄마","partOfSpeech":"n.","example":"My mom always knows when something is wrong.","exampleTranslation":"우리 엄마는 항상 뭔가 잘못됐을 때 알아채요.","category":"빈도 학습","level":17},{"id":11770,"term":"distinction","meaning":"차이; 구별; 탁월함","partOfSpeech":"n.","example":"There is a clear distinction between the two plans.","exampleTranslation":"두 계획 사이에는 분명한 차이가 있어요.","category":"빈도 학습","level":17},{"id":11771,"term":"satisfaction","meaning":"만족; 만족감","partOfSpeech":"n.","example":"She got real satisfaction from finishing the project on time.","exampleTranslation":"그녀는 프로젝트를 제때 끝냈을 때 진정한 만족감을 느꼈어요.","category":"빈도 학습","level":17},{"id":11772,"term":"incorporate","meaning":"포함시키다; 통합하다","partOfSpeech":"v.","example":"Try to incorporate more vegetables into your daily meals.","exampleTranslation":"일상 식사에 채소를 더 많이 포함시키려고 해보세요.","category":"빈도 학습","level":17},{"id":11773,"term":"pour","meaning":"붓다; 쏟아지다","partOfSpeech":"v.","example":"Could you pour me a glass of water, please?","exampleTranslation":"물 한 잔 부어줄 수 있어요?","category":"빈도 학습","level":17},{"id":11774,"term":"sweep","meaning":"쓸다; 휩쓸다","partOfSpeech":"v.","example":"She used a broom to sweep the leaves off the porch.","exampleTranslation":"그녀는 빗자루로 현관의 낙엽을 쓸었어요.","category":"빈도 학습","level":17},{"id":11775,"term":"obligation","meaning":"의무; 책임","partOfSpeech":"n.","example":"You have no obligation to stay if you don't want to.","exampleTranslation":"원하지 않으면 있어야 할 의무는 없어요.","category":"빈도 학습","level":17},{"id":11776,"term":"sir","meaning":"선생님; 손님 (남성에 대한 존칭)","partOfSpeech":"n.","example":"Excuse me, sir, you dropped your wallet.","exampleTranslation":"실례합니다, 손님, 지갑을 떨어뜨리셨어요.","category":"빈도 학습","level":17},{"id":11777,"term":"evaluate","meaning":"평가하다; 검토하다","partOfSpeech":"v.","example":"Take some time to evaluate your options before deciding.","exampleTranslation":"결정하기 전에 시간을 두고 선택지를 평가해 보세요.","category":"빈도 학습","level":17},{"id":11778,"term":"anger","meaning":"분노; 화","partOfSpeech":"n.","example":"He tried to hide his anger but it showed on his face.","exampleTranslation":"그는 분노를 숨기려 했지만 얼굴에 드러났어요.","category":"빈도 학습","level":17},{"id":11779,"term":"pub","meaning":"술집; 펍","partOfSpeech":"n.","example":"Let's grab a drink at the pub after work.","exampleTranslation":"퇴근 후에 펍에서 한잔 하자.","category":"빈도 학습","level":17},{"id":11780,"term":"perception","meaning":"인식; 지각; 이해","partOfSpeech":"n.","example":"Your perception of the situation might be different from mine.","exampleTranslation":"상황에 대한 당신의 인식이 저와 다를 수도 있어요.","category":"빈도 학습","level":17},{"id":11781,"term":"naturally","meaning":"자연스럽게; 당연히","partOfSpeech":"adv.","example":"She naturally took charge when no one else stepped up.","exampleTranslation":"아무도 나서지 않자 그녀가 자연스럽게 주도권을 잡았어요.","category":"빈도 학습","level":17},{"id":11782,"term":"initially","meaning":"처음에는; 초기에","partOfSpeech":"adv.","example":"I was initially nervous, but the interview went well.","exampleTranslation":"처음에는 긴장했지만 면접은 잘 됐어요.","category":"빈도 학습","level":17},{"id":11783,"term":"territory","meaning":"영역; 구역; 영토","partOfSpeech":"n.","example":"That neighborhood is unfamiliar territory for me.","exampleTranslation":"그 동네는 저한테 낯선 구역이에요.","category":"빈도 학습","level":17},{"id":11784,"term":"stream","meaning":"개울; 흐름; 스트리밍하다","partOfSpeech":"n./v.","example":"We found a quiet stream perfect for a picnic.","exampleTranslation":"소풍하기 딱 좋은 조용한 개울을 발견했어요.","category":"빈도 학습","level":17},{"id":11785,"term":"rarely","meaning":"거의 ~하지 않는; 드물게","partOfSpeech":"adv.","example":"She rarely eats fast food anymore.","exampleTranslation":"그녀는 이제 패스트푸드를 거의 먹지 않아요.","category":"빈도 학습","level":17},{"id":11786,"term":"height","meaning":"키; 높이","partOfSpeech":"n.","example":"You need to be a certain height to ride that roller coaster.","exampleTranslation":"그 롤러코스터를 타려면 키가 일정 이상이어야 해요.","category":"빈도 학습","level":17},{"id":11787,"term":"apparent","meaning":"분명한; 명백한","partOfSpeech":"adj.","example":"It was apparent that she hadn't slept the night before.","exampleTranslation":"그녀가 전날 밤 잠을 못 잔 게 분명했어요.","category":"빈도 학습","level":17},{"id":11788,"term":"western","meaning":"서쪽의; 서양의","partOfSpeech":"adj.","example":"She moved to a western city for work last year.","exampleTranslation":"그녀는 작년에 일 때문에 서쪽 도시로 이사했어요.","category":"빈도 학습","level":17},{"id":11789,"term":"expansion","meaning":"확장; 팽창","partOfSpeech":"n.","example":"The café is planning an expansion to the space next door.","exampleTranslation":"그 카페는 옆 공간으로 확장을 계획 중이에요.","category":"빈도 학습","level":17},{"id":11790,"term":"constantly","meaning":"끊임없이; 계속해서","partOfSpeech":"adv.","example":"My little brother constantly asks me for help with homework.","exampleTranslation":"남동생은 끊임없이 숙제 도움을 요청해요.","category":"빈도 학습","level":17},{"id":11791,"term":"scare","meaning":"겁주다; 놀라게 하다","partOfSpeech":"v.","example":"Don't scare me like that, you came out of nowhere!","exampleTranslation":"그렇게 놀라게 하지 마요, 갑자기 나타났잖아요!","category":"빈도 학습","level":17},{"id":11792,"term":"badly","meaning":"심하게; 몹시; 형편없이","partOfSpeech":"adv.","example":"I badly need a vacation after this week.","exampleTranslation":"이번 주 끝나고 나면 휴가가 몹시 필요해요.","category":"빈도 학습","level":17},{"id":11793,"term":"everyday","meaning":"일상적인; 평범한","partOfSpeech":"adj.","example":"Cooking is just an everyday task for me.","exampleTranslation":"요리는 저한테 그냥 일상적인 일이에요.","category":"빈도 학습","level":17},{"id":11794,"term":"boundary","meaning":"경계; 한계","partOfSpeech":"n.","example":"It's important to set a clear boundary at work.","exampleTranslation":"직장에서 명확한 경계를 설정하는 게 중요해요.","category":"빈도 학습","level":17},{"id":11795,"term":"ratio","meaning":"비율; 비","partOfSpeech":"n.","example":"The ratio of staff to students seems too low.","exampleTranslation":"직원 대 학생 비율이 너무 낮아 보여요.","category":"빈도 학습","level":17},{"id":11796,"term":"essay","meaning":"에세이; 논술문","partOfSpeech":"n.","example":"She stayed up late to finish her essay before the deadline.","exampleTranslation":"그녀는 마감 전에 에세이를 끝내려고 밤새 깨어 있었어요.","category":"빈도 학습","level":17},{"id":11797,"term":"scream","meaning":"비명을 지르다; 소리치다","partOfSpeech":"v.","example":"She started to scream when she saw the spider on the wall.","exampleTranslation":"벽에 거미를 보고 그녀는 비명을 지르기 시작했어요.","category":"빈도 학습","level":17},{"id":11798,"term":"pollution","meaning":"오염; 공해","partOfSpeech":"n.","example":"Air pollution in the city has gotten worse this summer.","exampleTranslation":"이번 여름 도심 대기 오염이 더 심해졌어요.","category":"빈도 학습","level":17},{"id":11799,"term":"disorder","meaning":"장애; 혼란; 무질서","partOfSpeech":"n.","example":"He was diagnosed with a sleep disorder last month.","exampleTranslation":"그는 지난달 수면 장애 진단을 받았어요.","category":"빈도 학습","level":17},{"id":11800,"term":"furniture","meaning":"가구","partOfSpeech":"n.","example":"We need to buy new furniture for the living room.","exampleTranslation":"거실에 새 가구를 사야 해요.","category":"빈도 학습","level":17},{"id":11801,"term":"symbol","meaning":"상징; 기호","partOfSpeech":"n.","example":"The dove is a symbol of peace around the world.","exampleTranslation":"비둘기는 전 세계적으로 평화의 상징이에요.","category":"빈도 학습","level":17},{"id":11802,"term":"demonstration","meaning":"시연; 시위","partOfSpeech":"n.","example":"The chef gave a cooking demonstration at the food festival.","exampleTranslation":"셰프가 음식 축제에서 요리 시연을 했어요.","category":"빈도 학습","level":17},{"id":11803,"term":"analyst","meaning":"분석가","partOfSpeech":"n.","example":"The analyst predicted strong sales growth for next quarter.","exampleTranslation":"그 분석가는 다음 분기에 강한 매출 성장을 예측했어요.","category":"빈도 학습","level":17},{"id":11804,"term":"steel","meaning":"철강; 강철","partOfSpeech":"n.","example":"The bridge was built with reinforced steel beams.","exampleTranslation":"그 다리는 강화 강철 빔으로 지어졌어요.","category":"빈도 학습","level":17},{"id":11805,"term":"cake","meaning":"케이크","partOfSpeech":"n.","example":"She baked a chocolate cake for his birthday.","exampleTranslation":"그녀는 그의 생일을 위해 초콜릿 케이크를 구웠어요.","category":"빈도 학습","level":17},{"id":11806,"term":"transform","meaning":"변화시키다; 탈바꿈하다","partOfSpeech":"v.","example":"A fresh coat of paint can transform the look of any room.","exampleTranslation":"페인트를 새로 칠하면 어떤 방이든 분위기를 완전히 바꿀 수 있어요.","category":"빈도 학습","level":17},{"id":11807,"term":"wound","meaning":"상처; 부상","partOfSpeech":"n.","example":"The nurse carefully cleaned the wound on his arm.","exampleTranslation":"간호사가 그의 팔에 난 상처를 조심스럽게 닦아줬어요.","category":"빈도 학습","level":17},{"id":11808,"term":"restriction","meaning":"제한; 규제","partOfSpeech":"n.","example":"There is a speed restriction of 30 mph in this school zone.","exampleTranslation":"이 학교 구역에서는 시속 30마일 속도 제한이 있어요.","category":"빈도 학습","level":17},{"id":11809,"term":"foundation","meaning":"기초; 재단","partOfSpeech":"n.","example":"A strong foundation is essential for any lasting relationship.","exampleTranslation":"튼튼한 기초는 모든 지속적인 관계에 필수적이에요.","category":"빈도 학습","level":17},{"id":11810,"term":"designer","meaning":"디자이너; 설계자","partOfSpeech":"n.","example":"The interior designer suggested warm colors for the bedroom.","exampleTranslation":"인테리어 디자이너가 침실에 따뜻한 색상을 제안했어요.","category":"빈도 학습","level":17},{"id":11811,"term":"strain","meaning":"부담; 긴장","partOfSpeech":"n./v.","example":"Working long hours puts a lot of strain on your body.","exampleTranslation":"오랜 시간 일하면 몸에 큰 부담이 돼요.","category":"빈도 학습","level":17},{"id":11812,"term":"innovation","meaning":"혁신; 새로운 방식","partOfSpeech":"n.","example":"The company is known for its innovation in mobile technology.","exampleTranslation":"그 회사는 모바일 기술 혁신으로 유명해요.","category":"빈도 학습","level":18},{"id":11813,"term":"album","meaning":"앨범","partOfSpeech":"n.","example":"Her new album topped the charts for three weeks straight.","exampleTranslation":"그녀의 새 앨범이 3주 연속으로 차트 1위를 했어요.","category":"빈도 학습","level":18},{"id":11814,"term":"singer","meaning":"가수","partOfSpeech":"n.","example":"The singer performed in front of a huge crowd last night.","exampleTranslation":"그 가수는 어젯밤 엄청난 관중 앞에서 공연했어요.","category":"빈도 학습","level":18},{"id":11815,"term":"trail","meaning":"오솔길; 흔적","partOfSpeech":"n.","example":"We hiked along a scenic trail through the forest.","exampleTranslation":"우리는 숲을 통과하는 경치 좋은 오솔길을 따라 하이킹했어요.","category":"빈도 학습","level":18},{"id":11816,"term":"trap","meaning":"함정; 덫","partOfSpeech":"n./v.","example":"Don't fall into the trap of spending more than you earn.","exampleTranslation":"버는 것보다 더 많이 쓰는 함정에 빠지지 마세요.","category":"빈도 학습","level":18},{"id":11817,"term":"loose","meaning":"헐거운; 느슨한","partOfSpeech":"adj.","example":"One of the screws on the chair is loose and needs tightening.","exampleTranslation":"의자 나사 중 하나가 헐거워서 조여야 해요.","category":"빈도 학습","level":18},{"id":11818,"term":"wealth","meaning":"부; 재산","partOfSpeech":"n.","example":"She shared her wealth by donating to local charities.","exampleTranslation":"그녀는 지역 자선단체에 기부해서 재산을 나눴어요.","category":"빈도 학습","level":18},{"id":11819,"term":"gradually","meaning":"서서히; 점차","partOfSpeech":"adv.","example":"The weather gradually improved as the afternoon went on.","exampleTranslation":"오후가 지나면서 날씨가 서서히 좋아졌어요.","category":"빈도 학습","level":18},{"id":11820,"term":"tank","meaning":"탱크; 저장통","partOfSpeech":"n.","example":"The fish tank in the lobby attracts a lot of attention.","exampleTranslation":"로비에 있는 수족관이 많은 관심을 끌어요.","category":"빈도 학습","level":18},{"id":11821,"term":"evil","meaning":"악; 사악한","partOfSpeech":"n./adj.","example":"The story explores the battle between good and evil.","exampleTranslation":"그 이야기는 선과 악의 싸움을 다루고 있어요.","category":"빈도 학습","level":18},{"id":11822,"term":"remarkable","meaning":"놀라운; 주목할 만한","partOfSpeech":"adj.","example":"It was remarkable how quickly she recovered from the injury.","exampleTranslation":"그녀가 부상에서 얼마나 빨리 회복했는지 놀라웠어요.","category":"빈도 학습","level":18},{"id":11823,"term":"tune","meaning":"곡; 선율","partOfSpeech":"n./v.","example":"I can't get that tune out of my head since this morning.","exampleTranslation":"아침부터 그 곡이 머릿속에서 떠나지 않아요.","category":"빈도 학습","level":18},{"id":11824,"term":"grass","meaning":"풀; 잔디","partOfSpeech":"n.","example":"The kids played on the grass in the backyard all afternoon.","exampleTranslation":"아이들이 오후 내내 뒤뜰 잔디밭에서 놀았어요.","category":"빈도 학습","level":18},{"id":11825,"term":"invitation","meaning":"초대; 초대장","partOfSpeech":"n.","example":"I received an invitation to her wedding in the mail today.","exampleTranslation":"오늘 우편으로 그녀의 결혼식 초대장을 받았어요.","category":"빈도 학습","level":18},{"id":11826,"term":"transition","meaning":"전환; 이행","partOfSpeech":"n.","example":"The transition from college to working life can be challenging.","exampleTranslation":"대학에서 직장 생활로의 전환은 어려울 수 있어요.","category":"빈도 학습","level":18},{"id":11827,"term":"frighten","meaning":"겁주다; 무섭게 하다","partOfSpeech":"v.","example":"Loud thunder can frighten young children during a storm.","exampleTranslation":"폭풍 때 큰 천둥소리는 어린아이들을 겁줄 수 있어요.","category":"빈도 학습","level":18},{"id":11828,"term":"bid","meaning":"입찰; 입찰하다","partOfSpeech":"n./v.","example":"He placed a bid on a vintage guitar at the online auction.","exampleTranslation":"그는 온라인 경매에서 빈티지 기타에 입찰했어요.","category":"빈도 학습","level":18},{"id":11829,"term":"breed","meaning":"품종; 기르다","partOfSpeech":"n./v.","example":"The golden retriever is a popular breed for families with kids.","exampleTranslation":"골든 리트리버는 아이가 있는 가정에서 인기 있는 품종이에요.","category":"빈도 학습","level":18},{"id":11830,"term":"extraordinary","meaning":"대단한; 비범한","partOfSpeech":"adj.","example":"She showed extraordinary patience while teaching the beginners.","exampleTranslation":"그녀는 초보자들을 가르치면서 대단한 인내심을 보여줬어요.","category":"빈도 학습","level":18},{"id":11831,"term":"brilliant","meaning":"뛰어난; 훌륭한","partOfSpeech":"adj.","example":"That was a brilliant idea — everyone loved it at the meeting.","exampleTranslation":"정말 훌륭한 아이디어였어요 — 회의에서 모두가 좋아했어요.","category":"빈도 학습","level":18},{"id":11832,"term":"adviser","meaning":"조언자; 고문","partOfSpeech":"n.","example":"She hired a financial adviser to help plan her retirement.","exampleTranslation":"그녀는 은퇴 계획을 세우는 데 도움받으려고 재정 고문을 고용했어요.","category":"빈도 학습","level":18},{"id":11833,"term":"stem","meaning":"줄기; ~에서 비롯되다","partOfSpeech":"n./v.","example":"Most of his problems stem from poor communication at work.","exampleTranslation":"그의 문제 대부분은 직장에서의 서투른 소통에서 비롯돼요.","category":"빈도 학습","level":18},{"id":11834,"term":"reverse","meaning":"반대; 뒤집다","partOfSpeech":"n./v.","example":"You need to reverse into that tight parking spot carefully.","exampleTranslation":"저 좁은 주차 공간에 후진으로 조심스럽게 들어가야 해요.","category":"빈도 학습","level":18},{"id":11835,"term":"mode","meaning":"방식; 모드","partOfSpeech":"n.","example":"Switch your phone to silent mode before the movie starts.","exampleTranslation":"영화가 시작하기 전에 폰을 무음 모드로 바꾸세요.","category":"빈도 학습","level":18},{"id":11836,"term":"mirror","meaning":"거울; 반영하다","partOfSpeech":"n./v.","example":"She checked her outfit in the mirror before leaving the house.","exampleTranslation":"그녀는 집을 나서기 전에 거울로 옷차림을 확인했어요.","category":"빈도 학습","level":18},{"id":11837,"term":"awful","meaning":"끔찍한; 형편없는","partOfSpeech":"adj.","example":"The traffic this morning was awful — I was late for work.","exampleTranslation":"오늘 아침 교통 상황이 끔찍했어요 — 회사에 지각했어요.","category":"빈도 학습","level":18},{"id":11838,"term":"pose","meaning":"자세를 취하다; 제기하다","partOfSpeech":"v./n.","example":"Everyone had to pose for a group photo after the ceremony.","exampleTranslation":"식이 끝난 후 모두 단체 사진을 위해 자세를 취해야 했어요.","category":"빈도 학습","level":18},{"id":11839,"term":"adjust","meaning":"조정하다; 적응하다","partOfSpeech":"v.","example":"You can adjust the seat height to make it more comfortable.","exampleTranslation":"더 편하게 하려면 좌석 높이를 조정할 수 있어요.","category":"빈도 학습","level":18},{"id":11840,"term":"creative","meaning":"창의적인; 독창적인","partOfSpeech":"adj.","example":"She found a creative way to decorate her room.","exampleTranslation":"그녀는 방을 꾸밀 창의적인 방법을 찾았다.","category":"빈도 학습","level":18},{"id":11841,"term":"nowadays","meaning":"요즘; 오늘날","partOfSpeech":"adv.","example":"Nowadays, most people do their shopping online.","exampleTranslation":"요즘은 대부분의 사람들이 온라인으로 쇼핑한다.","category":"빈도 학습","level":18},{"id":11842,"term":"poem","meaning":"시(詩)","partOfSpeech":"n.","example":"He wrote a poem for his grandmother's birthday.","exampleTranslation":"그는 할머니 생신을 위해 시 한 편을 썼다.","category":"빈도 학습","level":18},{"id":11843,"term":"agricultural","meaning":"농업의; 농사와 관련된","partOfSpeech":"adj.","example":"The region is known for its rich agricultural land.","exampleTranslation":"그 지역은 비옥한 농업 토지로 유명하다.","category":"빈도 학습","level":18},{"id":11844,"term":"competitor","meaning":"경쟁자; 경쟁 업체","partOfSpeech":"n.","example":"Our main competitor just launched a new product.","exampleTranslation":"우리의 주요 경쟁 업체가 방금 새 제품을 출시했다.","category":"빈도 학습","level":18},{"id":11845,"term":"alcohol","meaning":"술; 알코올","partOfSpeech":"n.","example":"The doctor told him to avoid alcohol for a month.","exampleTranslation":"의사는 그에게 한 달간 술을 삼가라고 말했다.","category":"빈도 학습","level":18},{"id":11846,"term":"festival","meaning":"축제; 행사","partOfSpeech":"n.","example":"The music festival attracts thousands of visitors every summer.","exampleTranslation":"그 음악 축제는 매년 여름 수천 명의 방문객을 끌어들인다.","category":"빈도 학습","level":18},{"id":11847,"term":"van","meaning":"밴; 승합차","partOfSpeech":"n.","example":"They rented a van to move all their furniture.","exampleTranslation":"그들은 가구를 모두 옮기기 위해 밴을 빌렸다.","category":"빈도 학습","level":18},{"id":11848,"term":"confident","meaning":"자신감 있는; 확신하는","partOfSpeech":"adj.","example":"She felt confident about her presentation at work.","exampleTranslation":"그녀는 직장에서 할 발표에 자신감이 있었다.","category":"빈도 학습","level":18},{"id":11849,"term":"planet","meaning":"행성; 지구","partOfSpeech":"n.","example":"We need to take better care of our planet.","exampleTranslation":"우리는 우리의 지구를 더 잘 돌봐야 한다.","category":"빈도 학습","level":18},{"id":11850,"term":"curve","meaning":"곡선; 커브","partOfSpeech":"n.","example":"The road has a sharp curve just past the bridge.","exampleTranslation":"다리를 지나자마자 도로에 급커브가 있다.","category":"빈도 학습","level":18},{"id":11851,"term":"knee","meaning":"무릎","partOfSpeech":"n.","example":"He hurt his knee during the basketball game.","exampleTranslation":"그는 농구 경기 중 무릎을 다쳤다.","category":"빈도 학습","level":18},{"id":11852,"term":"overcome","meaning":"극복하다; 이겨내다","partOfSpeech":"v.","example":"It takes time to overcome the fear of public speaking.","exampleTranslation":"대중 앞에서 말하는 것에 대한 두려움을 극복하는 데는 시간이 걸린다.","category":"빈도 학습","level":18},{"id":11853,"term":"web","meaning":"거미줄; 웹(인터넷)","partOfSpeech":"n.","example":"I found the recipe on the web last night.","exampleTranslation":"나는 어젯밤 웹에서 그 요리법을 찾았다.","category":"빈도 학습","level":18},{"id":11854,"term":"depth","meaning":"깊이; 심도","partOfSpeech":"n.","example":"Check the depth of the pool before you dive in.","exampleTranslation":"뛰어들기 전에 수영장 깊이를 확인하세요.","category":"빈도 학습","level":18},{"id":11855,"term":"giant","meaning":"거대한; 거인","partOfSpeech":"adj.","example":"There was a giant tree in the middle of the park.","exampleTranslation":"공원 한가운데 거대한 나무가 있었다.","category":"빈도 학습","level":18},{"id":11856,"term":"god","meaning":"신(神); 하느님","partOfSpeech":"n.","example":"Many people pray to god when they face difficult times.","exampleTranslation":"많은 사람들이 힘든 시간에 신에게 기도한다.","category":"빈도 학습","level":18},{"id":11857,"term":"portion","meaning":"부분; (음식의) 1인분","partOfSpeech":"n.","example":"She only ate a small portion of her meal.","exampleTranslation":"그녀는 식사의 일부만 먹었다.","category":"빈도 학습","level":18},{"id":11858,"term":"substance","meaning":"물질; 실질","partOfSpeech":"n.","example":"The label warned that the substance could be harmful.","exampleTranslation":"라벨에는 그 물질이 해로울 수 있다고 경고했다.","category":"빈도 학습","level":18},{"id":11859,"term":"extensive","meaning":"광범위한; 대규모의","partOfSpeech":"adj.","example":"The hotel went through extensive renovations last year.","exampleTranslation":"그 호텔은 작년에 대규모 리모델링을 거쳤다.","category":"빈도 학습","level":18},{"id":11860,"term":"interpret","meaning":"해석하다; 통역하다","partOfSpeech":"v.","example":"It is hard to interpret his silence as agreement.","exampleTranslation":"그의 침묵을 동의로 해석하기는 어렵다.","category":"빈도 학습","level":18},{"id":11861,"term":"independence","meaning":"독립; 자립","partOfSpeech":"n.","example":"Living alone gave her a sense of independence.","exampleTranslation":"혼자 살면서 그녀는 독립심을 느꼈다.","category":"빈도 학습","level":18},{"id":11862,"term":"sugar","meaning":"설탕; 당분","partOfSpeech":"n.","example":"I usually add a little sugar to my coffee.","exampleTranslation":"나는 보통 커피에 설탕을 조금 넣는다.","category":"빈도 학습","level":18},{"id":11863,"term":"inner","meaning":"내면의; 안쪽의","partOfSpeech":"adj.","example":"Yoga helps me find my inner calm after a stressful day.","exampleTranslation":"요가는 스트레스받은 하루 끝에 내면의 평온을 찾도록 도와준다.","category":"빈도 학습","level":18},{"id":11864,"term":"harm","meaning":"해; 피해","partOfSpeech":"n./v.","example":"Spending too much time on screens can harm your eyesight.","exampleTranslation":"화면을 너무 오래 보면 시력에 해가 될 수 있다.","category":"빈도 학습","level":18},{"id":11865,"term":"pink","meaning":"분홍색; 분홍빛의","partOfSpeech":"n.","example":"She painted her bedroom walls pink.","exampleTranslation":"그녀는 침실 벽을 분홍색으로 칠했다.","category":"빈도 학습","level":18},{"id":11866,"term":"shadow","meaning":"그림자; 그늘","partOfSpeech":"n.","example":"The shadow of the building covered the whole street.","exampleTranslation":"건물의 그림자가 거리 전체를 덮었다.","category":"빈도 학습","level":18},{"id":11867,"term":"strip","meaning":"벗기다; 좁고 긴 조각","partOfSpeech":"v.","example":"He had to strip the old paint off the wall before repainting.","exampleTranslation":"그는 다시 칠하기 전에 벽의 낡은 페인트를 벗겨내야 했다.","category":"빈도 학습","level":18},{"id":11868,"term":"smooth","meaning":"매끄러운; 부드러운","partOfSpeech":"adj.","example":"The baby's skin was incredibly smooth.","exampleTranslation":"아기의 피부는 놀랍도록 매끄러웠다.","category":"빈도 학습","level":18},{"id":11869,"term":"intervention","meaning":"개입; 중재","partOfSpeech":"n.","example":"Early intervention can prevent small problems from getting worse.","exampleTranslation":"조기 개입은 작은 문제가 더 악화되는 것을 막을 수 있다.","category":"빈도 학습","level":18},{"id":11870,"term":"impress","meaning":"인상을 주다; 감동시키다","partOfSpeech":"v.","example":"He wanted to impress his boss with the new report.","exampleTranslation":"그는 새 보고서로 상사에게 좋은 인상을 주고 싶었다.","category":"빈도 학습","level":18},{"id":11871,"term":"exam","meaning":"시험; 검사","partOfSpeech":"n.","example":"She studied all weekend to prepare for the exam.","exampleTranslation":"그녀는 시험을 준비하기 위해 주말 내내 공부했다.","category":"빈도 학습","level":18},{"id":11872,"term":"vice","meaning":"악습; 부도덕한 행위","partOfSpeech":"n.","example":"Gambling became his worst vice over the years.","exampleTranslation":"도박은 세월이 지나면서 그의 가장 나쁜 악습이 되었다.","category":"빈도 학습","level":18},{"id":11873,"term":"radical","meaning":"급진적인; 근본적인","partOfSpeech":"adj.","example":"The company made radical changes to its hiring process.","exampleTranslation":"그 회사는 채용 과정에 근본적인 변화를 가했다.","category":"빈도 학습","level":18},{"id":11874,"term":"similarly","meaning":"마찬가지로; 비슷하게","partOfSpeech":"adv.","example":"My sister loves hiking, and similarly, I enjoy long walks.","exampleTranslation":"내 언니는 등산을 좋아하고, 마찬가지로 나도 오래 걷는 것을 즐긴다.","category":"빈도 학습","level":18},{"id":11875,"term":"behave","meaning":"행동하다; 예의 바르게 굴다","partOfSpeech":"v.","example":"Please behave yourself at the dinner table.","exampleTranslation":"식탁에서 예의 바르게 굴어라.","category":"빈도 학습","level":18},{"id":11876,"term":"loud","meaning":"큰 소리의; 시끄러운","partOfSpeech":"adj.","example":"The music next door was too loud to sleep.","exampleTranslation":"옆집 음악 소리가 너무 커서 잠을 잘 수 없었다.","category":"빈도 학습","level":18},{"id":11877,"term":"dimension","meaning":"차원; 크기","partOfSpeech":"n.","example":"Check the exact dimension of the room before buying furniture.","exampleTranslation":"가구를 사기 전에 방의 정확한 크기를 확인하세요.","category":"빈도 학습","level":18},{"id":11878,"term":"subsequent","meaning":"그 다음의; 이후의","partOfSpeech":"adj.","example":"The first meeting went well, and subsequent talks were even better.","exampleTranslation":"첫 번째 회의는 잘 됐고, 이후 협의들은 더욱 좋았다.","category":"빈도 학습","level":18},{"id":11879,"term":"infection","meaning":"감염; 전염","partOfSpeech":"n.","example":"She went to the doctor because she suspected an ear infection.","exampleTranslation":"그녀는 귀 감염이 의심되어 병원에 갔다.","category":"빈도 학습","level":18},{"id":11880,"term":"jacket","meaning":"재킷; 겉옷","partOfSpeech":"n.","example":"She grabbed her jacket before heading outside.","exampleTranslation":"그녀는 밖으로 나가기 전에 재킷을 집어들었다.","category":"빈도 학습","level":18},{"id":11881,"term":"efficiency","meaning":"효율; 능률","partOfSpeech":"n.","example":"The new system improved the efficiency of the whole team.","exampleTranslation":"새 시스템은 팀 전체의 효율을 높였다.","category":"빈도 학습","level":18},{"id":11882,"term":"dirty","meaning":"더러운; 지저분한","partOfSpeech":"adj.","example":"My hands were dirty after working in the garden.","exampleTranslation":"정원 일을 하고 나서 손이 더러워졌다.","category":"빈도 학습","level":18},{"id":11883,"term":"statistic","meaning":"통계; 통계 수치","partOfSpeech":"n.","example":"That statistic shows how fast the population is growing.","exampleTranslation":"그 통계는 인구가 얼마나 빨리 증가하고 있는지 보여준다.","category":"빈도 학습","level":18},{"id":11884,"term":"regularly","meaning":"규칙적으로; 정기적으로","partOfSpeech":"adv.","example":"She regularly goes for a walk after dinner.","exampleTranslation":"그녀는 저녁 식사 후 규칙적으로 산책을 간다.","category":"빈도 학습","level":18},{"id":11885,"term":"resort","meaning":"리조트; 의지하다","partOfSpeech":"n./v.","example":"They stayed at a beach resort for their honeymoon.","exampleTranslation":"그들은 신혼여행으로 해변 리조트에 묵었다.","category":"빈도 학습","level":18},{"id":11886,"term":"iron","meaning":"다리미; 철; 다림질하다","partOfSpeech":"n./v.","example":"Could you iron this shirt before the meeting?","exampleTranslation":"회의 전에 이 셔츠를 다려줄 수 있어요?","category":"빈도 학습","level":18},{"id":11887,"term":"broadcast","meaning":"방송; 방송하다","partOfSpeech":"n./v.","example":"The game will broadcast live on national television tonight.","exampleTranslation":"그 경기는 오늘 밤 전국 방송으로 생중계될 것이다.","category":"빈도 학습","level":18},{"id":11888,"term":"membership","meaning":"회원 자격; 회원권","partOfSpeech":"n.","example":"I got a gym membership to work out more often.","exampleTranslation":"더 자주 운동하려고 헬스장 회원권을 끊었다.","category":"빈도 학습","level":18},{"id":11889,"term":"blind","meaning":"눈먼; 앞을 못 보는","partOfSpeech":"adj.","example":"The blind man found his way using a white cane.","exampleTranslation":"그 시각장애인은 흰 지팡이를 이용해 길을 찾았다.","category":"빈도 학습","level":18},{"id":11890,"term":"pure","meaning":"순수한; 깨끗한","partOfSpeech":"adj.","example":"The spring water here is pure and safe to drink.","exampleTranslation":"여기 샘물은 순수하고 마시기에 안전하다.","category":"빈도 학습","level":18},{"id":11891,"term":"bloody","meaning":"피투성이의; 피가 나는","partOfSpeech":"adj.","example":"He showed up at the clinic with a bloody cut on his arm.","exampleTranslation":"그는 팔에 피가 흐르는 상처를 입고 진료소에 나타났다.","category":"빈도 학습","level":18},{"id":11892,"term":"ally","meaning":"동맹국; 우군; 지지자","partOfSpeech":"n.","example":"She proved to be a strong ally during the difficult project.","exampleTranslation":"그녀는 힘든 프로젝트 기간 동안 든든한 지지자임을 입증했다.","category":"빈도 학습","level":18},{"id":11893,"term":"quantity","meaning":"양; 수량","partOfSpeech":"n.","example":"Please check the quantity of items before shipping.","exampleTranslation":"배송 전에 물품의 수량을 확인해 주세요.","category":"빈도 학습","level":18},{"id":11894,"term":"bend","meaning":"구부리다; 굽히다","partOfSpeech":"v.","example":"You need to bend your knees when you lift heavy boxes.","exampleTranslation":"무거운 상자를 들 때는 무릎을 굽혀야 한다.","category":"빈도 학습","level":18},{"id":11895,"term":"mature","meaning":"성숙한; 어른스러운","partOfSpeech":"adj.","example":"He handled the conflict in a very mature way.","exampleTranslation":"그는 갈등을 매우 성숙하게 처리했다.","category":"빈도 학습","level":18},{"id":11896,"term":"briefly","meaning":"잠깐; 간략하게","partOfSpeech":"adv.","example":"She briefly explained the plan before the meeting started.","exampleTranslation":"회의가 시작되기 전에 그녀는 계획을 간략하게 설명했다.","category":"빈도 학습","level":18},{"id":11897,"term":"alarm","meaning":"경보; 알람; 불안","partOfSpeech":"n.","example":"The alarm went off at six in the morning.","exampleTranslation":"아침 여섯 시에 알람이 울렸다.","category":"빈도 학습","level":18},{"id":11898,"term":"disturb","meaning":"방해하다; 불안하게 하다","partOfSpeech":"v.","example":"Please don't disturb me while I'm on this call.","exampleTranslation":"통화 중에는 방해하지 마세요.","category":"빈도 학습","level":18},{"id":11899,"term":"sustain","meaning":"유지하다; 지속하다","partOfSpeech":"v.","example":"It's hard to sustain that level of energy all day.","exampleTranslation":"하루 종일 그 수준의 에너지를 유지하기는 어렵다.","category":"빈도 학습","level":18},{"id":11900,"term":"flood","meaning":"홍수; 밀려들다","partOfSpeech":"n./v.","example":"The heavy rain caused a flood in the lower part of town.","exampleTranslation":"폭우로 마을 저지대에 홍수가 발생했다.","category":"빈도 학습","level":18},{"id":11901,"term":"poverty","meaning":"가난; 빈곤","partOfSpeech":"n.","example":"Many families in the area are still living in poverty.","exampleTranslation":"그 지역의 많은 가정이 여전히 빈곤 속에 살고 있다.","category":"빈도 학습","level":18},{"id":11902,"term":"crazy","meaning":"미친; 엄청난","partOfSpeech":"adj.","example":"It sounds crazy, but it actually worked.","exampleTranslation":"말도 안 되게 들리지만 실제로 효과가 있었다.","category":"빈도 학습","level":18},{"id":11903,"term":"cite","meaning":"인용하다; 예로 들다","partOfSpeech":"v.","example":"The report will cite several studies to support the findings.","exampleTranslation":"그 보고서는 결과를 뒷받침하기 위해 여러 연구를 인용할 것이다.","category":"빈도 학습","level":18},{"id":11904,"term":"newly","meaning":"새로; 최근에","partOfSpeech":"adv.","example":"They moved into a newly renovated apartment last month.","exampleTranslation":"그들은 지난달에 새로 리모델링된 아파트로 이사했다.","category":"빈도 학습","level":18},{"id":11905,"term":"parallel","meaning":"평행한; 유사한","partOfSpeech":"adj.","example":"The two streets run parallel to each other through downtown.","exampleTranslation":"두 거리는 시내를 가로질러 서로 평행하게 이어진다.","category":"빈도 학습","level":18},{"id":11906,"term":"gender","meaning":"성별","partOfSpeech":"n.","example":"The form asks for your name, age, and gender.","exampleTranslation":"양식에는 이름, 나이, 성별을 기입하도록 되어 있다.","category":"빈도 학습","level":18},{"id":11907,"term":"sponsor","meaning":"후원자; 후원하다","partOfSpeech":"n./v.","example":"A local company agreed to sponsor the charity event.","exampleTranslation":"지역 기업이 자선 행사를 후원하기로 했다.","category":"빈도 학습","level":18},{"id":11908,"term":"boot","meaning":"부츠; 장화","partOfSpeech":"n.","example":"She put on her rain boot before stepping into the puddle.","exampleTranslation":"그녀는 웅덩이에 발을 디디기 전에 장화를 신었다.","category":"빈도 학습","level":18},{"id":11909,"term":"accurate","meaning":"정확한; 정밀한","partOfSpeech":"adj.","example":"Make sure your measurements are accurate before you cut.","exampleTranslation":"자르기 전에 치수가 정확한지 확인하세요.","category":"빈도 학습","level":18},{"id":11910,"term":"dealer","meaning":"판매상; 딜러","partOfSpeech":"n.","example":"We bought the car directly from a local dealer.","exampleTranslation":"우리는 지역 딜러에게서 직접 차를 샀다.","category":"빈도 학습","level":18},{"id":11911,"term":"button","meaning":"단추; 버튼","partOfSpeech":"n.","example":"Press the button on the right to turn it on.","exampleTranslation":"오른쪽 버튼을 누르면 켜집니다.","category":"빈도 학습","level":18},{"id":11912,"term":"burden","meaning":"짐; 부담","partOfSpeech":"n.","example":"Taking care of the kids alone was a real burden for her.","exampleTranslation":"혼자 아이들을 돌보는 것은 그녀에게 정말 큰 부담이었다.","category":"빈도 학습","level":18},{"id":11913,"term":"desert","meaning":"사막; 버리다","partOfSpeech":"n./v.","example":"Temperatures in the desert can reach over 50 degrees.","exampleTranslation":"사막의 기온은 50도 이상까지 올라갈 수 있다.","category":"빈도 학습","level":18},{"id":11914,"term":"mate","meaning":"친구; 짝; 동료","partOfSpeech":"n.","example":"He went to the pub with his mate after work.","exampleTranslation":"그는 퇴근 후 친구와 함께 술집에 갔다.","category":"빈도 학습","level":18},{"id":11915,"term":"occasionally","meaning":"가끔; 때때로","partOfSpeech":"adv.","example":"We occasionally go out for dinner on weekends.","exampleTranslation":"우리는 주말에 가끔 외식을 하러 나간다.","category":"빈도 학습","level":18},{"id":11916,"term":"shareholder","meaning":"주주","partOfSpeech":"n.","example":"Every shareholder received a copy of the annual report.","exampleTranslation":"모든 주주에게 연간 보고서 사본이 전달되었다.","category":"빈도 학습","level":18},{"id":11917,"term":"bowl","meaning":"그릇; 볼","partOfSpeech":"n.","example":"She ate a warm bowl of soup for lunch.","exampleTranslation":"그녀는 점심으로 따뜻한 수프 한 그릇을 먹었다.","category":"빈도 학습","level":18},{"id":11918,"term":"discovery","meaning":"발견; 발굴","partOfSpeech":"n.","example":"The discovery of this ancient site shocked the whole team.","exampleTranslation":"이 고대 유적의 발견은 팀 전체를 놀라게 했다.","category":"빈도 학습","level":19},{"id":11919,"term":"resistance","meaning":"저항; 반발","partOfSpeech":"n.","example":"The new policy faced strong resistance from the staff.","exampleTranslation":"새 정책은 직원들의 강한 반발에 부딪혔다.","category":"빈도 학습","level":19},{"id":11920,"term":"bath","meaning":"목욕; 욕조","partOfSpeech":"n.","example":"I usually take a bath before bed.","exampleTranslation":"나는 보통 자기 전에 목욕을 한다.","category":"빈도 학습","level":19},{"id":11921,"term":"frequency","meaning":"빈도; 주파수","partOfSpeech":"n.","example":"The frequency of his calls increased after they broke up.","exampleTranslation":"그들이 헤어진 후 그의 전화 빈도가 늘어났다.","category":"빈도 학습","level":19},{"id":11922,"term":"criticize","meaning":"비판하다; 비평하다","partOfSpeech":"v.","example":"It's easy to criticize others but hard to improve yourself.","exampleTranslation":"남을 비판하기는 쉽지만 자신을 발전시키기는 어렵다.","category":"빈도 학습","level":19},{"id":11923,"term":"tap","meaning":"두드리다; 수도꼭지","partOfSpeech":"n./v.","example":"She felt someone tap her on the shoulder.","exampleTranslation":"누군가 그녀의 어깨를 톡 두드리는 것이 느껴졌다.","category":"빈도 학습","level":19},{"id":11924,"term":"philosophy","meaning":"철학; 인생관","partOfSpeech":"n.","example":"His philosophy is to live one day at a time.","exampleTranslation":"그의 인생관은 하루하루를 살아가는 것이다.","category":"빈도 학습","level":19},{"id":11925,"term":"lip","meaning":"입술","partOfSpeech":"n.","example":"She bit her lip nervously before the interview.","exampleTranslation":"그녀는 면접 전 긴장해서 입술을 깨물었다.","category":"빈도 학습","level":19},{"id":11926,"term":"attribute","meaning":"~의 덕분으로 보다; 속성","partOfSpeech":"n./v.","example":"Many people attribute their success to hard work and good luck.","exampleTranslation":"많은 사람들이 자신의 성공을 노력과 행운 덕분으로 본다.","category":"빈도 학습","level":19},{"id":11927,"term":"apologize","meaning":"사과하다","partOfSpeech":"v.","example":"He called to apologize for missing the meeting.","exampleTranslation":"그는 회의에 빠진 것을 사과하려고 전화했다.","category":"빈도 학습","level":19},{"id":11928,"term":"approval","meaning":"승인; 찬성","partOfSpeech":"n.","example":"The project needs the manager's approval before we start.","exampleTranslation":"프로젝트를 시작하기 전에 관리자의 승인이 필요하다.","category":"빈도 학습","level":19},{"id":11929,"term":"grab","meaning":"붙잡다; 급히 먹다","partOfSpeech":"v.","example":"Let's grab a coffee before the meeting starts.","exampleTranslation":"회의 시작 전에 커피 한 잔 빨리 마시자.","category":"빈도 학습","level":19},{"id":11930,"term":"entitle","meaning":"권리를 주다; 제목을 붙이다","partOfSpeech":"v.","example":"Being a member will entitle you to special discounts at the store.","exampleTranslation":"회원이 되면 매장에서 특별 할인을 받을 권리가 생긴다.","category":"빈도 학습","level":19},{"id":11931,"term":"lend","meaning":"빌려주다","partOfSpeech":"v.","example":"Could you lend me your pen for a second?","exampleTranslation":"잠깐 펜 좀 빌려줄 수 있어?","category":"빈도 학습","level":19},{"id":11932,"term":"involvement","meaning":"참여; 관여","partOfSpeech":"n.","example":"His involvement in the project was crucial to its success.","exampleTranslation":"그 프로젝트에 대한 그의 참여가 성공에 결정적이었다.","category":"빈도 학습","level":19},{"id":11933,"term":"exposure","meaning":"노출; 접촉","partOfSpeech":"n.","example":"Regular exposure to English helps you improve faster.","exampleTranslation":"규칙적인 영어 노출이 더 빠른 실력 향상에 도움이 된다.","category":"빈도 학습","level":19},{"id":11934,"term":"conventional","meaning":"전통적인; 관습적인","partOfSpeech":"adj.","example":"She chose a conventional wedding instead of a beach ceremony.","exampleTranslation":"그녀는 해변 예식 대신 전통적인 결혼식을 선택했다.","category":"빈도 학습","level":19},{"id":11935,"term":"digital","meaning":"디지털의; 전자식의","partOfSpeech":"adj.","example":"I store all my photos in digital format on the cloud.","exampleTranslation":"나는 모든 사진을 클라우드에 디지털 형식으로 저장한다.","category":"빈도 학습","level":19},{"id":11936,"term":"translate","meaning":"번역하다; 옮기다","partOfSpeech":"v.","example":"Can you translate this menu for me? I don't read Japanese.","exampleTranslation":"이 메뉴 좀 번역해 줄 수 있어? 나는 일본어를 못 읽어.","category":"빈도 학습","level":19},{"id":11937,"term":"edit","meaning":"편집하다; 수정하다","partOfSpeech":"v.","example":"Please edit this email before you send it to the client.","exampleTranslation":"고객에게 보내기 전에 이 이메일을 수정해 주세요.","category":"빈도 학습","level":19},{"id":11938,"term":"formation","meaning":"형성; 대형","partOfSpeech":"n.","example":"The formation of new habits takes at least a few weeks.","exampleTranslation":"새로운 습관의 형성에는 최소 몇 주가 걸린다.","category":"빈도 학습","level":19},{"id":11939,"term":"pleasant","meaning":"기분 좋은; 즐거운","partOfSpeech":"adj.","example":"We had a pleasant walk through the park this morning.","exampleTranslation":"우리는 오늘 아침 공원을 기분 좋게 산책했다.","category":"빈도 학습","level":19},{"id":11940,"term":"overseas","meaning":"해외에; 해외의","partOfSpeech":"adv.","example":"She moved overseas to pursue a career in finance.","exampleTranslation":"그녀는 금융 분야에서 커리어를 쌓기 위해 해외로 이주했다.","category":"빈도 학습","level":19},{"id":11941,"term":"advocate","meaning":"지지하다; 옹호자","partOfSpeech":"n./v.","example":"She is a strong advocate for mental health awareness.","exampleTranslation":"그녀는 정신 건강 인식 향상을 강하게 지지한다.","category":"빈도 학습","level":19},{"id":11942,"term":"establishment","meaning":"설립; 기관","partOfSpeech":"n.","example":"The establishment of that school changed the whole neighborhood.","exampleTranslation":"그 학교의 설립은 동네 전체를 바꿔 놓았다.","category":"빈도 학습","level":19},{"id":11943,"term":"summary","meaning":"요약; 개요","partOfSpeech":"n.","example":"Can you give me a quick summary of what happened?","exampleTranslation":"무슨 일이 있었는지 간단히 요약해 줄 수 있어?","category":"빈도 학습","level":19},{"id":11944,"term":"rough","meaning":"거친; 대략적인","partOfSpeech":"adj.","example":"The road was rough, so the drive took longer than expected.","exampleTranslation":"도로가 울퉁불퉁해서 예상보다 운전이 오래 걸렸다.","category":"빈도 학습","level":19},{"id":11945,"term":"pen","meaning":"펜; 볼펜","partOfSpeech":"n.","example":"Do you have a pen I could borrow to sign this form?","exampleTranslation":"이 양식에 서명할 펜 하나 빌릴 수 있을까요?","category":"빈도 학습","level":19},{"id":11946,"term":"recovery","meaning":"회복; 되찾기","partOfSpeech":"n.","example":"Her recovery from the surgery was faster than the doctors expected.","exampleTranslation":"그녀의 수술 후 회복은 의사들이 예상했던 것보다 빨랐다.","category":"빈도 학습","level":19},{"id":11947,"term":"seal","meaning":"봉인하다; 밀봉; 물개","partOfSpeech":"n./v.","example":"Make sure to seal the envelope before you drop it in the mailbox.","exampleTranslation":"우편함에 넣기 전에 봉투를 꼭 봉인하세요.","category":"빈도 학습","level":19},{"id":11948,"term":"tube","meaning":"관; 튜브","partOfSpeech":"n.","example":"She squeezed the last bit of toothpaste from the tube.","exampleTranslation":"그녀는 튜브에서 치약 마지막 한 방울까지 짜냈다.","category":"빈도 학습","level":19},{"id":11949,"term":"tower","meaning":"탑; 우뚝 솟다","partOfSpeech":"n.","example":"The tower is visible from almost anywhere in the city.","exampleTranslation":"그 탑은 도시 거의 어디서나 보인다.","category":"빈도 학습","level":19},{"id":11950,"term":"characterize","meaning":"특징짓다; 묘사하다","partOfSpeech":"v.","example":"What would you say characterize a good leader?","exampleTranslation":"좋은 리더를 어떻게 특징짓을 수 있을까요?","category":"빈도 학습","level":19},{"id":11951,"term":"specify","meaning":"명시하다; 구체적으로 말하다","partOfSpeech":"v.","example":"Please specify the size you want when placing your order.","exampleTranslation":"주문할 때 원하는 사이즈를 명시해 주세요.","category":"빈도 학습","level":19},{"id":11952,"term":"exact","meaning":"정확한; 바로 그","partOfSpeech":"adj.","example":"That is the exact spot where we first met.","exampleTranslation":"여기가 바로 우리가 처음 만났던 그 장소야.","category":"빈도 학습","level":19},{"id":11953,"term":"spin","meaning":"돌다; 회전시키다","partOfSpeech":"v.","example":"The kids love to spin around until they get dizzy.","exampleTranslation":"아이들은 어지러울 때까지 빙글빙글 도는 것을 좋아한다.","category":"빈도 학습","level":19},{"id":11954,"term":"operator","meaning":"운영자; 교환원","partOfSpeech":"n.","example":"The tour operator arranged everything including hotels and transfers.","exampleTranslation":"그 여행사 운영자는 호텔과 이동수단 등 모든 것을 준비해 줬다.","category":"빈도 학습","level":19},{"id":11955,"term":"infant","meaning":"유아; 아기","partOfSpeech":"n.","example":"The infant smiled at her mother for the first time today.","exampleTranslation":"그 아기는 오늘 처음으로 엄마에게 미소를 지었다.","category":"빈도 학습","level":19},{"id":11956,"term":"dig","meaning":"파다; 캐다","partOfSpeech":"v.","example":"The dog started to dig a hole near the fence.","exampleTranslation":"개가 울타리 근처에 구멍을 파기 시작했다.","category":"빈도 학습","level":19},{"id":11957,"term":"drag","meaning":"끌다; 질질 끌다","partOfSpeech":"v.","example":"Don't drag your feet — we're going to be late.","exampleTranslation":"꾸물거리지 마, 우리 늦겠어.","category":"빈도 학습","level":19},{"id":11958,"term":"mount","meaning":"오르다; 증가하다; 산","partOfSpeech":"n./v.","example":"The pressure to finish the project began to mount as the deadline approached.","exampleTranslation":"마감일이 다가오면서 프로젝트를 끝내야 한다는 압박이 커지기 시작했다.","category":"빈도 학습","level":19},{"id":11959,"term":"wrap","meaning":"싸다; 포장하다","partOfSpeech":"v.","example":"She used recycled paper to wrap the birthday gift.","exampleTranslation":"그녀는 생일 선물을 포장하는 데 재활용 종이를 사용했다.","category":"빈도 학습","level":19},{"id":11960,"term":"anticipate","meaning":"예상하다; 기대하다","partOfSpeech":"v.","example":"I didn't anticipate such a long wait at the clinic.","exampleTranslation":"병원에서 그렇게 오래 기다릴 줄은 예상하지 못했어요.","category":"빈도 학습","level":19},{"id":11961,"term":"dependent","meaning":"의존하는; 부양가족","partOfSpeech":"adj.","example":"He is still dependent on his parents for rent money.","exampleTranslation":"그는 아직도 월세를 부모님에게 의존하고 있어요.","category":"빈도 학습","level":19},{"id":11962,"term":"specialize","meaning":"전문으로 하다; 특화하다","partOfSpeech":"v.","example":"This bakery chooses to specialize in sourdough bread.","exampleTranslation":"이 베이커리는 사워도우 빵을 전문으로 해요.","category":"빈도 학습","level":19},{"id":11963,"term":"angle","meaning":"각도; 관점","partOfSpeech":"n.","example":"Try taking the photo from a lower angle for a better shot.","exampleTranslation":"더 좋은 사진을 위해 낮은 각도에서 찍어 보세요.","category":"빈도 학습","level":19},{"id":11964,"term":"chicken","meaning":"닭; 닭고기","partOfSpeech":"n.","example":"We ordered grilled chicken and a salad for dinner.","exampleTranslation":"저녁으로 구운 치킨과 샐러드를 주문했어요.","category":"빈도 학습","level":19},{"id":11965,"term":"anxiety","meaning":"불안; 걱정","partOfSpeech":"n.","example":"She felt a lot of anxiety before her job interview.","exampleTranslation":"그녀는 취업 면접 전에 불안감을 많이 느꼈어요.","category":"빈도 학습","level":19},{"id":11966,"term":"virus","meaning":"바이러스; 컴퓨터 바이러스","partOfSpeech":"n.","example":"Wash your hands often to avoid catching a virus.","exampleTranslation":"바이러스에 걸리지 않으려면 손을 자주 씻으세요.","category":"빈도 학습","level":19},{"id":11967,"term":"precisely","meaning":"정확히; 바로","partOfSpeech":"adv.","example":"That is precisely what I was trying to say.","exampleTranslation":"그게 바로 제가 말하려던 거예요.","category":"빈도 학습","level":19},{"id":11968,"term":"rival","meaning":"경쟁자; 맞수","partOfSpeech":"n.","example":"The two stores are fierce rival businesses on the same street.","exampleTranslation":"그 두 가게는 같은 거리에서 치열하게 경쟁하는 경쟁자예요.","category":"빈도 학습","level":19},{"id":11969,"term":"offense","meaning":"위반; 기분 나쁘게 함","partOfSpeech":"n.","example":"No offense, but your idea needs more work.","exampleTranslation":"기분 나쁘게 하려는 건 아닌데, 당신 아이디어는 좀 더 다듬을 필요가 있어요.","category":"빈도 학습","level":19},{"id":11970,"term":"detect","meaning":"감지하다; 발견하다","partOfSpeech":"v.","example":"The smoke alarm can detect even a small fire early.","exampleTranslation":"연기 경보기는 작은 불도 일찍 감지할 수 있어요.","category":"빈도 학습","level":19},{"id":11971,"term":"teenager","meaning":"10대 청소년","partOfSpeech":"n.","example":"Every teenager in the class had a smartphone.","exampleTranslation":"반의 모든 10대 학생들이 스마트폰을 가지고 있었어요.","category":"빈도 학습","level":19},{"id":11972,"term":"admire","meaning":"감탄하다; 존경하다","partOfSpeech":"v.","example":"I really admire how hard she works every day.","exampleTranslation":"저는 그녀가 매일 얼마나 열심히 일하는지 정말 존경해요.","category":"빈도 학습","level":19},{"id":11973,"term":"moderate","meaning":"보통의; 적당한","partOfSpeech":"adj.","example":"Just a moderate amount of exercise each day keeps you healthy.","exampleTranslation":"매일 적당한 양의 운동만으로도 건강을 유지할 수 있어요.","category":"빈도 학습","level":19},{"id":11974,"term":"surgery","meaning":"수술","partOfSpeech":"n.","example":"He recovered quickly after knee surgery last month.","exampleTranslation":"그는 지난달 무릎 수술 후 빠르게 회복했어요.","category":"빈도 학습","level":19},{"id":11975,"term":"musician","meaning":"음악가; 연주자","partOfSpeech":"n.","example":"She became a professional musician after years of practice.","exampleTranslation":"그녀는 수년간의 연습 끝에 전문 음악가가 됐어요.","category":"빈도 학습","level":19},{"id":11976,"term":"significance","meaning":"중요성; 의미","partOfSpeech":"n.","example":"He didn't understand the significance of that date to her.","exampleTranslation":"그는 그 날짜가 그녀에게 어떤 의미인지 이해하지 못했어요.","category":"빈도 학습","level":19},{"id":11977,"term":"shower","meaning":"샤워; 소나기","partOfSpeech":"n.","example":"I always feel better after a hot shower in the morning.","exampleTranslation":"아침에 뜨거운 샤워를 하고 나면 항상 기분이 좋아져요.","category":"빈도 학습","level":19},{"id":11978,"term":"illegal","meaning":"불법의; 위법의","partOfSpeech":"adj.","example":"It is illegal to park here during rush hour.","exampleTranslation":"출퇴근 시간에 여기에 주차하는 것은 불법이에요.","category":"빈도 학습","level":19},{"id":11979,"term":"charity","meaning":"자선 단체; 자선","partOfSpeech":"n.","example":"She donates part of her salary to charity every month.","exampleTranslation":"그녀는 매달 월급의 일부를 자선 단체에 기부해요.","category":"빈도 학습","level":19},{"id":11980,"term":"universal","meaning":"보편적인; 전 세계적인","partOfSpeech":"adj.","example":"A smile is almost universal across all cultures.","exampleTranslation":"미소는 거의 모든 문화에서 보편적이에요.","category":"빈도 학습","level":19},{"id":11981,"term":"cigarette","meaning":"담배","partOfSpeech":"n.","example":"He finally quit smoking his last cigarette two years ago.","exampleTranslation":"그는 2년 전에 마지막 담배를 끊었어요.","category":"빈도 학습","level":19},{"id":11982,"term":"constitute","meaning":"구성하다; ~에 해당하다","partOfSpeech":"v.","example":"Women constitute more than half of the workforce here.","exampleTranslation":"여기서는 여성이 전체 직원의 절반 이상을 구성해요.","category":"빈도 학습","level":19},{"id":11983,"term":"adequate","meaning":"충분한; 적절한","partOfSpeech":"adj.","example":"Make sure you get adequate sleep before a big exam.","exampleTranslation":"큰 시험 전에 충분한 수면을 취하도록 하세요.","category":"빈도 학습","level":19},{"id":11984,"term":"consultant","meaning":"컨설턴트; 자문가","partOfSpeech":"n.","example":"They hired a consultant to improve the company's marketing.","exampleTranslation":"그들은 회사 마케팅을 개선하기 위해 컨설턴트를 고용했어요.","category":"빈도 학습","level":19},{"id":11985,"term":"historian","meaning":"역사가; 역사학자","partOfSpeech":"n.","example":"The historian spent years researching that ancient battle.","exampleTranslation":"그 역사학자는 그 고대 전투를 연구하는 데 수년을 보냈어요.","category":"빈도 학습","level":19},{"id":11986,"term":"cousin","meaning":"사촌","partOfSpeech":"n.","example":"My cousin is visiting us from Canada next week.","exampleTranslation":"내 사촌이 다음 주에 캐나다에서 방문해요.","category":"빈도 학습","level":19},{"id":11987,"term":"visual","meaning":"시각적인; 시각 자료","partOfSpeech":"adj.","example":"The presentation had great visual aids that made it easy to follow.","exampleTranslation":"발표에 훌륭한 시각 자료가 있어서 이해하기 쉬웠어요.","category":"빈도 학습","level":19},{"id":11988,"term":"stupid","meaning":"멍청한; 어리석은","partOfSpeech":"adj.","example":"It was a stupid mistake to leave my wallet at home.","exampleTranslation":"지갑을 집에 두고 온 건 정말 어리석은 실수였어요.","category":"빈도 학습","level":19},{"id":11989,"term":"keen","meaning":"열성적인; 예리한","partOfSpeech":"adj.","example":"She is keen on learning new languages in her free time.","exampleTranslation":"그녀는 여가 시간에 새로운 언어를 배우는 것에 열성적이에요.","category":"빈도 학습","level":19},{"id":11990,"term":"ethnic","meaning":"민족의; 인종의","partOfSpeech":"adj.","example":"The city has a rich mix of ethnic restaurants to explore.","exampleTranslation":"그 도시에는 탐방할 수 있는 다양한 민족 음식점이 풍부해요.","category":"빈도 학습","level":19},{"id":11991,"term":"twin","meaning":"쌍둥이; 한 쌍의","partOfSpeech":"n.","example":"My twin sister and I look almost exactly alike.","exampleTranslation":"내 쌍둥이 언니와 나는 거의 똑같이 생겼어요.","category":"빈도 학습","level":19},{"id":11992,"term":"clinical","meaning":"임상의; 의료의","partOfSpeech":"adj.","example":"The new drug passed clinical trials with promising results.","exampleTranslation":"그 신약은 임상 시험을 유망한 결과로 통과했어요.","category":"빈도 학습","level":19},{"id":11993,"term":"eastern","meaning":"동쪽의; 동부의","partOfSpeech":"adj.","example":"They drove through the eastern part of the country on their road trip.","exampleTranslation":"그들은 로드트립에서 그 나라의 동부 지역을 가로질러 운전했어요.","category":"빈도 학습","level":19},{"id":11994,"term":"forecast","meaning":"예보; 예측하다","partOfSpeech":"n./v.","example":"The forecast says it will rain all weekend.","exampleTranslation":"예보에 따르면 주말 내내 비가 올 거래요.","category":"빈도 학습","level":19},{"id":11995,"term":"segment","meaning":"부분; 구분하다","partOfSpeech":"n.","example":"She peeled off a segment of the orange and handed it to me.","exampleTranslation":"그녀는 오렌지 한 조각을 떼어 나에게 건네줬어요.","category":"빈도 학습","level":19},{"id":11996,"term":"custom","meaning":"관습; 풍습","partOfSpeech":"n.","example":"It is a local custom to bring gifts when visiting someone's home.","exampleTranslation":"누군가의 집을 방문할 때 선물을 가져가는 것이 그 지역 관습이에요.","category":"빈도 학습","level":19},{"id":11997,"term":"adapt","meaning":"적응하다; 맞추다","partOfSpeech":"v.","example":"It took a few weeks to adapt to the new work schedule.","exampleTranslation":"새로운 업무 일정에 적응하는 데 몇 주가 걸렸어요.","category":"빈도 학습","level":19},{"id":11998,"term":"sand","meaning":"모래","partOfSpeech":"n.","example":"The kids spent the whole afternoon playing in the sand.","exampleTranslation":"아이들은 오후 내내 모래 속에서 놀았어요.","category":"빈도 학습","level":19},{"id":11999,"term":"cap","meaning":"모자; 한도","partOfSpeech":"n.","example":"He always wears a cap when he goes jogging outside.","exampleTranslation":"그는 밖에서 조깅할 때 항상 모자를 써요.","category":"빈도 학습","level":19},{"id":12000,"term":"prompt","meaning":"즉각적인; 신속한","partOfSpeech":"adj.","example":"Thanks for the prompt reply to my email.","exampleTranslation":"제 이메일에 신속하게 답장해 주셔서 감사해요.","category":"빈도 학습","level":19},{"id":12001,"term":"charm","meaning":"매력; 매력으로 사로잡다","partOfSpeech":"n./v.","example":"She has a lot of charm and everyone likes her.","exampleTranslation":"그녀는 매력이 넘쳐서 모두가 그녀를 좋아해요.","category":"빈도 학습","level":19},{"id":12002,"term":"react","meaning":"반응하다","partOfSpeech":"v.","example":"How did your parents react to the news?","exampleTranslation":"부모님은 그 소식에 어떻게 반응하셨어요?","category":"빈도 학습","level":19},{"id":12003,"term":"lecture","meaning":"강의, 강연","partOfSpeech":"n.","example":"The lecture this morning was really boring.","exampleTranslation":"오늘 아침 강의는 정말 지루했어요.","category":"빈도 학습","level":19},{"id":12004,"term":"venture","meaning":"모험적 사업; 과감히 해보다","partOfSpeech":"n./v.","example":"Starting your own business is always a risky venture.","exampleTranslation":"자기 사업을 시작하는 건 늘 위험한 모험이에요.","category":"빈도 학습","level":19},{"id":12005,"term":"compound","meaning":"화합물, 복합체","partOfSpeech":"n.","example":"Water is a compound of hydrogen and oxygen.","exampleTranslation":"물은 수소와 산소의 화합물이에요.","category":"빈도 학습","level":19},{"id":12006,"term":"rescue","meaning":"구조하다; 구조","partOfSpeech":"v./n.","example":"Firefighters came to rescue the trapped cat.","exampleTranslation":"소방관들이 갇힌 고양이를 구조하러 왔어요.","category":"빈도 학습","level":19},{"id":12007,"term":"mess","meaning":"엉망인 상태; 지저분함","partOfSpeech":"n.","example":"Sorry about the mess, I haven't cleaned up yet.","exampleTranslation":"지저분해서 미안해요, 아직 정리를 못 했어요.","category":"빈도 학습","level":19},{"id":12008,"term":"preference","meaning":"선호; 더 좋아함","partOfSpeech":"n.","example":"Do you have a preference for tea or coffee?","exampleTranslation":"차랑 커피 중에 더 좋아하는 게 있어요?","category":"빈도 학습","level":19},{"id":12009,"term":"comprehensive","meaning":"종합적인, 포괄적인","partOfSpeech":"adj.","example":"The book gives a comprehensive guide to cooking.","exampleTranslation":"그 책은 요리에 대한 종합적인 안내서예요.","category":"빈도 학습","level":19},{"id":12010,"term":"incentive","meaning":"동기 부여책; 장려책","partOfSpeech":"n.","example":"The bonus is a great incentive to work harder.","exampleTranslation":"그 보너스는 더 열심히 일하게 하는 좋은 동기예요.","category":"빈도 학습","level":19},{"id":12011,"term":"league","meaning":"(스포츠) 리그; 연맹","partOfSpeech":"n.","example":"Our team finished first in the league this year.","exampleTranslation":"우리 팀은 올해 리그에서 1위로 마쳤어요.","category":"빈도 학습","level":19},{"id":12012,"term":"dialog","meaning":"대화; (영화·연극) 대사","partOfSpeech":"n.","example":"The movie has funny dialog between the two friends.","exampleTranslation":"그 영화는 두 친구 사이의 재미있는 대사가 있어요.","category":"빈도 학습","level":19},{"id":12013,"term":"cream","meaning":"크림; 유지방","partOfSpeech":"n.","example":"I like a little cream in my coffee.","exampleTranslation":"저는 커피에 크림을 조금 넣는 걸 좋아해요.","category":"빈도 학습","level":19},{"id":12014,"term":"rapid","meaning":"빠른, 급속한","partOfSpeech":"adj.","example":"The city has seen rapid growth in recent years.","exampleTranslation":"그 도시는 최근 몇 년간 급속한 성장을 보였어요.","category":"빈도 학습","level":19},{"id":12015,"term":"cancel","meaning":"취소하다","partOfSpeech":"v.","example":"I had to cancel my trip because of work.","exampleTranslation":"일 때문에 여행을 취소해야 했어요.","category":"빈도 학습","level":19},{"id":12016,"term":"regret","meaning":"후회하다; 후회","partOfSpeech":"v./n.","example":"You won't regret buying this phone.","exampleTranslation":"이 휴대폰을 산 걸 후회하지 않을 거예요.","category":"빈도 학습","level":19},{"id":12017,"term":"dismiss","meaning":"묵살하다; 해고하다","partOfSpeech":"v.","example":"Please don't dismiss my idea so quickly.","exampleTranslation":"제 생각을 그렇게 빨리 묵살하지 말아 주세요.","category":"빈도 학습","level":19},{"id":12018,"term":"margin","meaning":"여백; (수익) 마진","partOfSpeech":"n.","example":"Write your notes in the margin of the page.","exampleTranslation":"페이지 여백에 메모를 적으세요.","category":"빈도 학습","level":19},{"id":12019,"term":"beneath","meaning":"~ 아래에","partOfSpeech":"prep.","example":"The keys were hidden beneath a pile of books.","exampleTranslation":"열쇠가 책 더미 아래에 숨겨져 있었어요.","category":"빈도 학습","level":19},{"id":12020,"term":"opponent","meaning":"상대, 적수","partOfSpeech":"n.","example":"Our opponent in the final was a strong team.","exampleTranslation":"결승에서 우리 상대는 강한 팀이었어요.","category":"빈도 학습","level":19},{"id":12021,"term":"resist","meaning":"저항하다; 참다","partOfSpeech":"v.","example":"I can't resist a good chocolate cake.","exampleTranslation":"저는 맛있는 초콜릿 케이크를 도저히 못 참아요.","category":"빈도 학습","level":19},{"id":12022,"term":"capability","meaning":"능력, 역량","partOfSpeech":"n.","example":"This phone has the capability to record video.","exampleTranslation":"이 휴대폰은 영상을 녹화하는 능력이 있어요.","category":"빈도 학습","level":19},{"id":12023,"term":"absolute","meaning":"완전한; 절대적인","partOfSpeech":"adj.","example":"I have absolute trust in my best friend.","exampleTranslation":"저는 제 가장 친한 친구를 완전히 신뢰해요.","category":"빈도 학습","level":19},{"id":12024,"term":"correspond","meaning":"일치하다; 서신을 주고받다","partOfSpeech":"v.","example":"Your answer doesn't correspond to the question.","exampleTranslation":"당신의 답은 질문과 일치하지 않아요.","category":"빈도 학습","level":19},{"id":12025,"term":"stroke","meaning":"쓰다듬다; 뇌졸중; 타격","partOfSpeech":"v./n.","example":"She likes to stroke the cat's soft fur.","exampleTranslation":"그녀는 고양이의 부드러운 털을 쓰다듬는 걸 좋아해요.","category":"빈도 학습","level":20},{"id":12026,"term":"dare","meaning":"감히 ~하다","partOfSpeech":"v.","example":"How dare you talk to me like that!","exampleTranslation":"어떻게 감히 나한테 그렇게 말할 수 있어!","category":"빈도 학습","level":20},{"id":12027,"term":"barrier","meaning":"장벽, 장애물","partOfSpeech":"n.","example":"Language can be a big barrier when traveling.","exampleTranslation":"여행할 때 언어는 큰 장벽이 될 수 있어요.","category":"빈도 학습","level":20},{"id":12028,"term":"rid","meaning":"없애다, 제거하다","partOfSpeech":"v.","example":"I want to get rid of these old clothes.","exampleTranslation":"저는 이 낡은 옷들을 없애고 싶어요.","category":"빈도 학습","level":20},{"id":12029,"term":"divorce","meaning":"이혼; 이혼하다","partOfSpeech":"n./v.","example":"Their divorce was hard on the whole family.","exampleTranslation":"그들의 이혼은 온 가족에게 힘든 일이었어요.","category":"빈도 학습","level":20},{"id":12030,"term":"ruin","meaning":"망치다; 폐허","partOfSpeech":"v./n.","example":"The rain will ruin our picnic plans.","exampleTranslation":"비가 우리 소풍 계획을 망칠 거예요.","category":"빈도 학습","level":20},{"id":12031,"term":"bury","meaning":"묻다, 매장하다","partOfSpeech":"v.","example":"The dog likes to bury bones in the yard.","exampleTranslation":"그 개는 마당에 뼈를 묻는 걸 좋아해요.","category":"빈도 학습","level":20},{"id":12032,"term":"counsel","meaning":"조언하다; 조언","partOfSpeech":"v./n.","example":"A good teacher will counsel students about their future.","exampleTranslation":"좋은 선생님은 학생들의 미래에 대해 조언해 줘요.","category":"빈도 학습","level":20},{"id":12033,"term":"tendency","meaning":"경향, 성향","partOfSpeech":"n.","example":"He has a tendency to arrive late for meetings.","exampleTranslation":"그는 회의에 늦게 도착하는 경향이 있어요.","category":"빈도 학습","level":20},{"id":12034,"term":"frequent","meaning":"잦은, 빈번한","partOfSpeech":"adj.","example":"She is a frequent visitor to this coffee shop.","exampleTranslation":"그녀는 이 커피숍에 자주 오는 단골이에요.","category":"빈도 학습","level":20},{"id":12035,"term":"motor","meaning":"모터, 전동기","partOfSpeech":"n.","example":"The motor in the fan stopped working.","exampleTranslation":"선풍기의 모터가 작동을 멈췄어요.","category":"빈도 학습","level":20},{"id":12036,"term":"survival","meaning":"생존","partOfSpeech":"n.","example":"Water is essential for our survival.","exampleTranslation":"물은 우리 생존에 꼭 필요해요.","category":"빈도 학습","level":20},{"id":12037,"term":"counter","meaning":"계산대; 조리대","partOfSpeech":"n.","example":"Please leave your bags on the counter.","exampleTranslation":"가방은 계산대 위에 놓아 주세요.","category":"빈도 학습","level":20},{"id":12038,"term":"possess","meaning":"소유하다, 지니다","partOfSpeech":"v.","example":"You possess all the skills needed for this job.","exampleTranslation":"당신은 이 일에 필요한 모든 능력을 지니고 있어요.","category":"빈도 학습","level":20},{"id":12039,"term":"permission","meaning":"허락, 허가","partOfSpeech":"n.","example":"You need permission to enter this room.","exampleTranslation":"이 방에 들어가려면 허가가 필요해요.","category":"빈도 학습","level":20},{"id":12040,"term":"valley","meaning":"골짜기; 계곡","partOfSpeech":"n.","example":"The village sits quietly in a green valley.","exampleTranslation":"그 마을은 초록빛 골짜기 안에 조용히 자리해 있다.","category":"빈도 학습","level":20},{"id":12041,"term":"float","meaning":"떠다니다; 뜨다","partOfSpeech":"v.","example":"Dead leaves float on the surface of the pond.","exampleTranslation":"낙엽들이 연못 표면 위에 떠다닌다.","category":"빈도 학습","level":20},{"id":12042,"term":"mad","meaning":"화난; 미친","partOfSpeech":"adj.","example":"She was mad at him for forgetting their anniversary.","exampleTranslation":"그녀는 기념일을 잊은 그에게 화가 났다.","category":"빈도 학습","level":20},{"id":12043,"term":"greatly","meaning":"크게; 대단히","partOfSpeech":"adv.","example":"Your support greatly helped me get through that tough time.","exampleTranslation":"당신의 도움이 그 힘든 시간을 버티는 데 크게 힘이 됐어요.","category":"빈도 학습","level":20},{"id":12044,"term":"visible","meaning":"눈에 보이는; 뚜렷한","partOfSpeech":"adj.","example":"The scar on his arm is still visible after all these years.","exampleTranslation":"그의 팔에 난 흉터는 그 세월이 지난 후에도 여전히 눈에 보인다.","category":"빈도 학습","level":20},{"id":12045,"term":"electric","meaning":"전기의; 전기로 작동하는","partOfSpeech":"adj.","example":"They switched to an electric car to save on fuel costs.","exampleTranslation":"그들은 연료비를 아끼기 위해 전기차로 바꿨다.","category":"빈도 학습","level":20},{"id":12046,"term":"impressive","meaning":"인상적인; 감동적인","partOfSpeech":"adj.","example":"Her performance at the recital was truly impressive.","exampleTranslation":"발표회에서 그녀의 연주는 정말 인상적이었다.","category":"빈도 학습","level":20},{"id":12047,"term":"evolution","meaning":"진화; 발전","partOfSpeech":"n.","example":"The evolution of smartphones has changed how we live.","exampleTranslation":"스마트폰의 발전은 우리가 사는 방식을 바꿔 놓았다.","category":"빈도 학습","level":20},{"id":12048,"term":"awareness","meaning":"인식; 의식","partOfSpeech":"n.","example":"Public awareness of recycling has grown a lot recently.","exampleTranslation":"재활용에 대한 사람들의 인식이 최근 많이 높아졌다.","category":"빈도 학습","level":20},{"id":12049,"term":"violent","meaning":"폭력적인; 격렬한","partOfSpeech":"adj.","example":"A violent storm knocked out the power for two days.","exampleTranslation":"격렬한 폭풍으로 이틀 동안 전기가 끊겼다.","category":"빈도 학습","level":20},{"id":12050,"term":"slave","meaning":"노예","partOfSpeech":"n.","example":"The museum exhibit showed how slave labor built the plantation.","exampleTranslation":"그 박물관 전시는 노예 노동이 어떻게 농장을 만들었는지 보여 줬다.","category":"빈도 학습","level":20},{"id":12051,"term":"wealthy","meaning":"부유한; 돈이 많은","partOfSpeech":"adj.","example":"Even wealthy people sometimes feel lonely.","exampleTranslation":"부유한 사람들도 때로는 외로움을 느낀다.","category":"빈도 학습","level":20},{"id":12052,"term":"architecture","meaning":"건축; 건축 양식","partOfSpeech":"n.","example":"The old cathedral's architecture draws thousands of visitors each year.","exampleTranslation":"그 오래된 성당의 건축 양식은 매년 수천 명의 방문객을 끌어들인다.","category":"빈도 학습","level":20},{"id":12053,"term":"acceptable","meaning":"받아들일 수 있는; 괜찮은","partOfSpeech":"adj.","example":"Is it acceptable to wear jeans to the meeting?","exampleTranslation":"회의에 청바지를 입고 가도 괜찮을까요?","category":"빈도 학습","level":20},{"id":12054,"term":"journal","meaning":"일기; 학술지","partOfSpeech":"n.","example":"She keeps a journal and writes in it every night before bed.","exampleTranslation":"그녀는 일기를 쓰는데, 매일 밤 자기 전에 적는다.","category":"빈도 학습","level":20},{"id":12055,"term":"coal","meaning":"석탄","partOfSpeech":"n.","example":"Many old power plants still burn coal for electricity.","exampleTranslation":"많은 오래된 발전소들이 아직도 석탄을 태워 전기를 만든다.","category":"빈도 학습","level":20},{"id":12056,"term":"measurement","meaning":"측정; 치수","partOfSpeech":"n.","example":"Take the measurement of the window before buying curtains.","exampleTranslation":"커튼을 사기 전에 창문 치수를 재 보세요.","category":"빈도 학습","level":20},{"id":12057,"term":"random","meaning":"무작위의; 임의의","partOfSpeech":"adj.","example":"They picked a random name from the list to win the prize.","exampleTranslation":"그들은 목록에서 무작위로 이름을 하나 골라 상을 줬다.","category":"빈도 학습","level":20},{"id":12058,"term":"successfully","meaning":"성공적으로","partOfSpeech":"adv.","example":"She successfully completed the marathon despite the heat.","exampleTranslation":"그녀는 더위에도 불구하고 마라톤을 성공적으로 완주했다.","category":"빈도 학습","level":20},{"id":12059,"term":"depress","meaning":"우울하게 하다; 침체시키다","partOfSpeech":"v.","example":"Gray weather for weeks on end can really depress your mood.","exampleTranslation":"몇 주씩 계속되는 흐린 날씨는 정말로 기분을 우울하게 만들 수 있다.","category":"빈도 학습","level":20},{"id":12060,"term":"illustration","meaning":"삽화; 설명","partOfSpeech":"n.","example":"The children's book had a beautiful illustration on every page.","exampleTranslation":"그 어린이 책에는 모든 페이지에 아름다운 삽화가 있었다.","category":"빈도 학습","level":20},{"id":12061,"term":"burst","meaning":"터지다; 갑자기 ~하다","partOfSpeech":"v.","example":"The kids burst out laughing when the clown fell over.","exampleTranslation":"광대가 넘어지자 아이들이 와르르 웃음을 터뜨렸다.","category":"빈도 학습","level":20},{"id":12062,"term":"privilege","meaning":"특권; 특혜","partOfSpeech":"n.","example":"Having clean water every day is a privilege many people lack.","exampleTranslation":"매일 깨끗한 물을 마실 수 있다는 건 많은 사람들이 누리지 못하는 특권이다.","category":"빈도 학습","level":20},{"id":12063,"term":"buyer","meaning":"구매자; 바이어","partOfSpeech":"n.","example":"The seller finally found a buyer for the old house.","exampleTranslation":"판매자는 마침내 오래된 집을 살 구매자를 찾았다.","category":"빈도 학습","level":20},{"id":12064,"term":"mutual","meaning":"서로의; 상호적인","partOfSpeech":"adj.","example":"They ended the relationship by mutual agreement.","exampleTranslation":"그들은 서로의 합의 하에 관계를 끝냈다.","category":"빈도 학습","level":20},{"id":12065,"term":"rail","meaning":"철도; 난간","partOfSpeech":"n.","example":"Hold on to the rail as you go down the stairs.","exampleTranslation":"계단을 내려갈 때 난간을 잡으세요.","category":"빈도 학습","level":20},{"id":12066,"term":"motivate","meaning":"동기를 부여하다; 의욕을 불러일으키다","partOfSpeech":"v.","example":"A good coach knows how to motivate players before a big game.","exampleTranslation":"좋은 코치는 큰 경기 전에 선수들에게 동기를 부여할 줄 안다.","category":"빈도 학습","level":20},{"id":12067,"term":"laboratory","meaning":"실험실; 연구소","partOfSpeech":"n.","example":"The vaccine was tested in a laboratory before being approved.","exampleTranslation":"그 백신은 승인되기 전에 실험실에서 검사를 받았다.","category":"빈도 학습","level":20},{"id":12068,"term":"mortgage","meaning":"주택 담보 대출; 모기지","partOfSpeech":"n.","example":"They took out a mortgage to buy their first home.","exampleTranslation":"그들은 첫 번째 집을 사기 위해 주택 담보 대출을 받았다.","category":"빈도 학습","level":20},{"id":12069,"term":"passion","meaning":"열정; 열망","partOfSpeech":"n.","example":"You can tell she has a real passion for cooking.","exampleTranslation":"그녀가 요리에 진정한 열정을 갖고 있다는 게 느껴진다.","category":"빈도 학습","level":20},{"id":12070,"term":"champion","meaning":"우승자; 챔피언","partOfSpeech":"n.","example":"She became the national champion after years of hard training.","exampleTranslation":"그녀는 수년간의 고된 훈련 끝에 전국 챔피언이 됐다.","category":"빈도 학습","level":20},{"id":12071,"term":"fulfill","meaning":"이행하다; 충족시키다","partOfSpeech":"v.","example":"He worked hard to fulfill his promise to his parents.","exampleTranslation":"그는 부모님께 한 약속을 이행하기 위해 열심히 일했다.","category":"빈도 학습","level":20},{"id":12072,"term":"dust","meaning":"먼지","partOfSpeech":"n.","example":"There's a thick layer of dust on the bookshelf.","exampleTranslation":"책장 위에 먼지가 두껍게 쌓여 있다.","category":"빈도 학습","level":20},{"id":12073,"term":"dedicate","meaning":"헌신하다; 바치다","partOfSpeech":"v.","example":"She decided to dedicate her career to helping underprivileged children.","exampleTranslation":"그녀는 자신의 경력을 소외된 아이들을 돕는 데 바치기로 결심했다.","category":"빈도 학습","level":20},{"id":12074,"term":"roughly","meaning":"대략; 거칠게","partOfSpeech":"adv.","example":"The journey takes roughly three hours by train.","exampleTranslation":"그 여정은 기차로 대략 세 시간이 걸린다.","category":"빈도 학습","level":20},{"id":12075,"term":"skirt","meaning":"치마; 스커트","partOfSpeech":"n.","example":"She wore a floral skirt to the summer party.","exampleTranslation":"그녀는 여름 파티에 꽃무늬 치마를 입고 갔다.","category":"빈도 학습","level":20},{"id":12076,"term":"province","meaning":"지방; 도(道)","partOfSpeech":"n.","example":"He grew up in a small town in a northern province.","exampleTranslation":"그는 북쪽 지방의 작은 마을에서 자랐다.","category":"빈도 학습","level":20},{"id":12077,"term":"march","meaning":"행진하다; 행진","partOfSpeech":"v.","example":"The protesters began to march through the city center.","exampleTranslation":"시위대가 도심을 가로질러 행진하기 시작했다.","category":"빈도 학습","level":20},{"id":12078,"term":"evaluation","meaning":"평가; 심사","partOfSpeech":"n.","example":"The annual evaluation helped her see where she could improve.","exampleTranslation":"연간 평가를 통해 그녀는 어디를 개선해야 할지 알 수 있었다.","category":"빈도 학습","level":20},{"id":12079,"term":"compromise","meaning":"타협; 타협하다","partOfSpeech":"n./v.","example":"They reached a compromise and split the cost equally.","exampleTranslation":"그들은 타협에 이르러 비용을 똑같이 나눴다.","category":"빈도 학습","level":20},{"id":12080,"term":"accomplish","meaning":"이루다; 달성하다","partOfSpeech":"v.","example":"She managed to accomplish all her goals this year.","exampleTranslation":"그녀는 올해 목표를 모두 달성해냈다.","category":"빈도 학습","level":20},{"id":12081,"term":"weakness","meaning":"약점; 취약함","partOfSpeech":"n.","example":"Admitting your weakness is the first step to improving.","exampleTranslation":"자신의 약점을 인정하는 것이 발전의 첫걸음이다.","category":"빈도 학습","level":20},{"id":12082,"term":"announcement","meaning":"발표; 공지","partOfSpeech":"n.","example":"The announcement surprised everyone at the meeting.","exampleTranslation":"그 발표는 회의에 있던 모든 사람을 놀라게 했다.","category":"빈도 학습","level":20},{"id":12083,"term":"salt","meaning":"소금","partOfSpeech":"n.","example":"Could you pass the salt, please?","exampleTranslation":"소금 좀 건네줄 수 있어요?","category":"빈도 학습","level":20},{"id":12084,"term":"glance","meaning":"흘끗 보다; 힐끗 봄","partOfSpeech":"n./v.","example":"She gave him a quick glance across the room.","exampleTranslation":"그녀는 방 너머로 그를 흘끗 쳐다봤다.","category":"빈도 학습","level":20},{"id":12085,"term":"opera","meaning":"오페라","partOfSpeech":"n.","example":"We're going to see an opera downtown tonight.","exampleTranslation":"오늘 밤 시내에 오페라 공연을 보러 간다.","category":"빈도 학습","level":20},{"id":12086,"term":"contest","meaning":"대회; 경쟁","partOfSpeech":"n.","example":"My daughter won the singing contest at school.","exampleTranslation":"내 딸이 학교 노래 대회에서 우승했다.","category":"빈도 학습","level":20},{"id":12087,"term":"brush","meaning":"솔; 붓; 닦다","partOfSpeech":"n./v.","example":"Don't forget to brush your teeth before bed.","exampleTranslation":"자기 전에 양치하는 것 잊지 마.","category":"빈도 학습","level":20},{"id":12088,"term":"embarrass","meaning":"당황하게 하다; 창피를 주다","partOfSpeech":"v.","example":"Please don't embarrass me in front of my friends.","exampleTranslation":"친구들 앞에서 나를 창피하게 하지 마.","category":"빈도 학습","level":20},{"id":12089,"term":"gallery","meaning":"갤러리; 미술관","partOfSpeech":"n.","example":"We spent the afternoon in the local gallery.","exampleTranslation":"우리는 오후를 동네 미술관에서 보냈다.","category":"빈도 학습","level":20},{"id":12090,"term":"genetic","meaning":"유전의; 유전자와 관련된","partOfSpeech":"adj.","example":"Some diseases have a genetic component.","exampleTranslation":"일부 질환은 유전적 요인을 가지고 있다.","category":"빈도 학습","level":20},{"id":12091,"term":"aggressive","meaning":"공격적인; 적극적인","partOfSpeech":"adj.","example":"The dog became aggressive when it felt threatened.","exampleTranslation":"개는 위협을 느끼자 공격적으로 변했다.","category":"빈도 학습","level":20},{"id":12092,"term":"chest","meaning":"가슴; 상자","partOfSpeech":"n.","example":"He felt a sharp pain in his chest after running.","exampleTranslation":"뛰고 나서 가슴에 날카로운 통증을 느꼈다.","category":"빈도 학습","level":20},{"id":12093,"term":"format","meaning":"형식; 서식","partOfSpeech":"n.","example":"Please save the file in PDF format.","exampleTranslation":"파일을 PDF 형식으로 저장해 주세요.","category":"빈도 학습","level":20},{"id":12094,"term":"literary","meaning":"문학의; 문학적인","partOfSpeech":"adj.","example":"She won a literary award for her debut novel.","exampleTranslation":"그녀는 첫 소설로 문학상을 받았다.","category":"빈도 학습","level":20},{"id":12095,"term":"govern","meaning":"통치하다; 지배하다","partOfSpeech":"v.","example":"It's not easy to govern a large and diverse country.","exampleTranslation":"크고 다양한 나라를 통치하는 것은 쉽지 않다.","category":"빈도 학습","level":20},{"id":12096,"term":"embrace","meaning":"껴안다; 받아들이다","partOfSpeech":"v.","example":"Try to embrace change instead of fearing it.","exampleTranslation":"변화를 두려워하지 말고 받아들이려고 해봐.","category":"빈도 학습","level":20},{"id":12097,"term":"praise","meaning":"칭찬하다; 칭찬","partOfSpeech":"n./v.","example":"The teacher gave lots of praise to the students.","exampleTranslation":"선생님은 학생들에게 칭찬을 많이 했다.","category":"빈도 학습","level":20},{"id":12098,"term":"silent","meaning":"조용한; 말없는","partOfSpeech":"adj.","example":"The house was completely silent after the kids went to bed.","exampleTranslation":"아이들이 잠자리에 든 후 집 안이 완전히 조용해졌다.","category":"빈도 학습","level":20},{"id":12099,"term":"pump","meaning":"펌프; 퍼올리다","partOfSpeech":"n./v.","example":"The pump stopped working and the basement flooded.","exampleTranslation":"펌프가 작동을 멈추면서 지하실이 침수됐다.","category":"빈도 학습","level":20},{"id":12100,"term":"publisher","meaning":"출판사; 출판인","partOfSpeech":"n.","example":"She finally found a publisher for her book.","exampleTranslation":"그녀는 마침내 자신의 책을 낼 출판사를 찾았다.","category":"빈도 학습","level":20},{"id":12101,"term":"celebration","meaning":"축하; 기념 행사","partOfSpeech":"n.","example":"We threw a big celebration for her retirement.","exampleTranslation":"우리는 그녀의 은퇴를 위해 큰 축하 행사를 열었다.","category":"빈도 학습","level":20},{"id":12102,"term":"golf","meaning":"골프","partOfSpeech":"n.","example":"He plays golf every weekend with his colleagues.","exampleTranslation":"그는 매 주말 동료들과 골프를 친다.","category":"빈도 학습","level":20},{"id":12103,"term":"compensation","meaning":"보상; 보수","partOfSpeech":"n.","example":"She received compensation for the damage to her car.","exampleTranslation":"그녀는 자동차 피해에 대한 보상을 받았다.","category":"빈도 학습","level":20},{"id":12104,"term":"classical","meaning":"고전의; 클래식의","partOfSpeech":"adj.","example":"He listens to classical music while he works.","exampleTranslation":"그는 일할 때 클래식 음악을 듣는다.","category":"빈도 학습","level":20},{"id":12105,"term":"weigh","meaning":"무게를 재다; 무게가 나가다","partOfSpeech":"v.","example":"Can you weigh this bag at the check-in counter?","exampleTranslation":"체크인 카운터에서 이 가방 무게를 재줄 수 있어요?","category":"빈도 학습","level":20},{"id":12106,"term":"versus","meaning":"대(對); ~에 맞서","partOfSpeech":"prep.","example":"Tonight's game is the home team versus the champions.","exampleTranslation":"오늘 밤 경기는 홈팀 대 챔피언팀의 대결이다.","category":"빈도 학습","level":20},{"id":12107,"term":"deficit","meaning":"적자; 부족분","partOfSpeech":"n.","example":"The company reported a large deficit this quarter.","exampleTranslation":"그 회사는 이번 분기에 큰 적자를 보고했다.","category":"빈도 학습","level":20},{"id":12108,"term":"modify","meaning":"수정하다; 변경하다","partOfSpeech":"v.","example":"You can modify your order before it ships.","exampleTranslation":"배송되기 전에 주문을 수정할 수 있습니다.","category":"빈도 학습","level":20},{"id":12109,"term":"flash","meaning":"번쩍임; 순간; 번쩍이다","partOfSpeech":"n./v.","example":"A flash of lightning lit up the dark sky.","exampleTranslation":"번개가 번쩍이며 어두운 하늘을 밝혔다.","category":"빈도 학습","level":20},{"id":12110,"term":"friendship","meaning":"우정; 친분","partOfSpeech":"n.","example":"Their friendship lasted more than thirty years.","exampleTranslation":"그들의 우정은 30년 넘게 이어졌다.","category":"빈도 학습","level":20},{"id":12111,"term":"profession","meaning":"직업; 전문직","partOfSpeech":"n.","example":"Teaching is a very rewarding profession.","exampleTranslation":"교직은 매우 보람 있는 직업이다.","category":"빈도 학습","level":20},{"id":12112,"term":"literally","meaning":"말 그대로; 정말로","partOfSpeech":"adv.","example":"I was literally shaking with excitement before the performance.","exampleTranslation":"공연 전에 나는 흥분으로 말 그대로 몸을 떨었다.","category":"빈도 학습","level":20},{"id":12113,"term":"equation","meaning":"방정식; 등식","partOfSpeech":"n.","example":"The teacher wrote a complex equation on the board.","exampleTranslation":"선생님이 칠판에 복잡한 방정식을 적었다.","category":"빈도 학습","level":20},{"id":12114,"term":"gesture","meaning":"몸짓; 제스처","partOfSpeech":"n.","example":"He made a gesture with his hands to show he didn't know.","exampleTranslation":"그는 모른다는 뜻으로 손으로 몸짓을 했다.","category":"빈도 학습","level":20},{"id":12115,"term":"entertain","meaning":"즐겁게 하다; 접대하다","partOfSpeech":"v.","example":"She always knows how to entertain guests at dinner.","exampleTranslation":"그녀는 저녁 식사 자리에서 손님을 즐겁게 하는 방법을 항상 알고 있다.","category":"빈도 학습","level":20},{"id":12116,"term":"fantastic","meaning":"굉장한; 환상적인","partOfSpeech":"adj.","example":"That was a fantastic meal — I loved every bite.","exampleTranslation":"정말 굉장한 식사였어 — 한 입 한 입 다 맛있었어.","category":"빈도 학습","level":20},{"id":12117,"term":"assign","meaning":"배정하다; 할당하다","partOfSpeech":"v.","example":"The manager will assign tasks to each team member.","exampleTranslation":"매니저가 각 팀원에게 업무를 배정할 것이다.","category":"빈도 학습","level":20},{"id":12118,"term":"inflation","meaning":"인플레이션; 물가 상승","partOfSpeech":"n.","example":"Inflation has made groceries much more expensive lately.","exampleTranslation":"요즘 물가 상승으로 식료품 가격이 훨씬 비싸졌다.","category":"빈도 학습","level":20},{"id":12119,"term":"historic","meaning":"역사적으로 중요한; 역사적인","partOfSpeech":"adj.","example":"Visiting the historic city center was unforgettable.","exampleTranslation":"역사적인 구시가지를 방문한 것은 잊을 수 없었다.","category":"빈도 학습","level":20},{"id":12120,"term":"injure","meaning":"다치게 하다; 부상을 입히다","partOfSpeech":"v.","example":"He fell off his bike and injure his knee badly.","exampleTranslation":"그는 자전거에서 떨어져 무릎을 심하게 다쳤다.","category":"빈도 학습","level":20},{"id":12121,"term":"therapy","meaning":"치료; 요법","partOfSpeech":"n.","example":"She goes to therapy every week to manage her anxiety.","exampleTranslation":"그녀는 불안을 다스리기 위해 매주 치료를 받으러 간다.","category":"빈도 학습","level":20},{"id":12122,"term":"orange","meaning":"오렌지; 주황색","partOfSpeech":"n.","example":"I peel an orange every morning with my breakfast.","exampleTranslation":"나는 매일 아침 식사와 함께 오렌지를 깎아 먹는다.","category":"빈도 학습","level":20},{"id":12123,"term":"twist","meaning":"비틀다; 뒤틀다","partOfSpeech":"v.","example":"Just twist the cap off and the bottle opens easily.","exampleTranslation":"뚜껑을 그냥 비틀면 병이 쉽게 열린다.","category":"빈도 학습","level":20},{"id":12124,"term":"personnel","meaning":"직원; 인사(부서)","partOfSpeech":"n.","example":"All personnel must wear a badge inside the building.","exampleTranslation":"모든 직원은 건물 안에서 배지를 착용해야 한다.","category":"빈도 학습","level":20},{"id":12125,"term":"imagination","meaning":"상상력; 상상","partOfSpeech":"n.","example":"Kids use their imagination to turn boxes into spaceships.","exampleTranslation":"아이들은 상상력을 발휘해 상자를 우주선으로 만든다.","category":"빈도 학습","level":20},{"id":12126,"term":"disagree","meaning":"동의하지 않다; 의견이 다르다","partOfSpeech":"v.","example":"I disagree with you on that point, but I respect your view.","exampleTranslation":"그 부분은 의견이 다르지만 당신의 생각을 존중해요.","category":"빈도 학습","level":20},{"id":12127,"term":"throat","meaning":"목구멍; 인후","partOfSpeech":"n.","example":"My throat hurts and I can barely swallow anything.","exampleTranslation":"목이 아파서 뭔가를 삼키기가 힘들다.","category":"빈도 학습","level":20},{"id":12128,"term":"insight","meaning":"통찰; 깊은 이해","partOfSpeech":"n.","example":"Her comment gave me real insight into the problem.","exampleTranslation":"그녀의 말이 그 문제에 대한 진정한 통찰을 주었다.","category":"빈도 학습","level":20},{"id":12129,"term":"tackle","meaning":"해결하다; 다루다","partOfSpeech":"v.","example":"We need to tackle this issue before it gets worse.","exampleTranslation":"더 나빠지기 전에 이 문제를 해결해야 한다.","category":"빈도 학습","level":20},{"id":12130,"term":"forever","meaning":"영원히; 언제까지나","partOfSpeech":"adv.","example":"I could stay on this beach forever, it's so peaceful.","exampleTranslation":"이 해변에 영원히 있어도 좋을 것 같아, 너무 평화롭다.","category":"빈도 학습","level":20},{"id":12131,"term":"exceed","meaning":"초과하다; 넘다","partOfSpeech":"v.","example":"Don't exceed the speed limit on the highway.","exampleTranslation":"고속도로에서 제한속도를 넘지 마세요.","category":"빈도 학습","level":21},{"id":12132,"term":"expenditure","meaning":"지출; 소비","partOfSpeech":"n.","example":"Monthly expenditure on food has gone up this year.","exampleTranslation":"올해 식비 월 지출이 늘었다.","category":"빈도 학습","level":21},{"id":12133,"term":"joy","meaning":"기쁨; 즐거움","partOfSpeech":"n.","example":"Seeing her smile fills me with joy every time.","exampleTranslation":"그녀의 미소를 볼 때마다 기쁨이 넘친다.","category":"빈도 학습","level":21},{"id":12134,"term":"pregnant","meaning":"임신한","partOfSpeech":"adj.","example":"She found out she was pregnant last month.","exampleTranslation":"그녀는 지난달에 임신한 것을 알게 됐다.","category":"빈도 학습","level":21},{"id":12135,"term":"reliable","meaning":"믿을 수 있는; 신뢰할 만한","partOfSpeech":"adj.","example":"He's the most reliable person on our team.","exampleTranslation":"그는 우리 팀에서 가장 믿을 수 있는 사람이다.","category":"빈도 학습","level":21},{"id":12136,"term":"gear","meaning":"장비; 기어","partOfSpeech":"n.","example":"Make sure you pack all the camping gear before we leave.","exampleTranslation":"떠나기 전에 캠핑 장비를 모두 챙겼는지 확인해.","category":"빈도 학습","level":21},{"id":12137,"term":"poet","meaning":"시인","partOfSpeech":"n.","example":"She became a well-known poet after her first collection came out.","exampleTranslation":"그녀는 첫 시집이 나온 후 유명한 시인이 됐다.","category":"빈도 학습","level":21},{"id":12138,"term":"fortune","meaning":"행운; 재산","partOfSpeech":"n.","example":"He made a fortune by investing early in real estate.","exampleTranslation":"그는 부동산에 일찍 투자해서 큰 재산을 모았다.","category":"빈도 학습","level":21},{"id":12139,"term":"ceremony","meaning":"의식; 식","partOfSpeech":"n.","example":"The graduation ceremony will be held outdoors this year.","exampleTranslation":"올해 졸업식은 야외에서 열릴 예정이다.","category":"빈도 학습","level":21},{"id":12140,"term":"pile","meaning":"더미; 쌓다","partOfSpeech":"n./v.","example":"There's a big pile of laundry waiting to be washed.","exampleTranslation":"세탁하기를 기다리는 빨랫감이 큰 더미로 쌓여 있다.","category":"빈도 학습","level":21},{"id":12141,"term":"pig","meaning":"돼지","partOfSpeech":"n.","example":"The kids loved feeding the pig at the farm.","exampleTranslation":"아이들은 농장에서 돼지에게 먹이를 주는 걸 무척 좋아했다.","category":"빈도 학습","level":21},{"id":12142,"term":"mixture","meaning":"혼합물; 섞음","partOfSpeech":"n.","example":"Stir the mixture until it turns smooth and creamy.","exampleTranslation":"혼합물이 부드럽고 크리미해질 때까지 저으세요.","category":"빈도 학습","level":21},{"id":12143,"term":"automatically","meaning":"자동으로; 저절로","partOfSpeech":"adv.","example":"The lights turn off automatically when you leave the room.","exampleTranslation":"방을 나가면 불이 자동으로 꺼진다.","category":"빈도 학습","level":21},{"id":12144,"term":"scholar","meaning":"학자; 장학생","partOfSpeech":"n.","example":"He is a respected scholar in the field of history.","exampleTranslation":"그는 역사 분야에서 존경받는 학자다.","category":"빈도 학습","level":21},{"id":12145,"term":"psychological","meaning":"심리적인; 정신적인","partOfSpeech":"adj.","example":"The accident had a serious psychological impact on him.","exampleTranslation":"그 사고는 그에게 심각한 심리적 영향을 미쳤다.","category":"빈도 학습","level":21},{"id":12146,"term":"dramatically","meaning":"극적으로; 크게","partOfSpeech":"adv.","example":"Sales dramatically increased after the new campaign launched.","exampleTranslation":"새 캠페인이 시작된 후 매출이 극적으로 증가했다.","category":"빈도 학습","level":21},{"id":12147,"term":"stake","meaning":"위험에 처한 것; 지분; 말뚝","partOfSpeech":"n.","example":"There's a lot at stake if we make the wrong decision here.","exampleTranslation":"여기서 잘못된 결정을 내리면 잃을 게 많다.","category":"빈도 학습","level":21},{"id":12148,"term":"creature","meaning":"생물; 동물","partOfSpeech":"n.","example":"The ocean is full of strange and beautiful creature.","exampleTranslation":"바다는 기묘하고 아름다운 생물들로 가득하다.","category":"빈도 학습","level":21},{"id":12149,"term":"partnership","meaning":"동반자 관계; 협력","partOfSpeech":"n.","example":"Their partnership has made the business much stronger.","exampleTranslation":"그들의 협력 덕분에 사업이 훨씬 탄탄해졌다.","category":"빈도 학습","level":21},{"id":12150,"term":"participation","meaning":"참여; 참가","partOfSpeech":"n.","example":"Your participation in the meeting is really important.","exampleTranslation":"회의에 참여해 주시는 것이 정말 중요합니다.","category":"빈도 학습","level":21},{"id":12151,"term":"clause","meaning":"조항; 절","partOfSpeech":"n.","example":"Read every clause in the contract before you sign it.","exampleTranslation":"서명하기 전에 계약서의 모든 조항을 읽으세요.","category":"빈도 학습","level":21},{"id":12152,"term":"penalty","meaning":"벌칙; 처벌","partOfSpeech":"n.","example":"There's a penalty for late payment on your bill.","exampleTranslation":"청구서를 늦게 납부하면 연체 벌칙이 부과된다.","category":"빈도 학습","level":21},{"id":12153,"term":"chamber","meaning":"방; 회의실; 의회","partOfSpeech":"n.","example":"The senators gathered in the chamber to vote on the bill.","exampleTranslation":"상원의원들이 법안 표결을 위해 의사당에 모였다.","category":"빈도 학습","level":21},{"id":12154,"term":"fancy","meaning":"고급스러운; 마음에 들다","partOfSpeech":"adj.","example":"They took us to a really fancy restaurant for the anniversary.","exampleTranslation":"그들은 기념일에 우리를 정말 고급스러운 식당에 데려갔다.","category":"빈도 학습","level":21},{"id":12155,"term":"poetry","meaning":"시; 시 문학","partOfSpeech":"n.","example":"She started reading poetry to help her relax at night.","exampleTranslation":"그녀는 밤에 긴장을 풀기 위해 시를 읽기 시작했다.","category":"빈도 학습","level":21},{"id":12156,"term":"chat","meaning":"잡담하다; 대화","partOfSpeech":"v.","example":"We sat down to chat over coffee for an hour.","exampleTranslation":"우리는 한 시간 동안 커피를 마시며 수다를 떨었다.","category":"빈도 학습","level":21},{"id":12157,"term":"clothing","meaning":"의류; 옷","partOfSpeech":"n.","example":"Pack warm clothing because the nights get very cold there.","exampleTranslation":"그곳은 밤이 많이 춥기 때문에 따뜻한 옷을 챙기세요.","category":"빈도 학습","level":21},{"id":12158,"term":"evolve","meaning":"진화하다; 발전하다","partOfSpeech":"v.","example":"Businesses need to evolve quickly to stay competitive.","exampleTranslation":"기업들은 경쟁력을 유지하기 위해 빠르게 발전해야 한다.","category":"빈도 학습","level":21},{"id":12159,"term":"sake","meaning":"위함; 이익","partOfSpeech":"n.","example":"She moved to a quieter neighborhood for the sake of her kids.","exampleTranslation":"그녀는 아이들을 위해 더 조용한 동네로 이사했다.","category":"빈도 학습","level":21},{"id":12160,"term":"shelf","meaning":"선반; 책장","partOfSpeech":"n.","example":"Put the books back on the shelf when you're done.","exampleTranslation":"다 읽으면 책을 다시 선반에 꽂아 두세요.","category":"빈도 학습","level":21},{"id":12161,"term":"boost","meaning":"높이다, 끌어올리다; 증가","partOfSpeech":"v.","example":"A good night's sleep can boost your mood a lot.","exampleTranslation":"푹 자고 나면 기분이 훨씬 나아질 수 있어요.","category":"빈도 학습","level":21},{"id":12162,"term":"tail","meaning":"꼬리; 뒷부분","partOfSpeech":"n.","example":"The dog wagged its tail when it saw its owner.","exampleTranslation":"강아지가 주인을 보자 꼬리를 흔들었어요.","category":"빈도 학습","level":21},{"id":12163,"term":"possession","meaning":"소유; 소유물","partOfSpeech":"n.","example":"Her phone is her most valuable possession.","exampleTranslation":"그녀에게 휴대폰은 가장 소중한 소유물이에요.","category":"빈도 학습","level":21},{"id":12164,"term":"abortion","meaning":"낙태; 임신 중단","partOfSpeech":"n.","example":"The debate over abortion has been going on for decades.","exampleTranslation":"낙태에 관한 논쟁은 수십 년째 이어지고 있어요.","category":"빈도 학습","level":21},{"id":12165,"term":"curious","meaning":"궁금한, 호기심 있는","partOfSpeech":"adj.","example":"I'm curious about how they make this dish.","exampleTranslation":"이 음식을 어떻게 만드는지 궁금해요.","category":"빈도 학습","level":21},{"id":12166,"term":"wooden","meaning":"나무로 만든, 목조의","partOfSpeech":"adj.","example":"They sat at a wooden table in the old café.","exampleTranslation":"그들은 오래된 카페의 나무 테이블에 앉았어요.","category":"빈도 학습","level":21},{"id":12167,"term":"boom","meaning":"급성장, 호황; 쾅 하는 소리","partOfSpeech":"n.","example":"There's been a boom in online shopping lately.","exampleTranslation":"최근 온라인 쇼핑이 크게 늘었어요.","category":"빈도 학습","level":21},{"id":12168,"term":"tale","meaning":"이야기, 옛날이야기","partOfSpeech":"n.","example":"My grandma used to tell us a tale every night.","exampleTranslation":"할머니는 매일 밤 우리에게 이야기를 들려주곤 했어요.","category":"빈도 학습","level":21},{"id":12169,"term":"democratic","meaning":"민주적인; 민주주의의","partOfSpeech":"adj.","example":"The company tries to make decisions in a democratic way.","exampleTranslation":"그 회사는 민주적인 방식으로 결정을 내리려 해요.","category":"빈도 학습","level":21},{"id":12170,"term":"maintenance","meaning":"유지, 관리; 정비","partOfSpeech":"n.","example":"The building requires regular maintenance to stay in good shape.","exampleTranslation":"건물을 좋은 상태로 유지하려면 정기적인 관리가 필요해요.","category":"빈도 학습","level":21},{"id":12171,"term":"consequently","meaning":"그 결과로, 따라서","partOfSpeech":"adv.","example":"He missed the last train and consequently had to take a taxi.","exampleTranslation":"그는 막차를 놓쳐서 결국 택시를 타야 했어요.","category":"빈도 학습","level":21},{"id":12172,"term":"pot","meaning":"냄비; 화분","partOfSpeech":"n.","example":"She put the pasta in a large pot of boiling water.","exampleTranslation":"그녀는 끓는 물이 담긴 큰 냄비에 파스타를 넣었어요.","category":"빈도 학습","level":21},{"id":12173,"term":"cow","meaning":"암소, 젖소","partOfSpeech":"n.","example":"The farmer milked the cow every morning.","exampleTranslation":"농부는 매일 아침 암소의 젖을 짰어요.","category":"빈도 학습","level":21},{"id":12174,"term":"strengthen","meaning":"강화하다, 튼튼하게 하다","partOfSpeech":"v.","example":"Exercise can strengthen your muscles over time.","exampleTranslation":"꾸준히 운동하면 근육을 강화할 수 있어요.","category":"빈도 학습","level":21},{"id":12175,"term":"whilst","meaning":"~하는 동안에, ~하면서","partOfSpeech":"conj.","example":"She listened to music whilst cooking dinner.","exampleTranslation":"그녀는 저녁을 요리하면서 음악을 들었어요.","category":"빈도 학습","level":21},{"id":12176,"term":"constraint","meaning":"제약, 제한","partOfSpeech":"n.","example":"Budget constraint forced us to cancel the trip.","exampleTranslation":"예산 제약 때문에 여행을 취소해야 했어요.","category":"빈도 학습","level":21},{"id":12177,"term":"fold","meaning":"접다; 개다","partOfSpeech":"v.","example":"Please fold the letter before putting it in the envelope.","exampleTranslation":"편지를 봉투에 넣기 전에 접어 주세요.","category":"빈도 학습","level":21},{"id":12178,"term":"bin","meaning":"쓰레기통; 수납함","partOfSpeech":"n.","example":"Throw the empty bottle in the recycling bin.","exampleTranslation":"빈 병은 재활용 쓰레기통에 버려 주세요.","category":"빈도 학습","level":21},{"id":12179,"term":"undergo","meaning":"겪다, 받다 (치료·과정 등을)","partOfSpeech":"v.","example":"She had to undergo surgery to fix her knee.","exampleTranslation":"그녀는 무릎을 고치기 위해 수술을 받아야 했어요.","category":"빈도 학습","level":21},{"id":12180,"term":"potentially","meaning":"잠재적으로, 어쩌면","partOfSpeech":"adv.","example":"This new drug could potentially save thousands of lives.","exampleTranslation":"이 신약은 잠재적으로 수천 명의 생명을 구할 수도 있어요.","category":"빈도 학습","level":21},{"id":12181,"term":"scope","meaning":"범위; 여지","partOfSpeech":"n.","example":"The scope of the project was larger than we expected.","exampleTranslation":"프로젝트의 범위가 예상보다 훨씬 넓었어요.","category":"빈도 학습","level":21},{"id":12182,"term":"pretend","meaning":"~인 척하다, 꾸미다","partOfSpeech":"v.","example":"The kids pretend to be superheroes in the backyard.","exampleTranslation":"아이들은 뒷마당에서 슈퍼히어로인 척 놀아요.","category":"빈도 학습","level":21},{"id":12183,"term":"diversity","meaning":"다양성","partOfSpeech":"n.","example":"Our team values diversity and different perspectives.","exampleTranslation":"우리 팀은 다양성과 다른 관점을 중요하게 여겨요.","category":"빈도 학습","level":21},{"id":12184,"term":"allege","meaning":"주장하다, 혐의를 제기하다","partOfSpeech":"v.","example":"Witnesses allege that the officer used excessive force.","exampleTranslation":"목격자들은 그 경찰관이 과도한 폭력을 썼다고 주장해요.","category":"빈도 학습","level":21},{"id":12185,"term":"pride","meaning":"자부심, 자랑스러움","partOfSpeech":"n.","example":"She felt a deep sense of pride when her son graduated.","exampleTranslation":"아들이 졸업했을 때 그녀는 깊은 자부심을 느꼈어요.","category":"빈도 학습","level":21},{"id":12186,"term":"intense","meaning":"강렬한, 극심한","partOfSpeech":"adj.","example":"The heat was so intense that we stayed inside all day.","exampleTranslation":"더위가 너무 강렬해서 하루 종일 집 안에 있었어요.","category":"빈도 학습","level":21},{"id":12187,"term":"resign","meaning":"사임하다, 사직하다","partOfSpeech":"v.","example":"The manager decided to resign after ten years at the company.","exampleTranslation":"그 매니저는 10년 만에 회사를 그만두기로 결정했어요.","category":"빈도 학습","level":21},{"id":12188,"term":"craft","meaning":"공예; 솜씨; 만들다","partOfSpeech":"n./v.","example":"She sells handmade jewelry at the local craft market.","exampleTranslation":"그녀는 지역 공예 시장에서 직접 만든 보석류를 팔아요.","category":"빈도 학습","level":21},{"id":12189,"term":"strict","meaning":"엄격한, 까다로운","partOfSpeech":"adj.","example":"The school has strict rules about phone use in class.","exampleTranslation":"그 학교는 수업 중 휴대폰 사용에 관해 엄격한 규칙이 있어요.","category":"빈도 학습","level":21},{"id":12190,"term":"concrete","meaning":"구체적인; 콘크리트","partOfSpeech":"adj.","example":"Can you give me a concrete example of what you mean?","exampleTranslation":"무슨 뜻인지 구체적인 예를 들어 줄 수 있어요?","category":"빈도 학습","level":21},{"id":12191,"term":"shell","meaning":"껍데기, 껍질; 조개껍데기","partOfSpeech":"n.","example":"She collected a beautiful shell on the beach.","exampleTranslation":"그녀는 해변에서 예쁜 조개껍데기를 주웠어요.","category":"빈도 학습","level":21},{"id":12192,"term":"damn","meaning":"제기랄; 빌어먹을","partOfSpeech":"adv.","example":"That was a damn good meal, honestly.","exampleTranslation":"솔직히 정말 끝내주는 식사였어요.","category":"빈도 학습","level":21},{"id":12193,"term":"distinct","meaning":"뚜렷한, 분명한; 구별되는","partOfSpeech":"adj.","example":"The two regions have distinct cultures and dialects.","exampleTranslation":"그 두 지역은 문화와 방언이 뚜렷하게 달라요.","category":"빈도 학습","level":21},{"id":12194,"term":"humor","meaning":"유머, 유머 감각","partOfSpeech":"n.","example":"His humor always makes everyone laugh at meetings.","exampleTranslation":"그의 유머는 회의에서 항상 모두를 웃게 해요.","category":"빈도 학습","level":21},{"id":12195,"term":"limitation","meaning":"한계, 제한","partOfSpeech":"n.","example":"Every technology has its own limitation.","exampleTranslation":"모든 기술에는 저마다의 한계가 있어요.","category":"빈도 학습","level":21},{"id":12196,"term":"indication","meaning":"징후, 암시; 지시","partOfSpeech":"n.","example":"There's no indication that the weather will improve soon.","exampleTranslation":"날씨가 곧 나아질 것이라는 징후가 전혀 없어요.","category":"빈도 학습","level":21},{"id":12197,"term":"stability","meaning":"안정, 안정성","partOfSpeech":"n.","example":"Financial stability is important for peace of mind.","exampleTranslation":"마음의 평화를 위해 재정적 안정이 중요해요.","category":"빈도 학습","level":21},{"id":12198,"term":"wise","meaning":"지혜로운, 현명한","partOfSpeech":"adj.","example":"It was wise of her to save money before quitting her job.","exampleTranslation":"직장을 그만두기 전에 돈을 모아 둔 건 현명한 선택이었어요.","category":"빈도 학습","level":21},{"id":12199,"term":"neglect","meaning":"방치하다, 소홀히 하다","partOfSpeech":"v.","example":"Don't neglect your health just because you're busy.","exampleTranslation":"바쁘다는 이유로 건강을 소홀히 하지 마세요.","category":"빈도 학습","level":21},{"id":12200,"term":"compose","meaning":"작곡하다; 구성하다","partOfSpeech":"v.","example":"She sat down to compose a song for her friend.","exampleTranslation":"그녀는 친구를 위해 노래를 작곡하려고 자리에 앉았다.","category":"빈도 학습","level":21},{"id":12201,"term":"jail","meaning":"교도소; 수감하다","partOfSpeech":"n./v.","example":"He spent two years in jail for the theft.","exampleTranslation":"그는 절도죄로 2년간 교도소에 있었다.","category":"빈도 학습","level":21},{"id":12202,"term":"shelter","meaning":"피난처; 보호시설","partOfSpeech":"n.","example":"They took shelter under a tree when it started raining.","exampleTranslation":"비가 내리기 시작하자 그들은 나무 아래로 피했다.","category":"빈도 학습","level":21},{"id":12203,"term":"mere","meaning":"단순한; 고작","partOfSpeech":"adj.","example":"It took a mere five minutes to fix the problem.","exampleTranslation":"그 문제를 해결하는 데 고작 5분밖에 걸리지 않았다.","category":"빈도 학습","level":21},{"id":12204,"term":"carbon","meaning":"탄소","partOfSpeech":"n.","example":"The company is working to reduce its carbon footprint.","exampleTranslation":"그 회사는 탄소 발자국을 줄이기 위해 노력하고 있다.","category":"빈도 학습","level":21},{"id":12205,"term":"regulate","meaning":"규제하다; 조절하다","partOfSpeech":"v.","example":"The government needs to regulate food safety standards.","exampleTranslation":"정부는 식품 안전 기준을 규제할 필요가 있다.","category":"빈도 학습","level":21},{"id":12206,"term":"cheese","meaning":"치즈","partOfSpeech":"n.","example":"Can you add extra cheese on my pizza, please?","exampleTranslation":"피자에 치즈를 더 넣어 주시겠어요?","category":"빈도 학습","level":21},{"id":12207,"term":"trigger","meaning":"촉발하다; 방아쇠","partOfSpeech":"v./n.","example":"Loud noises can trigger anxiety in some people.","exampleTranslation":"큰 소음은 일부 사람들에게 불안을 촉발할 수 있다.","category":"빈도 학습","level":21},{"id":12208,"term":"pipe","meaning":"파이프; 관","partOfSpeech":"n.","example":"The pipe under the sink was leaking all night.","exampleTranslation":"싱크대 아래 파이프가 밤새 새고 있었다.","category":"빈도 학습","level":21},{"id":12209,"term":"destruction","meaning":"파괴; 멸망","partOfSpeech":"n.","example":"The hurricane caused massive destruction along the coast.","exampleTranslation":"허리케인은 해안을 따라 엄청난 파괴를 일으켰다.","category":"빈도 학습","level":21},{"id":12210,"term":"guitar","meaning":"기타","partOfSpeech":"n.","example":"He plays guitar at a local café every Friday night.","exampleTranslation":"그는 매주 금요일 밤 동네 카페에서 기타를 연주한다.","category":"빈도 학습","level":21},{"id":12211,"term":"flag","meaning":"깃발; 표시하다","partOfSpeech":"n./v.","example":"She waved a flag to get the taxi's attention.","exampleTranslation":"그녀는 택시의 주의를 끌기 위해 깃발을 흔들었다.","category":"빈도 학습","level":21},{"id":12212,"term":"piano","meaning":"피아노","partOfSpeech":"n.","example":"My daughter has been taking piano lessons since age six.","exampleTranslation":"내 딸은 여섯 살부터 피아노 레슨을 받아 왔다.","category":"빈도 학습","level":21},{"id":12213,"term":"magic","meaning":"마법; 마술","partOfSpeech":"n.","example":"The kids were amazed by the magic show at the party.","exampleTranslation":"아이들은 파티에서의 마술 쇼에 깜짝 놀랐다.","category":"빈도 학습","level":21},{"id":12214,"term":"mystery","meaning":"미스터리; 수수께끼","partOfSpeech":"n.","example":"How the ancient builders moved those stones remains a mystery.","exampleTranslation":"고대 건설자들이 그 돌들을 어떻게 옮겼는지는 여전히 수수께끼로 남아 있다.","category":"빈도 학습","level":21},{"id":12215,"term":"ski","meaning":"스키를 타다; 스키","partOfSpeech":"v./n.","example":"We plan to ski in the Alps next winter.","exampleTranslation":"우리는 내년 겨울에 알프스에서 스키를 탈 계획이다.","category":"빈도 학습","level":21},{"id":12216,"term":"whisper","meaning":"속삭이다; 귓속말","partOfSpeech":"v./n.","example":"He leaned over to whisper something in her ear.","exampleTranslation":"그는 몸을 기울여 그녀의 귀에 무언가를 속삭였다.","category":"빈도 학습","level":21},{"id":12217,"term":"rear","meaning":"뒤쪽; 뒤의","partOfSpeech":"n./adj.","example":"Please use the rear entrance after 9 p.m.","exampleTranslation":"오후 9시 이후에는 뒷문을 이용해 주세요.","category":"빈도 학습","level":21},{"id":12218,"term":"species","meaning":"종(種); 생물 종류","partOfSpeech":"n.","example":"Several species of birds nest in this forest.","exampleTranslation":"이 숲에는 여러 종의 새들이 둥지를 튼다.","category":"빈도 학습","level":21},{"id":12219,"term":"moon","meaning":"달","partOfSpeech":"n.","example":"The moon was so bright we didn't need a flashlight.","exampleTranslation":"달이 너무 밝아서 손전등이 필요 없었다.","category":"빈도 학습","level":21},{"id":12220,"term":"presumably","meaning":"아마도; 추정컨대","partOfSpeech":"adv.","example":"She's not here, so presumably she left early.","exampleTranslation":"그녀가 여기 없으니 아마도 일찍 떠난 것 같다.","category":"빈도 학습","level":21},{"id":12221,"term":"bless","meaning":"축복하다; 은혜를 베풀다","partOfSpeech":"v.","example":"She counts herself lucky to bless others with kindness.","exampleTranslation":"그녀는 친절로 다른 사람들을 축복할 수 있어 자신이 운이 좋다고 생각한다.","category":"빈도 학습","level":21},{"id":12222,"term":"airline","meaning":"항공사","partOfSpeech":"n.","example":"Which airline did you book your ticket with?","exampleTranslation":"어느 항공사로 티켓을 예약했어요?","category":"빈도 학습","level":21},{"id":12223,"term":"amendment","meaning":"수정(안); 개정","partOfSpeech":"n.","example":"The committee voted to pass the amendment to the contract.","exampleTranslation":"위원회는 계약 수정안을 통과시키기로 투표했다.","category":"빈도 학습","level":21},{"id":12224,"term":"grandmother","meaning":"할머니","partOfSpeech":"n.","example":"My grandmother taught me how to make her famous soup.","exampleTranslation":"할머니는 나에게 그녀의 유명한 수프 만드는 법을 가르쳐 주었다.","category":"빈도 학습","level":21},{"id":12225,"term":"jury","meaning":"배심원단","partOfSpeech":"n.","example":"The jury took three days to reach a verdict.","exampleTranslation":"배심원단은 평결을 내리는 데 3일이 걸렸다.","category":"빈도 학습","level":21},{"id":12226,"term":"cooperation","meaning":"협력; 협조","partOfSpeech":"n.","example":"The project succeeded thanks to cooperation between all teams.","exampleTranslation":"그 프로젝트는 모든 팀의 협력 덕분에 성공했다.","category":"빈도 학습","level":21},{"id":12227,"term":"civilian","meaning":"민간인; 민간의","partOfSpeech":"n./adj.","example":"The aid workers made sure no civilian was harmed.","exampleTranslation":"구호 활동가들은 민간인이 다치지 않도록 확인했다.","category":"빈도 학습","level":21},{"id":12228,"term":"composition","meaning":"구성; 작품","partOfSpeech":"n.","example":"The teacher praised the composition she wrote for class.","exampleTranslation":"선생님은 그녀가 수업을 위해 쓴 작품을 칭찬했다.","category":"빈도 학습","level":21},{"id":12229,"term":"coin","meaning":"동전; 주화","partOfSpeech":"n.","example":"He found an old coin buried in the backyard.","exampleTranslation":"그는 뒷마당에 묻혀 있던 오래된 동전을 발견했다.","category":"빈도 학습","level":21},{"id":12230,"term":"regardless","meaning":"그럼에도 불구하고; ~에 관계없이","partOfSpeech":"adv.","example":"She showed up regardless of the bad weather.","exampleTranslation":"그녀는 나쁜 날씨에도 불구하고 나타났다.","category":"빈도 학습","level":21},{"id":12231,"term":"scan","meaning":"훑어보다; 스캔하다","partOfSpeech":"v.","example":"I usually scan the headlines before reading the full article.","exampleTranslation":"나는 보통 전체 기사를 읽기 전에 헤드라인을 훑어본다.","category":"빈도 학습","level":21},{"id":12232,"term":"bunch","meaning":"묶음; 다발","partOfSpeech":"n.","example":"He brought a bunch of flowers for his mother.","exampleTranslation":"그는 어머니를 위해 꽃 한 다발을 가져왔다.","category":"빈도 학습","level":21},{"id":12233,"term":"racial","meaning":"인종의; 인종적인","partOfSpeech":"adj.","example":"The school promotes racial equality among all students.","exampleTranslation":"그 학교는 모든 학생들 사이에서 인종 평등을 장려한다.","category":"빈도 학습","level":21},{"id":12234,"term":"greet","meaning":"인사하다; 맞이하다","partOfSpeech":"v.","example":"He went outside to greet the guests at the door.","exampleTranslation":"그는 문 앞에서 손님들을 맞이하기 위해 밖으로 나갔다.","category":"빈도 학습","level":21},{"id":12235,"term":"hopefully","meaning":"바라건대; 희망적으로","partOfSpeech":"adv.","example":"Hopefully the weather will be nice for the picnic.","exampleTranslation":"바라건대 소풍 날 날씨가 좋으면 좋겠다.","category":"빈도 학습","level":21},{"id":12236,"term":"sanction","meaning":"제재; 승인하다","partOfSpeech":"n./v.","example":"The council agreed to sanction the new building plan.","exampleTranslation":"위원회는 새 건축 계획을 승인하기로 합의했다.","category":"빈도 학습","level":21},{"id":12237,"term":"trick","meaning":"속임수; 요령","partOfSpeech":"n.","example":"He showed us a simple trick to open the jar easily.","exampleTranslation":"그는 우리에게 병뚜껑을 쉽게 여는 간단한 요령을 알려 주었다.","category":"빈도 학습","level":21},{"id":12238,"term":"paragraph","meaning":"문단; 단락","partOfSpeech":"n.","example":"Please read the first paragraph of the article carefully.","exampleTranslation":"기사의 첫 번째 문단을 주의 깊게 읽어 주세요.","category":"빈도 학습","level":22},{"id":12239,"term":"maker","meaning":"제작자; 만드는 사람","partOfSpeech":"n.","example":"She is a talented maker of handmade jewelry.","exampleTranslation":"그녀는 수제 보석을 만드는 재능 있는 제작자이다.","category":"빈도 학습","level":22},{"id":12240,"term":"chocolate","meaning":"초콜릿","partOfSpeech":"n.","example":"She bought a box of chocolate for her friend's birthday.","exampleTranslation":"그녀는 친구 생일 선물로 초콜릿 한 상자를 샀다.","category":"빈도 학습","level":22},{"id":12241,"term":"stimulate","meaning":"자극하다; 촉진하다","partOfSpeech":"v.","example":"Coffee can stimulate your mind when you feel tired.","exampleTranslation":"커피는 피곤할 때 정신을 맑게 해줄 수 있다.","category":"빈도 학습","level":22},{"id":12242,"term":"belt","meaning":"벨트; 허리띠","partOfSpeech":"n.","example":"He forgot to wear his belt this morning.","exampleTranslation":"그는 오늘 아침에 벨트 차는 것을 잊었다.","category":"빈도 학습","level":22},{"id":12243,"term":"potato","meaning":"감자","partOfSpeech":"n.","example":"Can you peel the potato while I boil some water?","exampleTranslation":"내가 물 끓이는 동안 감자 좀 껍질 벗겨줄 수 있어?","category":"빈도 학습","level":22},{"id":12244,"term":"narrative","meaning":"이야기; 서술","partOfSpeech":"n.","example":"The movie's narrative was easy to follow from beginning to end.","exampleTranslation":"그 영화의 이야기는 처음부터 끝까지 따라가기 쉬웠다.","category":"빈도 학습","level":22},{"id":12245,"term":"tissue","meaning":"휴지; 조직","partOfSpeech":"n.","example":"Do you have a tissue? I think I'm getting a cold.","exampleTranslation":"휴지 있어? 감기에 걸리는 것 같아.","category":"빈도 학습","level":22},{"id":12246,"term":"barely","meaning":"간신히; 거의 ~않다","partOfSpeech":"adv.","example":"I barely made it to the train before the doors closed.","exampleTranslation":"문이 닫히기 직전에 간신히 기차에 탔다.","category":"빈도 학습","level":22},{"id":12247,"term":"invent","meaning":"발명하다; 만들어내다","partOfSpeech":"v.","example":"Kids love to invent silly games when they're bored.","exampleTranslation":"아이들은 심심할 때 엉뚱한 놀이를 만들어내기를 좋아한다.","category":"빈도 학습","level":22},{"id":12248,"term":"tourism","meaning":"관광; 관광업","partOfSpeech":"n.","example":"Tourism has brought a lot of money to the small coastal town.","exampleTranslation":"관광업이 그 작은 해안 마을에 많은 돈을 가져다주었다.","category":"빈도 학습","level":22},{"id":12249,"term":"pro","meaning":"전문가; 찬성(론)","partOfSpeech":"n.","example":"She plays tennis like a pro even though she's never had lessons.","exampleTranslation":"그녀는 레슨을 받은 적이 없는데도 프로처럼 테니스를 친다.","category":"빈도 학습","level":22},{"id":12250,"term":"stair","meaning":"계단","partOfSpeech":"n.","example":"He tripped on the last stair and dropped his coffee.","exampleTranslation":"그는 마지막 계단에서 발이 걸려 커피를 쏟았다.","category":"빈도 학습","level":22},{"id":12251,"term":"hesitate","meaning":"망설이다; 주저하다","partOfSpeech":"v.","example":"Don't hesitate to call me if you need help moving.","exampleTranslation":"이사할 때 도움이 필요하면 망설이지 말고 전화해.","category":"빈도 학습","level":22},{"id":12252,"term":"shine","meaning":"빛나다; 빛을 내다","partOfSpeech":"v.","example":"The sun started to shine just as we reached the beach.","exampleTranslation":"우리가 해변에 도착하자마자 햇살이 빛나기 시작했다.","category":"빈도 학습","level":22},{"id":12253,"term":"motivation","meaning":"동기; 의욕","partOfSpeech":"n.","example":"I lost all my motivation after staying home for two weeks.","exampleTranslation":"2주 동안 집에만 있었더니 의욕이 완전히 사라졌다.","category":"빈도 학습","level":22},{"id":12254,"term":"romantic","meaning":"낭만적인; 로맨틱한","partOfSpeech":"adj.","example":"He planned a romantic dinner by the river for their anniversary.","exampleTranslation":"그는 기념일에 강가에서 낭만적인 저녁 식사를 준비했다.","category":"빈도 학습","level":22},{"id":12255,"term":"firmly","meaning":"단호하게; 굳게","partOfSpeech":"adv.","example":"She firmly told him she wasn't interested in the offer.","exampleTranslation":"그녀는 그 제안에 관심이 없다고 단호하게 말했다.","category":"빈도 학습","level":22},{"id":12256,"term":"interior","meaning":"내부; 인테리어","partOfSpeech":"n.","example":"The interior of the old café was decorated with vintage posters.","exampleTranslation":"그 오래된 카페의 내부는 빈티지 포스터로 꾸며져 있었다.","category":"빈도 학습","level":22},{"id":12257,"term":"stomach","meaning":"배; 위장","partOfSpeech":"n.","example":"My stomach started growling during the quiet meeting.","exampleTranslation":"조용한 회의 중에 배에서 꼬르륵 소리가 나기 시작했다.","category":"빈도 학습","level":22},{"id":12258,"term":"nowhere","meaning":"아무 데도 (~않다); 어디에도","partOfSpeech":"adv.","example":"I looked everywhere but my keys were nowhere to be found.","exampleTranslation":"온 사방을 뒤졌지만 열쇠가 어디에도 없었다.","category":"빈도 학습","level":22},{"id":12259,"term":"pray","meaning":"기도하다; 빌다","partOfSpeech":"v.","example":"She would pray every night before going to sleep.","exampleTranslation":"그녀는 잠들기 전에 매일 밤 기도를 했다.","category":"빈도 학습","level":22},{"id":12260,"term":"championship","meaning":"선수권 대회; 우승","partOfSpeech":"n.","example":"Our school team won the championship for the third year in a row.","exampleTranslation":"우리 학교 팀이 3년 연속 선수권 대회에서 우승했다.","category":"빈도 학습","level":22},{"id":12261,"term":"servant","meaning":"하인; 종업원","partOfSpeech":"n.","example":"In the old story, the servant was more clever than the king.","exampleTranslation":"그 옛이야기에서 하인은 왕보다 훨씬 영리했다.","category":"빈도 학습","level":22},{"id":12262,"term":"immigrant","meaning":"이민자","partOfSpeech":"n.","example":"As an immigrant, she worked hard to build a new life here.","exampleTranslation":"이민자로서 그녀는 이곳에서 새 삶을 일구기 위해 열심히 일했다.","category":"빈도 학습","level":22},{"id":12263,"term":"excess","meaning":"과잉; 초과","partOfSpeech":"n.","example":"Eating excess sugar every day is bad for your health.","exampleTranslation":"매일 설탕을 과다 섭취하는 것은 건강에 좋지 않다.","category":"빈도 학습","level":22},{"id":12264,"term":"complexity","meaning":"복잡성; 복잡함","partOfSpeech":"n.","example":"The complexity of the tax form confused almost everyone.","exampleTranslation":"세금 신고서의 복잡함에 거의 모두가 혼란스러워했다.","category":"빈도 학습","level":22},{"id":12265,"term":"liability","meaning":"책임; 부채","partOfSpeech":"n.","example":"The company accepted full liability for the accident.","exampleTranslation":"회사는 그 사고에 대한 모든 책임을 인정했다.","category":"빈도 학습","level":22},{"id":12266,"term":"surprisingly","meaning":"놀랍게도; 의외로","partOfSpeech":"adv.","example":"The small restaurant was surprisingly crowded on a Tuesday night.","exampleTranslation":"그 작은 식당은 화요일 밤임에도 의외로 사람이 많았다.","category":"빈도 학습","level":22},{"id":12267,"term":"extract","meaning":"추출하다; 뽑아내다","partOfSpeech":"v.","example":"The dentist had to extract the damaged tooth.","exampleTranslation":"치과의사는 손상된 치아를 뽑아야 했다.","category":"빈도 학습","level":22},{"id":12268,"term":"implementation","meaning":"실행; 시행","partOfSpeech":"n.","example":"The implementation of the new policy took several months.","exampleTranslation":"새 정책의 시행에는 몇 달이 걸렸다.","category":"빈도 학습","level":22},{"id":12269,"term":"bias","meaning":"편견; 편향","partOfSpeech":"n.","example":"She tried to set aside her bias before reading the review.","exampleTranslation":"그녀는 리뷰를 읽기 전에 자신의 편견을 내려놓으려 했다.","category":"빈도 학습","level":22},{"id":12270,"term":"differently","meaning":"다르게; 달리","partOfSpeech":"adv.","example":"Everyone handles stress differently, so be patient with each other.","exampleTranslation":"사람마다 스트레스를 다르게 받아들이니 서로 이해해줘야 한다.","category":"빈도 학습","level":22},{"id":12271,"term":"catalog","meaning":"목록; 카탈로그","partOfSpeech":"n.","example":"I found this lamp in a home decor catalog at the dentist's office.","exampleTranslation":"치과 대기실에서 본 인테리어 카탈로그에서 이 조명을 발견했다.","category":"빈도 학습","level":22},{"id":12272,"term":"continuous","meaning":"지속적인; 계속되는","partOfSpeech":"adj.","example":"The continuous noise from the construction kept me awake all night.","exampleTranslation":"공사장에서 나는 지속적인 소음 때문에 밤새 잠을 못 잤다.","category":"빈도 학습","level":22},{"id":12273,"term":"golden","meaning":"황금빛의; 귀중한","partOfSpeech":"adj.","example":"The golden leaves in the park made for a beautiful autumn photo.","exampleTranslation":"공원의 황금빛 낙엽 덕분에 아름다운 가을 사진이 찍혔다.","category":"빈도 학습","level":22},{"id":12274,"term":"stamp","meaning":"우표; 도장","partOfSpeech":"n.","example":"Don't forget to put a stamp on the envelope before you mail it.","exampleTranslation":"편지를 부치기 전에 봉투에 우표 붙이는 거 잊지 마.","category":"빈도 학습","level":22},{"id":12275,"term":"guideline","meaning":"지침; 가이드라인","partOfSpeech":"n.","example":"Please read the guideline carefully before filling out the form.","exampleTranslation":"양식을 작성하기 전에 지침을 꼼꼼히 읽어보세요.","category":"빈도 학습","level":22},{"id":12276,"term":"envelope","meaning":"봉투","partOfSpeech":"n.","example":"She slipped a note into the envelope and sealed it.","exampleTranslation":"그녀는 봉투 안에 메모를 넣고 봉했다.","category":"빈도 학습","level":22},{"id":12277,"term":"knife","meaning":"칼; 나이프","partOfSpeech":"n.","example":"A sharp knife makes cooking much easier and safer.","exampleTranslation":"날카로운 칼이 있으면 요리가 훨씬 편하고 안전하다.","category":"빈도 학습","level":22},{"id":12278,"term":"biological","meaning":"생물학적인; 생물의","partOfSpeech":"adj.","example":"The researchers studied the biological effects of the new drug.","exampleTranslation":"연구자들은 새 약물의 생물학적 영향을 연구했다.","category":"빈도 학습","level":22},{"id":12279,"term":"consume","meaning":"소비하다; 섭취하다","partOfSpeech":"v.","example":"We tend to consume more energy in the winter months.","exampleTranslation":"우리는 겨울철에 에너지를 더 많이 소비하는 경향이 있다.","category":"빈도 학습","level":22},{"id":12280,"term":"luxury","meaning":"사치; 호화로움","partOfSpeech":"n.","example":"Staying at that hotel felt like pure luxury.","exampleTranslation":"그 호텔에 머무는 건 순수한 사치처럼 느껴졌어.","category":"빈도 학습","level":22},{"id":12281,"term":"weekly","meaning":"매주의; 주 1회의","partOfSpeech":"adj.","example":"We have a weekly meeting every Monday morning.","exampleTranslation":"우리는 매주 월요일 아침에 회의가 있어.","category":"빈도 학습","level":22},{"id":12282,"term":"wherever","meaning":"어디든지; 어디에 있든","partOfSpeech":"conj.","example":"You can call me wherever you are.","exampleTranslation":"어디에 있든 나한테 전화해도 돼.","category":"빈도 학습","level":22},{"id":12283,"term":"bite","meaning":"물다; 한 입","partOfSpeech":"v.","example":"Can I have a bite of your sandwich?","exampleTranslation":"네 샌드위치 한 입 먹어도 돼?","category":"빈도 학습","level":22},{"id":12284,"term":"printer","meaning":"프린터; 인쇄기","partOfSpeech":"n.","example":"The printer is out of ink again.","exampleTranslation":"프린터 잉크가 또 떨어졌어.","category":"빈도 학습","level":22},{"id":12285,"term":"firstly","meaning":"첫째로; 우선","partOfSpeech":"adv.","example":"Firstly, let me introduce myself to the group.","exampleTranslation":"우선, 그룹에 제 소개를 할게요.","category":"빈도 학습","level":22},{"id":12286,"term":"anxious","meaning":"불안한; 걱정되는","partOfSpeech":"adj.","example":"I always feel anxious before a job interview.","exampleTranslation":"취업 면접 전에는 항상 불안해.","category":"빈도 학습","level":22},{"id":12287,"term":"adventure","meaning":"모험; 신나는 경험","partOfSpeech":"n.","example":"Backpacking across Europe was a real adventure.","exampleTranslation":"유럽을 배낭여행하는 건 진짜 모험이었어.","category":"빈도 학습","level":22},{"id":12288,"term":"fence","meaning":"울타리; 담장","partOfSpeech":"n.","example":"The dog keeps jumping over the fence.","exampleTranslation":"그 개가 계속 울타리를 뛰어넘어.","category":"빈도 학습","level":22},{"id":12289,"term":"exhaust","meaning":"기진맥진하게 하다; 다 써버리다","partOfSpeech":"v.","example":"The long hike began to exhaust everyone in the group.","exampleTranslation":"긴 하이킹이 일행 모두를 지치게 했어.","category":"빈도 학습","level":22},{"id":12290,"term":"attraction","meaning":"명소; 매력","partOfSpeech":"n.","example":"The Eiffel Tower is Paris's most famous attraction.","exampleTranslation":"에펠탑은 파리에서 가장 유명한 명소야.","category":"빈도 학습","level":22},{"id":12291,"term":"ocean","meaning":"바다; 대양","partOfSpeech":"n.","example":"We spent the afternoon swimming in the ocean.","exampleTranslation":"우리는 오후 내내 바다에서 수영했어.","category":"빈도 학습","level":22},{"id":12292,"term":"quietly","meaning":"조용히; 소리 없이","partOfSpeech":"adv.","example":"She quietly closed the door so she wouldn't wake anyone.","exampleTranslation":"그녀는 아무도 깨우지 않으려고 조용히 문을 닫았어.","category":"빈도 학습","level":22},{"id":12293,"term":"castle","meaning":"성; 성곽","partOfSpeech":"n.","example":"We visited an old castle in the Scottish Highlands.","exampleTranslation":"우리는 스코틀랜드 고지대에 있는 오래된 성을 방문했어.","category":"빈도 학습","level":22},{"id":12294,"term":"veteran","meaning":"베테랑; 노련한 사람","partOfSpeech":"n.","example":"She's a veteran teacher with over twenty years of experience.","exampleTranslation":"그녀는 20년 이상 경력의 베테랑 교사야.","category":"빈도 학습","level":22},{"id":12295,"term":"reflection","meaning":"반성; 반영; (거울에 비친) 모습","partOfSpeech":"n.","example":"He saw his reflection in the shop window.","exampleTranslation":"그는 상점 유리창에 비친 자신의 모습을 봤어.","category":"빈도 학습","level":22},{"id":12296,"term":"nerve","meaning":"신경; 용기; 뻔뻔함","partOfSpeech":"n.","example":"It took a lot of nerve to speak in front of the whole school.","exampleTranslation":"전교생 앞에서 말하려면 정말 큰 용기가 필요했어.","category":"빈도 학습","level":22},{"id":12297,"term":"determination","meaning":"결심; 의지","partOfSpeech":"n.","example":"Her determination to finish the race inspired everyone.","exampleTranslation":"결승선까지 완주하겠다는 그녀의 의지가 모두에게 감동을 줬어.","category":"빈도 학습","level":22},{"id":12298,"term":"altogether","meaning":"완전히; 모두 합해서","partOfSpeech":"adv.","example":"That's ten items altogether, so it comes to fifty dollars.","exampleTranslation":"모두 합해서 물건이 열 개니까 50달러예요.","category":"빈도 학습","level":22},{"id":12299,"term":"fiction","meaning":"소설; 허구","partOfSpeech":"n.","example":"I prefer reading fiction over nonfiction books.","exampleTranslation":"나는 논픽션보다 소설 읽는 걸 더 좋아해.","category":"빈도 학습","level":22},{"id":12300,"term":"carpet","meaning":"카펫; 양탄자","partOfSpeech":"n.","example":"The kids spilled juice on the carpet again.","exampleTranslation":"아이들이 또 카펫에 주스를 쏟았어.","category":"빈도 학습","level":22},{"id":12301,"term":"confusion","meaning":"혼란; 혼동","partOfSpeech":"n.","example":"There was some confusion about the meeting time.","exampleTranslation":"회의 시간에 대해 혼란이 좀 있었어.","category":"빈도 학습","level":22},{"id":12302,"term":"hurry","meaning":"서두르다; 급히 하다","partOfSpeech":"v.","example":"We need to hurry or we'll miss the train.","exampleTranslation":"서두르지 않으면 기차 놓쳐.","category":"빈도 학습","level":22},{"id":12303,"term":"logic","meaning":"논리; 이치","partOfSpeech":"n.","example":"I don't follow the logic of your argument.","exampleTranslation":"네 주장의 논리가 잘 이해가 안 돼.","category":"빈도 학습","level":22},{"id":12304,"term":"controversial","meaning":"논란이 많은; 의견이 갈리는","partOfSpeech":"adj.","example":"The new policy proved to be quite controversial.","exampleTranslation":"새 정책은 꽤 논란이 많은 것으로 드러났어.","category":"빈도 학습","level":22},{"id":12305,"term":"grammar","meaning":"문법","partOfSpeech":"n.","example":"Good grammar is important when writing a formal email.","exampleTranslation":"격식 있는 이메일을 쓸 때는 문법이 중요해.","category":"빈도 학습","level":22},{"id":12306,"term":"revise","meaning":"수정하다; 고치다","partOfSpeech":"v.","example":"Can you revise this paragraph before we submit it?","exampleTranslation":"제출하기 전에 이 단락 좀 고쳐줄 수 있어?","category":"빈도 학습","level":22},{"id":12307,"term":"hint","meaning":"힌트; 암시","partOfSpeech":"n.","example":"Just give me a hint — I can't guess the answer.","exampleTranslation":"힌트만 줘 — 답을 못 맞히겠어.","category":"빈도 학습","level":22},{"id":12308,"term":"hook","meaning":"갈고리; 훅","partOfSpeech":"n.","example":"Hang your coat on the hook by the door.","exampleTranslation":"문 옆 갈고리에 코트 걸어.","category":"빈도 학습","level":22},{"id":12309,"term":"bell","meaning":"종; 벨","partOfSpeech":"n.","example":"The bell rang and all the students rushed out.","exampleTranslation":"종이 울리자 학생들이 모두 뛰어나갔어.","category":"빈도 학습","level":22},{"id":12310,"term":"liquid","meaning":"액체; 액상의","partOfSpeech":"n.","example":"Drink plenty of liquid when you have a fever.","exampleTranslation":"열이 날 때는 수분을 충분히 섭취해.","category":"빈도 학습","level":22},{"id":12311,"term":"panic","meaning":"공황; 극심한 불안","partOfSpeech":"n.","example":"Don't panic — we still have plenty of time.","exampleTranslation":"당황하지 마 — 아직 시간이 충분해.","category":"빈도 학습","level":22},{"id":12312,"term":"uncle","meaning":"삼촌; 외삼촌","partOfSpeech":"n.","example":"My uncle taught me how to ride a bike.","exampleTranslation":"삼촌이 나한테 자전거 타는 법을 가르쳐줬어.","category":"빈도 학습","level":22},{"id":12313,"term":"slope","meaning":"경사면; 비탈","partOfSpeech":"n.","example":"The kids loved sledding down the snowy slope.","exampleTranslation":"아이들은 눈 덮인 비탈을 썰매 타고 내려가는 걸 정말 좋아했어.","category":"빈도 학습","level":22},{"id":12314,"term":"happiness","meaning":"행복; 기쁨","partOfSpeech":"n.","example":"Spending time with family brings me true happiness.","exampleTranslation":"가족과 함께하는 시간이 나에게 진정한 행복을 줘.","category":"빈도 학습","level":22},{"id":12315,"term":"genuine","meaning":"진짜의; 진심 어린","partOfSpeech":"adj.","example":"Her smile looked genuine and warm.","exampleTranslation":"그녀의 미소는 진심 어리고 따뜻해 보였어.","category":"빈도 학습","level":22},{"id":12316,"term":"vessel","meaning":"선박; 용기(그릇)","partOfSpeech":"n.","example":"The rescue vessel arrived within an hour.","exampleTranslation":"구조선이 한 시간 안에 도착했어.","category":"빈도 학습","level":22},{"id":12317,"term":"verb","meaning":"동사","partOfSpeech":"n.","example":"Every sentence needs a verb to be complete.","exampleTranslation":"모든 문장이 완성되려면 동사가 필요해.","category":"빈도 학습","level":22},{"id":12318,"term":"reckon","meaning":"생각하다; 추정하다","partOfSpeech":"v.","example":"I reckon it'll take about two hours to get there.","exampleTranslation":"거기까지 두 시간쯤 걸릴 것 같아.","category":"빈도 학습","level":22},{"id":12319,"term":"silly","meaning":"어리석은; 바보 같은","partOfSpeech":"adj.","example":"Don't be silly — of course you can do it.","exampleTranslation":"바보 같은 소리 하지 마 — 물론 넌 할 수 있어.","category":"빈도 학습","level":22},{"id":12320,"term":"transportation","meaning":"교통; 운송","partOfSpeech":"n.","example":"Public transportation in this city is fast and cheap.","exampleTranslation":"이 도시의 대중교통은 빠르고 저렴해요.","category":"빈도 학습","level":22},{"id":12321,"term":"harbor","meaning":"항구; 품다","partOfSpeech":"n./v.","example":"The boats came back to the harbor before the storm.","exampleTranslation":"폭풍이 오기 전에 배들이 항구로 돌아왔어요.","category":"빈도 학습","level":22},{"id":12322,"term":"comedy","meaning":"코미디; 희극","partOfSpeech":"n.","example":"I need a good comedy to watch tonight.","exampleTranslation":"오늘 밤 볼 재미있는 코미디가 필요해요.","category":"빈도 학습","level":22},{"id":12323,"term":"chase","meaning":"뒤쫓다; 추격","partOfSpeech":"n./v.","example":"The dog loves to chase squirrels in the park.","exampleTranslation":"그 개는 공원에서 다람쥐를 쫓아다니는 걸 좋아해요.","category":"빈도 학습","level":22},{"id":12324,"term":"storage","meaning":"보관; 저장 공간","partOfSpeech":"n.","example":"We need more storage for all these boxes.","exampleTranslation":"이 상자들을 다 보관할 공간이 더 필요해요.","category":"빈도 학습","level":22},{"id":12325,"term":"universe","meaning":"우주; 세계","partOfSpeech":"n.","example":"The universe is too big for us to fully understand.","exampleTranslation":"우주는 우리가 완전히 이해하기엔 너무 커요.","category":"빈도 학습","level":22},{"id":12326,"term":"horrible","meaning":"끔찍한; 형편없는","partOfSpeech":"adj.","example":"The weather was horrible, so we stayed inside.","exampleTranslation":"날씨가 너무 끔찍해서 우리는 안에 있었어요.","category":"빈도 학습","level":22},{"id":12327,"term":"sheep","meaning":"양","partOfSpeech":"n.","example":"There were hundreds of sheep on the hillside.","exampleTranslation":"언덕에 양이 수백 마리 있었어요.","category":"빈도 학습","level":22},{"id":12328,"term":"lover","meaning":"연인; ~을 좋아하는 사람","partOfSpeech":"n.","example":"She is a true lover of jazz music.","exampleTranslation":"그녀는 진정한 재즈 음악 애호가예요.","category":"빈도 학습","level":22},{"id":12329,"term":"rat","meaning":"쥐; 배신자","partOfSpeech":"n.","example":"We found a rat in the kitchen and called pest control.","exampleTranslation":"주방에서 쥐를 발견하고 해충 방제 업체에 전화했어요.","category":"빈도 학습","level":22},{"id":12330,"term":"portrait","meaning":"초상화; 인물 사진","partOfSpeech":"n.","example":"She had a portrait of her grandmother on the wall.","exampleTranslation":"그녀는 벽에 할머니 초상화를 걸어 두었어요.","category":"빈도 학습","level":22},{"id":12331,"term":"innocent","meaning":"결백한; 순진한","partOfSpeech":"adj.","example":"He was found innocent after the full investigation.","exampleTranslation":"완전한 조사 끝에 그는 결백한 것으로 밝혀졌어요.","category":"빈도 학습","level":22},{"id":12332,"term":"substitute","meaning":"대체하다; 대용품","partOfSpeech":"n./v.","example":"You can substitute honey for sugar in this recipe.","exampleTranslation":"이 레시피에서 설탕 대신 꿀을 대체해 쓸 수 있어요.","category":"빈도 학습","level":22},{"id":12333,"term":"supplement","meaning":"보충제; 보충하다","partOfSpeech":"n./v.","example":"She takes a vitamin supplement every morning.","exampleTranslation":"그녀는 매일 아침 비타민 보충제를 먹어요.","category":"빈도 학습","level":22},{"id":12334,"term":"adjustment","meaning":"조정; 적응","partOfSpeech":"n.","example":"A small adjustment to the schedule made everything easier.","exampleTranslation":"일정을 조금 조정하니 모든 게 훨씬 수월해졌어요.","category":"빈도 학습","level":22},{"id":12335,"term":"reasonably","meaning":"합리적으로; 꽤","partOfSpeech":"adv.","example":"The hotel was reasonably priced for the area.","exampleTranslation":"그 지역치고 호텔 가격이 꽤 합리적이었어요.","category":"빈도 학습","level":22},{"id":12336,"term":"filter","meaning":"필터; 거르다","partOfSpeech":"n./v.","example":"Please filter the search results by date.","exampleTranslation":"날짜별로 검색 결과를 걸러 주세요.","category":"빈도 학습","level":22},{"id":12337,"term":"flexible","meaning":"유연한; 융통성 있는","partOfSpeech":"adj.","example":"My boss is flexible about working from home.","exampleTranslation":"우리 상사는 재택근무에 대해 유연해요.","category":"빈도 학습","level":22},{"id":12338,"term":"abstract","meaning":"추상적인; 개요","partOfSpeech":"adj.","example":"The painting is very abstract and hard to describe.","exampleTranslation":"그 그림은 매우 추상적이어서 설명하기가 어려워요.","category":"빈도 학습","level":22},{"id":12339,"term":"tent","meaning":"텐트","partOfSpeech":"n.","example":"We put up our tent near the river for the night.","exampleTranslation":"우리는 강가에 텐트를 치고 하룻밤을 보냈어요.","category":"빈도 학습","level":22},{"id":12340,"term":"precise","meaning":"정확한; 꼼꼼한","partOfSpeech":"adj.","example":"Can you give me the precise address of the venue?","exampleTranslation":"행사장의 정확한 주소를 알려 주시겠어요?","category":"빈도 학습","level":22},{"id":12341,"term":"distant","meaning":"먼; 거리를 두는","partOfSpeech":"adj.","example":"She seemed distant during the whole conversation.","exampleTranslation":"그녀는 대화 내내 거리를 두는 것 같았어요.","category":"빈도 학습","level":22},{"id":12342,"term":"stranger","meaning":"낯선 사람; 이방인","partOfSpeech":"n.","example":"A stranger helped me when I got lost downtown.","exampleTranslation":"시내에서 길을 잃었을 때 낯선 사람이 도와줬어요.","category":"빈도 학습","level":22},{"id":12343,"term":"shade","meaning":"그늘; 색조","partOfSpeech":"n.","example":"Let's sit in the shade to cool down a bit.","exampleTranslation":"좀 식히려고 그늘에 앉읍시다.","category":"빈도 학습","level":22},{"id":12344,"term":"grain","meaning":"곡물; 낟알","partOfSpeech":"n.","example":"This bread is made from whole grain flour.","exampleTranslation":"이 빵은 통곡물 밀가루로 만들었어요.","category":"빈도 학습","level":23},{"id":12345,"term":"situate","meaning":"위치시키다; 배치하다","partOfSpeech":"v.","example":"It is best to situate the desk near a window for natural light.","exampleTranslation":"자연광을 위해 책상을 창가 쪽에 배치하는 게 가장 좋아요.","category":"빈도 학습","level":23},{"id":12346,"term":"summarize","meaning":"요약하다","partOfSpeech":"v.","example":"Could you summarize the main points of the report?","exampleTranslation":"보고서의 주요 내용을 요약해 주시겠어요?","category":"빈도 학습","level":23},{"id":12347,"term":"leap","meaning":"뛰어오르다; 도약","partOfSpeech":"n./v.","example":"The cat made a sudden leap onto the table.","exampleTranslation":"고양이가 갑자기 테이블 위로 뛰어올랐어요.","category":"빈도 학습","level":23},{"id":12348,"term":"snap","meaning":"딱 부러지다; 찰칵 찍다","partOfSpeech":"n./v.","example":"I heard the branch snap under his foot.","exampleTranslation":"그의 발 아래 나뭇가지가 딱 부러지는 소리가 들렸어요.","category":"빈도 학습","level":23},{"id":12349,"term":"probability","meaning":"확률; 가능성","partOfSpeech":"n.","example":"The probability of rain tomorrow is very high.","exampleTranslation":"내일 비가 올 확률이 매우 높아요.","category":"빈도 학습","level":23},{"id":12350,"term":"leather","meaning":"가죽","partOfSpeech":"n.","example":"She bought a leather wallet as a gift for her dad.","exampleTranslation":"그녀는 아버지 선물로 가죽 지갑을 샀어요.","category":"빈도 학습","level":23},{"id":12351,"term":"uncertainty","meaning":"불확실성; 불확실함","partOfSpeech":"n.","example":"There is a lot of uncertainty about the future of the project.","exampleTranslation":"프로젝트의 미래에 대한 불확실성이 커요.","category":"빈도 학습","level":23},{"id":12352,"term":"swear","meaning":"맹세하다; 욕하다","partOfSpeech":"v.","example":"I swear I left my keys on the table.","exampleTranslation":"분명히 테이블 위에 열쇠를 뒀다고요.","category":"빈도 학습","level":23},{"id":12353,"term":"refugee","meaning":"난민","partOfSpeech":"n.","example":"The organization helps refugee families find housing.","exampleTranslation":"그 단체는 난민 가족들이 거처를 찾도록 돕고 있어요.","category":"빈도 학습","level":23},{"id":12354,"term":"shore","meaning":"해안; 기슭","partOfSpeech":"n.","example":"We walked along the shore and collected shells.","exampleTranslation":"우리는 해안을 따라 걸으며 조개껍데기를 모았어요.","category":"빈도 학습","level":23},{"id":12355,"term":"monthly","meaning":"매월의; 한 달에 한 번","partOfSpeech":"adj.","example":"I pay a monthly fee for the streaming service.","exampleTranslation":"스트리밍 서비스 이용료를 매월 내고 있어요.","category":"빈도 학습","level":23},{"id":12356,"term":"comprise","meaning":"구성하다; ~으로 이루어지다","partOfSpeech":"v.","example":"The team will comprise members from three different departments.","exampleTranslation":"그 팀은 세 개 부서의 구성원들로 이루어질 거예요.","category":"빈도 학습","level":23},{"id":12357,"term":"stir","meaning":"젓다; 뒤섞다","partOfSpeech":"v.","example":"Stir the sauce gently so it does not burn.","exampleTranslation":"소스가 타지 않도록 천천히 저어 주세요.","category":"빈도 학습","level":23},{"id":12358,"term":"excitement","meaning":"흥분; 설렘","partOfSpeech":"n.","example":"There was great excitement before the concert started.","exampleTranslation":"콘서트가 시작하기 전에 엄청난 설렘이 있었어요.","category":"빈도 학습","level":23},{"id":12359,"term":"sigh","meaning":"한숨 쉬다; 한숨","partOfSpeech":"n./v.","example":"She let out a long sigh after hearing the bad news.","exampleTranslation":"그녀는 나쁜 소식을 듣고 긴 한숨을 내쉬었어요.","category":"빈도 학습","level":23},{"id":12360,"term":"pregnancy","meaning":"임신","partOfSpeech":"n.","example":"She found out about her pregnancy last week.","exampleTranslation":"그녀는 지난주에 임신 사실을 알게 됐어.","category":"빈도 학습","level":23},{"id":12361,"term":"experimental","meaning":"실험적인; 시험 단계의","partOfSpeech":"adj.","example":"The doctor suggested an experimental treatment for the condition.","exampleTranslation":"의사는 그 증상에 실험적인 치료법을 제안했어.","category":"빈도 학습","level":23},{"id":12362,"term":"institutional","meaning":"기관의; 제도적인","partOfSpeech":"adj.","example":"There has been a lot of institutional support for the new program.","exampleTranslation":"새 프로그램에 대한 기관 차원의 지원이 많이 있었어.","category":"빈도 학습","level":23},{"id":12363,"term":"slice","meaning":"조각; (얇게) 썰다","partOfSpeech":"n./v.","example":"Can I have another slice of that bread?","exampleTranslation":"그 빵 한 조각 더 먹어도 될까?","category":"빈도 학습","level":23},{"id":12364,"term":"wander","meaning":"돌아다니다; 거닐다","partOfSpeech":"v.","example":"We like to wander through the market on Sunday mornings.","exampleTranslation":"우리는 일요일 아침에 시장을 거닐며 돌아다니는 걸 좋아해.","category":"빈도 학습","level":23},{"id":12365,"term":"empire","meaning":"제국; (거대한) 기업 집단","partOfSpeech":"n.","example":"He built a business empire from nothing.","exampleTranslation":"그는 아무것도 없는 데서 사업 제국을 일궜어.","category":"빈도 학습","level":23},{"id":12366,"term":"subsequently","meaning":"그 후에; 나중에","partOfSpeech":"adv.","example":"He left the company and subsequently started his own business.","exampleTranslation":"그는 회사를 떠난 후 나중에 자신의 사업을 시작했어.","category":"빈도 학습","level":23},{"id":12367,"term":"gentle","meaning":"부드러운; 온화한","partOfSpeech":"adj.","example":"She has a gentle voice that puts people at ease.","exampleTranslation":"그녀는 사람들을 편하게 해주는 부드러운 목소리를 갖고 있어.","category":"빈도 학습","level":23},{"id":12368,"term":"attendance","meaning":"출석; 참석","partOfSpeech":"n.","example":"Attendance at the meeting is mandatory for all staff.","exampleTranslation":"회의 출석은 모든 직원에게 의무야.","category":"빈도 학습","level":23},{"id":12369,"term":"ownership","meaning":"소유권; 소유","partOfSpeech":"n.","example":"The ownership of the property was transferred to his daughter.","exampleTranslation":"그 부동산의 소유권이 그의 딸에게 넘어갔어.","category":"빈도 학습","level":23},{"id":12370,"term":"qualification","meaning":"자격; 자격증","partOfSpeech":"n.","example":"You need the right qualification to apply for that job.","exampleTranslation":"그 일에 지원하려면 적합한 자격이 필요해.","category":"빈도 학습","level":23},{"id":12371,"term":"suspend","meaning":"중단하다; 정직시키다","partOfSpeech":"v.","example":"They decided to suspend the project due to budget issues.","exampleTranslation":"그들은 예산 문제로 프로젝트를 중단하기로 했어.","category":"빈도 학습","level":23},{"id":12372,"term":"functional","meaning":"기능적인; 실용적인","partOfSpeech":"adj.","example":"The new office design is both stylish and functional.","exampleTranslation":"새 사무실 디자인은 세련되면서도 기능적이야.","category":"빈도 학습","level":23},{"id":12373,"term":"voluntary","meaning":"자발적인; 자원봉사의","partOfSpeech":"adj.","example":"His participation in the program was entirely voluntary.","exampleTranslation":"그의 프로그램 참여는 전적으로 자발적이었어.","category":"빈도 학습","level":23},{"id":12374,"term":"pale","meaning":"창백한; 연한","partOfSpeech":"adj.","example":"She looked pale and tired after the long flight.","exampleTranslation":"그녀는 긴 비행 후 창백하고 피곤해 보였어.","category":"빈도 학습","level":23},{"id":12375,"term":"stain","meaning":"얼룩; 얼룩지다","partOfSpeech":"n./v.","example":"There's a stain on your shirt from the coffee.","exampleTranslation":"커피 때문에 네 셔츠에 얼룩이 생겼어.","category":"빈도 학습","level":23},{"id":12376,"term":"athlete","meaning":"운동선수","partOfSpeech":"n.","example":"She became a professional athlete at age eighteen.","exampleTranslation":"그녀는 열여덟 살에 프로 운동선수가 됐어.","category":"빈도 학습","level":23},{"id":12377,"term":"organic","meaning":"유기농의; 자연 발생적인","partOfSpeech":"adj.","example":"I try to buy organic vegetables when I can.","exampleTranslation":"나는 가능하면 유기농 채소를 사려고 해.","category":"빈도 학습","level":23},{"id":12378,"term":"tongue","meaning":"혀; 언어","partOfSpeech":"n.","example":"She burned her tongue on the hot soup.","exampleTranslation":"그녀는 뜨거운 수프에 혀를 데었어.","category":"빈도 학습","level":23},{"id":12379,"term":"structural","meaning":"구조적인; 구조상의","partOfSpeech":"adj.","example":"The engineers found a structural problem in the old building.","exampleTranslation":"기술자들이 오래된 건물에서 구조적 문제를 발견했어.","category":"빈도 학습","level":23},{"id":12380,"term":"fool","meaning":"바보; 속이다","partOfSpeech":"n./v.","example":"Don't let him fool you with that story.","exampleTranslation":"그 얘기로 그가 널 속이게 두지 마.","category":"빈도 학습","level":23},{"id":12381,"term":"alongside","meaning":"~와 나란히; ~와 함께","partOfSpeech":"prep.","example":"She worked alongside her colleagues to finish the report.","exampleTranslation":"그녀는 보고서를 완성하기 위해 동료들과 함께 일했어.","category":"빈도 학습","level":23},{"id":12382,"term":"unite","meaning":"하나로 합치다; 단결하다","partOfSpeech":"v.","example":"The crisis helped unite the community like never before.","exampleTranslation":"그 위기는 지역 사회를 그 어느 때보다 단결시키는 데 도움이 됐어.","category":"빈도 학습","level":23},{"id":12383,"term":"gently","meaning":"부드럽게; 조심스럽게","partOfSpeech":"adv.","example":"She gently lifted the sleeping baby from the crib.","exampleTranslation":"그녀는 잠든 아기를 요람에서 조심스럽게 들어 올렸어.","category":"빈도 학습","level":23},{"id":12384,"term":"compute","meaning":"계산하다; 산출하다","partOfSpeech":"v.","example":"It takes a few seconds to compute the total cost.","exampleTranslation":"총 비용을 계산하는 데 몇 초가 걸려.","category":"빈도 학습","level":23},{"id":12385,"term":"wipe","meaning":"닦다; 훔치다","partOfSpeech":"v.","example":"Please wipe the table before we eat.","exampleTranslation":"먹기 전에 테이블 좀 닦아줘.","category":"빈도 학습","level":23},{"id":12386,"term":"weird","meaning":"이상한; 기이한","partOfSpeech":"adj.","example":"That was a really weird dream I had last night.","exampleTranslation":"어젯밤에 정말 이상한 꿈을 꿨어.","category":"빈도 학습","level":23},{"id":12387,"term":"gaze","meaning":"응시하다; 바라보다","partOfSpeech":"v.","example":"I love to gaze at the stars on a clear night.","exampleTranslation":"맑은 밤에 별을 바라보는 걸 정말 좋아해.","category":"빈도 학습","level":23},{"id":12388,"term":"fade","meaning":"바래다; 서서히 사라지다","partOfSpeech":"v.","example":"The colors in the painting will fade over time.","exampleTranslation":"그림의 색깔은 시간이 지나면서 바랠 거야.","category":"빈도 학습","level":23},{"id":12389,"term":"cough","meaning":"기침; 기침하다","partOfSpeech":"n./v.","example":"I've had a bad cough for the past three days.","exampleTranslation":"사흘째 심한 기침을 하고 있어.","category":"빈도 학습","level":23},{"id":12390,"term":"hypothesis","meaning":"가설","partOfSpeech":"n.","example":"The scientist tested her hypothesis with a series of experiments.","exampleTranslation":"그 과학자는 일련의 실험으로 자신의 가설을 검증했어.","category":"빈도 학습","level":23},{"id":12391,"term":"royal","meaning":"왕실의; 왕족의","partOfSpeech":"adj.","example":"The royal family attended the ceremony in the palace.","exampleTranslation":"왕실 가족이 궁전에서 열린 행사에 참석했어.","category":"빈도 학습","level":23},{"id":12392,"term":"theoretical","meaning":"이론적인; 이론상의","partOfSpeech":"adj.","example":"His knowledge is mostly theoretical since he has little real experience.","exampleTranslation":"그는 실제 경험이 거의 없어서 지식이 대부분 이론적이야.","category":"빈도 학습","level":23},{"id":12393,"term":"curtain","meaning":"커튼; 막","partOfSpeech":"n.","example":"She pulled the curtain shut to block out the light.","exampleTranslation":"그녀는 빛을 차단하기 위해 커튼을 닫았어.","category":"빈도 학습","level":23},{"id":12394,"term":"mayor","meaning":"시장(市長)","partOfSpeech":"n.","example":"The mayor announced a new plan to improve public transport.","exampleTranslation":"시장은 대중교통을 개선하기 위한 새 계획을 발표했어.","category":"빈도 학습","level":23},{"id":12395,"term":"darkness","meaning":"어둠; 암흑","partOfSpeech":"n.","example":"I could barely see anything in the darkness of the room.","exampleTranslation":"방의 어둠 속에서 거의 아무것도 보이지 않았어.","category":"빈도 학습","level":23},{"id":12396,"term":"aunt","meaning":"이모; 고모; 숙모","partOfSpeech":"n.","example":"My aunt lives in Sydney and visits us every summer.","exampleTranslation":"내 이모는 시드니에 살고 매년 여름에 우릴 찾아와.","category":"빈도 학습","level":23},{"id":12397,"term":"tournament","meaning":"토너먼트; 선수권 대회","partOfSpeech":"n.","example":"Our team made it to the final round of the tournament.","exampleTranslation":"우리 팀이 토너먼트 결승전에 진출했어.","category":"빈도 학습","level":23},{"id":12398,"term":"registration","meaning":"등록; 신청","partOfSpeech":"n.","example":"Online registration for the course closes on Friday.","exampleTranslation":"그 강좌의 온라인 등록은 금요일에 마감돼.","category":"빈도 학습","level":23},{"id":12399,"term":"fragment","meaning":"조각; 파편","partOfSpeech":"n.","example":"A small fragment of glass was stuck in her shoe.","exampleTranslation":"작은 유리 조각이 그녀의 신발에 박혀 있었어.","category":"빈도 학습","level":23},{"id":12400,"term":"listener","meaning":"듣는 사람; 청취자","partOfSpeech":"n.","example":"She is a good listener who never interrupts.","exampleTranslation":"그녀는 절대 말을 끊지 않는 좋은 경청자예요.","category":"빈도 학습","level":23},{"id":12401,"term":"tender","meaning":"부드러운; 다정한","partOfSpeech":"adj.","example":"The meat was so tender it fell off the bone.","exampleTranslation":"고기가 너무 부드러워서 뼈에서 저절로 떨어졌어요.","category":"빈도 학습","level":23},{"id":12402,"term":"density","meaning":"밀도; 밀집도","partOfSpeech":"n.","example":"The population density in this city is very high.","exampleTranslation":"이 도시의 인구 밀도는 매우 높아요.","category":"빈도 학습","level":23},{"id":12403,"term":"ugly","meaning":"못생긴; 보기 흉한","partOfSpeech":"adj.","example":"That ugly stain on the wall is hard to remove.","exampleTranslation":"벽에 있는 그 보기 흉한 얼룩은 지우기가 어려워요.","category":"빈도 학습","level":23},{"id":12404,"term":"module","meaning":"모듈; 단위 구성 요소","partOfSpeech":"n.","example":"This course is divided into six separate module sections.","exampleTranslation":"이 강좌는 여섯 개의 별도 모듈로 나뉘어 있어요.","category":"빈도 학습","level":23},{"id":12405,"term":"faithfully","meaning":"충실히; 성실하게","partOfSpeech":"adv.","example":"He faithfully followed all the doctor's instructions.","exampleTranslation":"그는 의사의 모든 지시를 충실히 따랐어요.","category":"빈도 학습","level":23},{"id":12406,"term":"autumn","meaning":"가을","partOfSpeech":"n.","example":"The leaves turn red and orange every autumn.","exampleTranslation":"매년 가을마다 나뭇잎이 빨갛고 주황색으로 변해요.","category":"빈도 학습","level":23},{"id":12407,"term":"cheek","meaning":"뺨; 볼","partOfSpeech":"n.","example":"She kissed him gently on the cheek.","exampleTranslation":"그녀는 그의 뺨에 부드럽게 입을 맞췄어요.","category":"빈도 학습","level":23},{"id":12408,"term":"attachment","meaning":"첨부 파일; 애착","partOfSpeech":"n.","example":"Please check the attachment I sent with the email.","exampleTranslation":"이메일에 함께 보낸 첨부 파일을 확인해 주세요.","category":"빈도 학습","level":23},{"id":12409,"term":"holder","meaning":"보유자; 거치대","partOfSpeech":"n.","example":"The ticket holder must show ID at the entrance.","exampleTranslation":"티켓 보유자는 입구에서 신분증을 제시해야 해요.","category":"빈도 학습","level":23},{"id":12410,"term":"grin","meaning":"활짝 웃다; 씩 웃음","partOfSpeech":"v.","example":"He gave a big grin when he heard the good news.","exampleTranslation":"좋은 소식을 들었을 때 그는 활짝 웃었어요.","category":"빈도 학습","level":23},{"id":12411,"term":"noun","meaning":"명사","partOfSpeech":"n.","example":"Dog is a noun that refers to a common pet.","exampleTranslation":"'Dog'은 흔한 반려동물을 가리키는 명사예요.","category":"빈도 학습","level":23},{"id":12412,"term":"fortunate","meaning":"운 좋은; 다행스러운","partOfSpeech":"adj.","example":"We were fortunate to find seats on the last train.","exampleTranslation":"마지막 기차에서 자리를 찾다니 정말 운이 좋았어요.","category":"빈도 학습","level":23},{"id":12413,"term":"alright","meaning":"괜찮은; 좋아","partOfSpeech":"adj.","example":"Are you alright after that long flight?","exampleTranslation":"그 긴 비행 후에 괜찮아요?","category":"빈도 학습","level":23},{"id":12414,"term":"lazy","meaning":"게으른; 나태한","partOfSpeech":"adj.","example":"I felt lazy all morning and stayed in bed.","exampleTranslation":"오전 내내 게으른 기분이 들어서 침대에 있었어요.","category":"빈도 학습","level":23},{"id":12415,"term":"hunger","meaning":"배고픔; 굶주림","partOfSpeech":"n.","example":"After the long hike, hunger hit us all at once.","exampleTranslation":"긴 하이킹 후에 우리 모두 한꺼번에 배고픔이 밀려왔어요.","category":"빈도 학습","level":23},{"id":12416,"term":"insure","meaning":"보험에 들다; 보장하다","partOfSpeech":"v.","example":"You should insure your phone in case you lose it.","exampleTranslation":"잃어버릴 경우를 대비해 휴대폰 보험에 들어야 해요.","category":"빈도 학습","level":23},{"id":12417,"term":"ashamed","meaning":"부끄러운; 창피한","partOfSpeech":"adj.","example":"He felt ashamed of his rude behavior at dinner.","exampleTranslation":"그는 저녁 식사 자리에서 무례하게 굴었던 것이 부끄러웠어요.","category":"빈도 학습","level":23},{"id":12418,"term":"found","meaning":"(단체·기관을) 설립하다","partOfSpeech":"v.","example":"She decided to found a small nonprofit organization.","exampleTranslation":"그녀는 작은 비영리 단체를 설립하기로 결심했어요.","category":"빈도 학습","level":23},{"id":12419,"term":"thirst","meaning":"갈증; 목마름","partOfSpeech":"n.","example":"After running in the heat, my thirst was unbearable.","exampleTranslation":"더위 속에서 뛰고 나니 갈증이 견디기 힘들었어요.","category":"빈도 학습","level":23},{"id":12420,"term":"dominate","meaning":"지배하다; 압도하다","partOfSpeech":"v.","example":"One player seemed to dominate every game this season.","exampleTranslation":"한 선수가 이번 시즌 모든 경기를 압도하는 것 같았어요.","category":"빈도 학습","level":23}]`);export{e as default};